-- Poems batch 342
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('a27f8115-bc82-4a45-9761-7d105e9e1ce0','次韵安禮見寄','楊時','宋','宋诗','song-poetry','','[]','末俗相看老尚新，交游千里更誰親。',64,'全唐诗/poet.song.63000.json','["末俗相看老尚新，交游千里更誰親。", "蕭條身世聊安分，迂闊行藏懶徇人。", "宦路競羞關柝吏，勞生誰息利名身。", "我慚抱甕無機械，幽興惟思水石濱。"]'),
('d002ea87-112a-4117-a662-7dd2ae5d1435','冬寒兩齒忽覺動搖因成書懷','楊時','宋','宋诗','song-poetry','','[]','未年三十髮先彫，歲晚俄驚兩齒搖。',64,'全唐诗/poet.song.63000.json','["未年三十髮先彫，歲晚俄驚兩齒搖。", "都爲疏慵成計拙，直緣衰病覺形焦。", "連經宿雨重裘冷，旋煮藜羹野興饒。", "擺脫塵樊猶未得，不堪回首問漁樵。"]'),
('f8a10810-23f3-45fe-b714-b8da9d91bb0a','書懷','楊時','宋','宋诗','song-poetry','','[]','駸駸塵土久方還，直道謀身力愈難。',64,'全唐诗/poet.song.63000.json','["駸駸塵土久方還，直道謀身力愈難。", "靖節每嗟嬰世網，漫郎何意出人間。", "風驚駭浪潜鱗伏，竹隠灣磯翠羽閒。", "好去杖藜穿蠟屐，伴雲隨月弄潺湲。"]'),
('9bb1538e-fdca-43ab-8809-f07ae1e7bedc','汴上','楊時','宋','宋诗','song-poetry','','[]','天上行雲曳白衣，半銜晴日在林扉。',64,'全唐诗/poet.song.63000.json','["天上行雲曳白衣，半銜晴日在林扉。", "盤花落雁驚還起，啄食饑烏趁不飛。", "榆莢青錢飄已盡，月堤流水漭相圍。", "征途處處塵隨眼，多病長年與世違。"]'),
('46e21c00-abfa-4172-bd38-d2817c835091','陳留書事','楊時','宋','宋诗','song-poetry','','[]','烏檣風纜欲飛翾，拍岸驚濤挽不前。',64,'全唐诗/poet.song.63000.json','["烏檣風纜欲飛翾，拍岸驚濤挽不前。", "曲浦漲沙仍積凍，疏林斜日自生烟。", "崎嶔道路真堪笑，放浪江湖已判年。", "一枕晝眠無好夢，空慚邊老腹便便。"]'),
('b1c220f0-9ffb-4325-a657-69e96010e653','予自長沙還植蘭竹於東西軒調官京師逾年而歸蘭竹皆衰悴感而成詩','楊時','宋','宋诗','song-poetry','','[]','柴桑衰晚愛吾廬，三徑歸來手自鋤。',64,'全唐诗/poet.song.63000.json','["柴桑衰晚愛吾廬，三徑歸來手自鋤。", "但得叔卿長飽飯，不妨孝若老談書。", "蘭因採佩枝先瘁，竹爲凌霜葉自疏。", "留骨廟堂寧曳尾，魯門無用祀爰居。"]'),
('fb013238-e8d7-4419-b39f-1132d48c605e','和李倅游武夷','楊時','宋','宋诗','song-poetry','','[]','濃淡烟鬟半雨晴，溪光初借晚霞明。',64,'全唐诗/poet.song.63000.json','["濃淡烟鬟半雨晴，溪光初借晚霞明。", "鼇頭湧出三峰秀，天漢融成一鑑清。", "枌社有誰藏舊牒，賓雲無處問遺聲。", "幔亭寂寞仙何在，勾漏丹砂早晚成。"]'),
('fa713533-a174-45ea-8976-04bc8fdf7355','荆州書事二首  其一','楊時','宋','宋诗','song-poetry','','[]','江湖泛泛一虛舟，去作人間浪漫游。',64,'全唐诗/poet.song.63000.json','["江湖泛泛一虛舟，去作人間浪漫游。", "歲晚光陰雲冉冉，畏途風雨日浮浮。", "萬鍾信是樊中雉，一棹聊同水上鷗。", "投老虀鹽成底事，憑誰爲種橘千頭。"]'),
('22bd4470-a2a4-4fd7-af8b-a22ba7f37ea0','荆州書事二首  其二','楊時','宋','宋诗','song-poetry','','[]','千里瀕江地可毛，結廬何必故山椒。',64,'全唐诗/poet.song.63000.json','["千里瀕江地可毛，結廬何必故山椒。", "載醪不過斜川路，飲水誰同陋巷瓢。", "勿問雞蟲閒得失，但知鵬鷃各逍遥。", "黄塵滿眼僧窗靜，坐對風花意已消。"]'),
('ac134551-500e-4233-ab6e-b82aa385bded','天寧節','楊時','宋','宋诗','song-poetry','','[]','祥開若木射瑶光，淑氣先春景自長。',64,'全唐诗/poet.song.63000.json','["祥開若木射瑶光，淑氣先春景自長。", "玉陛風閒飛綵綬，獸爐烟暖襲珠囊。", "雲門羽鶴儀仙仗，天上蟠桃薦壽觴。", "已見晶輝環帝座，定應長照鼎宮傍。"]'),
('0ea0f108-6a35-4598-aaa3-e6c5c470500d','閒居書事','楊時','宋','宋诗','song-poetry','','[]','虛庭幽草翠相環，默坐頹然草色間。',64,'全唐诗/poet.song.63000.json','["虛庭幽草翠相環，默坐頹然草色間。", "玩意詩書千古近，放懷天地一身閒。", "疏窗風度聊欹枕，永巷人稀獨掩關。", "誰信紅塵隨處凈，不論城郭與青山。"]'),
('123e55ff-ccca-4f30-8bc8-fe878d0e4128','直舍大風書事寄循道','楊時','宋','宋诗','song-poetry','','[]','枕書無寐首空搔，萬竅噓風正怒號。',64,'全唐诗/poet.song.63000.json','["枕書無寐首空搔，萬竅噓風正怒號。", "雪意浮空迷遠目，月林疏影見秋毫。", "幽庭所藉惟荒草，妙理應須付濁醪。", "誰念維舟江上客，落帆千里壓雲濤。"]'),
('30d32b99-0b29-40db-9cfb-fd18921c4aea','和席季成遊金鑾寺','楊時','宋','宋诗','song-poetry','','[]','朱甍碧瓦照孤城，杖屨翛然野色清。',64,'全唐诗/poet.song.63000.json','["朱甍碧瓦照孤城，杖屨翛然野色清。", "縠捲水風輕蕩漾，珠翻荷雨自虧盈。", "勝遊已覺非人境，妙語寧須味玉英。", "願借金篦聊刮目，不容幻翳有纖萌。"]'),
('26f313fb-b31a-4a9e-9e17-85d6d923e9e9','送王充道游三茅廬阜','楊時','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','荆吳相望各天涯，千里柴車鹿自隨。',64,'全唐诗/poet.song.63000.json','["荆吳相望各天涯，千里柴車鹿自隨。", "解轡定應春盡日，及歸宜待鶴來時。", "聖賢莫負樽中淥，日月長爲物外遲。", "若過匡廬訪真隠，卧龍菴下有期頤。"]'),
('6eb8f3da-fd91-4bd5-9ed2-5b057fd9b8d9','春日有懷諸友','楊時','宋','宋诗','song-poetry','','[]','憑几無聊晝掩扉，芬芬晴氣減春衣。',64,'全唐诗/poet.song.63000.json','["憑几無聊晝掩扉，芬芬晴氣減春衣。", "隔簾相應鶑初語，背日連飛雁北歸。", "莫逆交遊千里別，遠來音信兩年稀。", "追尋舊事成幽夢，觸物心行事事非。"]'),
('f571b940-42db-4444-ad08-eea92a0f541e','望湖樓晚眺','楊時','宋','宋诗','song-poetry','','[]','斜日侵簾上玉鈎，簷花飛動錦文浮。',64,'全唐诗/poet.song.63000.json','["斜日侵簾上玉鈎，簷花飛動錦文浮。", "湖光寫出千峰秀，天影融成十里秋。", "翠鷸翻風窺淺水，片雲隨意入滄洲。", "留連更待東窗月，注目晴空獨倚樓。"]'),
('dce89824-a050-44a6-a30d-fbac530fbe34','次韵晁以道','楊時','宋','宋诗','song-poetry','','[]','誰能載酒尋元亮，共寄無何作醉鄉。',64,'全唐诗/poet.song.63000.json','["誰能載酒尋元亮，共寄無何作醉鄉。", "便好收心事農圃，不須驚世露文章。", "壺中日月春長在，塞上烟塵客自忙。", "千里同風無遠近，未分秦隴與瀟湘。"]'),
('3ce721b9-c4da-4457-b70b-d27de8f3dcaa','和錢濟明游官園','楊時','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','虛舟觸物本無意，看花得句慚非才。',64,'全唐诗/poet.song.63000.json','["虛舟觸物本無意，看花得句慚非才。", "名園古寺尋春色，不葷勿鄙雙魚鰓。", "木奴千頭比封戶，秋實付與江風催。", "因思萬點愁人處，何似洞庭金作堆。"]'),
('783d5f2d-a760-4c44-8484-d3c26c13da0a','過吳江','楊時','宋','宋诗','song-poetry','','[]','天水相涵翠有餘，玻璃萬頃接方壺。',64,'全唐诗/poet.song.63000.json','["天水相涵翠有餘，玻璃萬頃接方壺。", "山浮晚照清如洗，風遠飛帆細欲無。", "漫叟未應甘皂櫪，散人終欲傲江湖。", "維舟况值鱸魚美，鱠疊銀絲飫腹腴。"]'),
('380837ab-beb3-4d0d-ba57-b14f4a0eb89b','南歸書事','楊時','宋','宋诗','song-poetry','','[]','浪漫人間壓客塵，衡門長憶鎖榆枌。',64,'全唐诗/poet.song.63000.json','["浪漫人間壓客塵，衡門長憶鎖榆枌。", "忘言擬盡輪人妙，陳迹慵尋史籀文。", "萬里功名心獨冷，一廛耕鑿力能勤。", "舊游欲問南歸趣，寂寞吾今過子雲。"]'),
('72daec56-d668-4d95-bd3d-8f4d09a9ea00','寸碧軒','楊時','宋','宋诗','song-poetry','','[]','隠隠遥山列畫屏，簷間寸碧與雲平。',64,'全唐诗/poet.song.63000.json','["隠隠遥山列畫屏，簷間寸碧與雲平。", "低回席上遺簪露，彷彿牆東翠黛橫。", "虛景遠涵千里色，晚暉仍借一溪清。", "春風景物知多少，可稱收身樂此生。"]'),
('73ad9c3d-4147-49e2-93c1-18341c3baeff','冬早書事','楊時','宋','宋诗','song-poetry','','[]','窈冥誰爲宰爐錘，榮謝唯知歲序催。',64,'全唐诗/poet.song.63000.json','["窈冥誰爲宰爐錘，榮謝唯知歲序催。", "臘日未經梅已綻，春風尚遠凍先開。", "愁無潤澤歸芳樹，獨有餘寒著死荄。", "收盡浮雲天愈凈，夜深猶起望三台。"]'),
('0a250f41-d53a-4fbb-aff0-9b6fda1e814f','齒落書懷','楊時','宋','宋诗','song-poetry','','[]','身上蕭條事事空，齒牙凋落賸衰翁。',64,'全唐诗/poet.song.63000.json','["身上蕭條事事空，齒牙凋落賸衰翁。", "渴心尚欠冰凌解，病骨長思藥力攻。", "文几倦親塵土暗，斷編慵理蠹魚封。", "南床穩卧陶公宅，枕上悠揚一榻風。"]'),
('eadf3475-a4d4-4f25-b64f-1cf172f5315d','書懷','楊時','宋','宋诗','song-poetry','','[]','敝裘千里北風寒，還憶簞瓢陋巷安。',32,'全唐诗/poet.song.63000.json','["敝裘千里北風寒，還憶簞瓢陋巷安。", "位重金多非所慕，直緣三釜慰親歡。"]'),
('dfce65cf-7c7f-4a35-9b40-8b2548cbfca5','端午日','楊時','宋','宋诗','song-poetry','','[]','悠悠南北各天涯，欲望鄉關眼已花。',32,'全唐诗/poet.song.63000.json','["悠悠南北各天涯，欲望鄉關眼已花。", "憶得親庭誰共語，應憐遊子未還家。"]'),
('814af062-100a-4728-860f-50c10354f641','渚宮觀梅寄康侯','楊時','宋','宋诗','song-poetry','','[]','欲驅殘臘變春風，只有寒梅作選鋒。',32,'全唐诗/poet.song.63000.json','["欲驅殘臘變春風，只有寒梅作選鋒。", "莫把疏英輕鬭雪，好藏清艷月明中。"]'),
('54d7b622-2c0c-4a91-8cd3-85749658385d','勉謝自明','楊時','宋','宋诗','song-poetry','','[]','少年力學志須彊，得失由來一夢長。',32,'全唐诗/poet.song.64000.json','["少年力學志須彊，得失由來一夢長。", "試問邯鄲欹枕客，人間幾度熟黄粱。"]'),
('bfaa33c2-88b0-453e-a7f1-1ecb66d44d23','臘月見桃花','楊時','宋','宋诗','song-poetry','','[]','脂臉輕勻作艷粧，未應潔白似梅香。',32,'全唐诗/poet.song.64000.json','["脂臉輕勻作艷粧，未應潔白似梅香。", "夭紅不見凌霜操，漫向春前取次芳。"]'),
('7f074882-9f82-435a-b45f-708aafb0c20d','過蘭溪','楊時','宋','宋诗','song-poetry','','[]','紛紛朝市競秋毫，江上霜風正怒號。',32,'全唐诗/poet.song.64000.json','["紛紛朝市競秋毫，江上霜風正怒號。", "不問揚瀾與彭浪，翩然東下日千艘。"]'),
('6959cbf2-ea9e-4d22-8d00-417f2b7f3d19','夜雨','楊時','宋','宋诗','song-poetry','','[]','似聞疏雨打篷聲，枕上悠揚夢半醒。',32,'全唐诗/poet.song.64000.json','["似聞疏雨打篷聲，枕上悠揚夢半醒。", "明日覺來渾不記，隔船相語過前汀。"]'),
('e320222c-34d3-45a9-8563-fbcfd0a5e57d','重經烏石舖','楊時','宋','宋诗','song-poetry','','[]','夾屋青松翠靄中，去年經此亦匆匆。',32,'全唐诗/poet.song.64000.json','["夾屋青松翠靄中，去年經此亦匆匆。", "重來烏石岡頭路，依舊松聲带曉風。"]'),
('421aa775-3932-4831-8f67-48c19f5fd7d9','江上','楊時','宋','宋诗','song-poetry','','[]','寒雲幕羃結秋陰，月淡霜娥冷不禁。',32,'全唐诗/poet.song.64000.json','["寒雲幕羃結秋陰，月淡霜娥冷不禁。", "更祝江波休蕩漾，莫令清影碎浮金。"]'),
('a598eac2-b588-408a-9c84-1fbad752fe20','淮上獨酌','楊時','宋','宋诗','song-poetry','','[]','廉纖晚雨洗輕塵，天淡雲浮夜色新。',32,'全唐诗/poet.song.64000.json','["廉纖晚雨洗輕塵，天淡雲浮夜色新。", "頼有麯生風味好，不須邀月作三人。"]'),
('b2892cc1-8ba8-45ee-9e77-23a2ac7d2dd0','吳國華暗香亭','楊時','宋','宋诗','song-poetry','','[]','漫愁青女妬新粧，已有風傳處處香。',32,'全唐诗/poet.song.64000.json','["漫愁青女妬新粧，已有風傳處處香。", "試問隠淪溪上客，欲將春色若爲藏。"]'),
('dc41b9c8-a0f9-47e5-930b-fbbccf5d5364','虛心亭','楊時','宋','宋诗','song-poetry','','[]','山橫鰲背碧巑岏，亭對浮筠縹緲間。',32,'全唐诗/poet.song.64000.json','["山橫鰲背碧巑岏，亭對浮筠縹緲間。", "蕭散誰爲三徑侶，祇應長共白雲閒。"]'),
('4b8576c4-4f2b-403a-9bfe-abad8f38ed76','容照巖','楊時','宋','宋诗','song-poetry','','[]','清時投迹在嶔崟，一穴晴光破晚陰。',32,'全唐诗/poet.song.64000.json','["清時投迹在嶔崟，一穴晴光破晚陰。", "刺草未容忘魏闕，故應長有子牟心。"]'),
('de46fe71-b699-4833-ae52-283cdea78a64','藏春峽','楊時','宋','宋诗','song-poetry','','[]','山銜幽徑碧如環，一壑風烟自往還。',32,'全唐诗/poet.song.64000.json','["山銜幽徑碧如環，一壑風烟自往還。", "不似武陵流出水，殘紅那得到人間。"]'),
('cd37f249-bcf8-4e8a-affe-c7a3e65ab79f','綠陰亭上','楊時','宋','宋诗','song-poetry','','[]','沙邊幽鳥傍清漪，瀧下漁船逆浪歸。',32,'全唐诗/poet.song.64000.json','["沙邊幽鳥傍清漪，瀧下漁船逆浪歸。", "身在輞川圖畫裏，晴空惟欠雪花飛。"]'),
('d35d4c3c-3be3-49ea-a351-fd2601113458','病中作','楊時','宋','宋诗','song-poetry','','[]','通衢隔轍斷經過，門巷空無雀可羅。',32,'全唐诗/poet.song.64000.json','["通衢隔轍斷經過，門巷空無雀可羅。", "驅去兒童卧虛室，蕭然惟一病維摩。"]'),
