('c6d968b4-c907-43bc-babf-63b0f63a22de','頌','釋曉純','宋','宋诗','song-poetry','','[]','軒昂師子首，牛足馬身材。',24,'全唐诗/poet.song.64000.json','["軒昂師子首，牛足馬身材。", "三道如能入，玄門疊疊開。"]'),
('b00b7907-36af-4a43-904d-604839ee0416','偈','釋曉純','宋','宋诗','song-poetry','','[]','有箇漢自從曠大劫，無住亦無依。',39,'全唐诗/poet.song.64000.json','["有箇漢自從曠大劫，無住亦無依。", "上無片瓦蓋頭，下無寸土立足。", "朝到西天，暮歸東土。"]'),
('f429d736-3ef3-4ad8-866e-0f18a5dc9067','偈四首  其一','釋繼昌','宋','宋诗','song-poetry','','[]','五陵公子爭誇富，百衲高僧不厭貧。',32,'全唐诗/poet.song.64000.json','["五陵公子爭誇富，百衲高僧不厭貧。", "近來世俗多顛倒，只重衣衫不重人。"]'),
('62bc31d4-a032-4491-b996-53fb707b6311','偈四首  其二','釋繼昌','宋','宋诗','song-poetry','','[]','木佛不度火，甘露臺前逢達磨。',30,'全唐诗/poet.song.64000.json','["木佛不度火，甘露臺前逢達磨。", "惆悵洛陽人未來，面壁九年空冷坐。"]'),
('83157ac0-2038-4bc3-83a3-e99ab538f40b','偈四首  其三','釋繼昌','宋','宋诗','song-poetry','','[]','金佛不度爐，坐歎勞生走道途。',30,'全唐诗/poet.song.64000.json','["金佛不度爐，坐歎勞生走道途。", "不向華山圖上看，豈知潘閬倒騎馿。"]'),
('20b34047-50fd-4732-8f4a-47d8f2bd713a','偈四首  其四','釋繼昌','宋','宋诗','song-poetry','','[]','泥佛不度水，一道靈光照天地。',30,'全唐诗/poet.song.64000.json','["泥佛不度水，一道靈光照天地。", "堪羨玄沙老古錐，不要南山要鼈鼻。"]'),
('49fd1433-678a-4453-8c9a-3125942e85a8','偈','化禪師','宋','宋诗','song-poetry','','[]','翠竹黄花非外境，白雲明月露全真。',32,'全唐诗/poet.song.64000.json','["翠竹黄花非外境，白雲明月露全真。", "頭頭盡是吾家物，信手拈來不是塵。"]'),
('65ca5d68-add0-4af3-b73b-b2d32a063f2b','偈','釋慧圓','宋','宋诗','song-poetry','','[]','這一交，這一交，萬兩黄金也合消。',32,'全唐诗/poet.song.64000.json','["這一交，這一交，萬兩黄金也合消。", "頭上笠，腰下包，清風明月杖頭挑。"]'),
('d388c9c9-6860-4f44-90ce-bd033bc93f6e','偈','釋戒香','宋','宋诗','song-poetry','','[]','孟冬改旦曉天寒，葉落歸根露遠山。',32,'全唐诗/poet.song.64000.json','["孟冬改旦曉天寒，葉落歸根露遠山。", "不是見聞生滅法，當頭莫作見聞看。"]'),
('62fdac65-688b-44d8-a0f7-3f46ab28dd34','問懷秀禪師','僧某','宋','宋诗','song-poetry','','[]','昔日溈山水牯牛，自從放去絕蹤由。',32,'全唐诗/poet.song.64000.json','["昔日溈山水牯牛，自從放去絕蹤由。", "今朝幸遇師登座，未審時人何處求。"]'),
('43e18c3e-8684-4fe0-b847-2e29ec2494af','偈','釋紹慈','宋','宋诗','song-poetry','','[]','我祖別行最上機，縱橫生殺絕猜疑。',32,'全唐诗/poet.song.64000.json','["我祖別行最上機，縱橫生殺絕猜疑。", "雖然塞斷羣狐路，返擲須還師子兒。"]'),
('6224fa45-e729-4b07-826b-4868d93fe485','偈','釋康源','宋','宋诗','song-poetry','','[]','山僧有一訣，尋常不漏泄。',32,'全唐诗/poet.song.64000.json','["山僧有一訣，尋常不漏泄。", "今日不囊藏，分明爲君說。", "寒時寒，熱時熱。"]'),
('eff0e241-baa7-445d-9317-30627aef8677','偈','釋宣能','宋','宋诗','song-poetry','','[]','石鞏箭，秘魔叉。',34,'全唐诗/poet.song.64000.json','["石鞏箭，秘魔叉。", "直下會得，眼裏空華。", "堪悲堪笑少林客，暗携隻履度流沙。"]'),
('40dbc290-a75d-4392-a814-c179029bc423','句','章縡','宋','宋诗','song-poetry','','[]','船尾淮山青未了，馬頭隋柳綠相迎。',16,'全唐诗/poet.song.64000.json','["船尾淮山青未了，馬頭隋柳綠相迎。"]'),
('2d5e76be-d34b-4b4c-a47b-8380947bc59f','劉阮洞  其一','王漢之','宋','宋诗','song-poetry','','[]','洞府門閒白日賒，碧潭清影照雲霞。',64,'全唐诗/poet.song.64000.json','["洞府門閒白日賒，碧潭清影照雲霞。", "弄珠人捧江皋佩，刻玉巖開閬苑花。", "風月有情回俗駕，塵埃無處問仙家。", "歸來悵望金橋處，露滴桃源一徑斜。"]'),
('ce0a4d2a-7b62-4807-9b08-a04c539f245e','劉阮洞  其二','王漢之','宋','宋诗','song-poetry','','[]','二女春遊閬苑花，醉邀劉阮飯胡麻。',32,'全唐诗/poet.song.64000.json','["二女春遊閬苑花，醉邀劉阮飯胡麻。", "仙衣忽逐笙簫去，空倚山頭恨落霞。"]'),
('cbf153da-acc8-4de5-a902-401eeceaf8b8','石橋','郭茂倩','宋','宋诗','song-poetry','','[]','石橋庵下少徘徊，雪暗松林撥不開。',32,'全唐诗/poet.song.64000.json','["石橋庵下少徘徊，雪暗松林撥不開。", "坐久無人天向午，雙烏飛上施生臺。"]'),
('a0d80d9e-e398-4a4b-84e7-f73aacdddb64','見山臺','李夷行','宋','宋诗','song-poetry','','[]','□□□□□□□，紛紛紅紫簇虛簷。',32,'全唐诗/poet.song.64000.json','["□□□□□□□，紛紛紅紫簇虛簷。", "山光不肯饒春色，故向花間出數尖。"]'),
('aebbbdd8-a548-49ce-bc63-e4396f434ab3','崇寧元年閏六月廿五日道祖再按鹽亭經光祿坂留題頓軒','薛紹彭','宋','宋诗','song-poetry','','[]','光祿坂高鹽亭東，潼江直下如彎弓。',64,'全唐诗/poet.song.64000.json','["光祿坂高鹽亭東，潼江直下如彎弓。", "山長水遠快望眼，少陵過後名不空。", "當時江山意不在，草動怕賊悲途窮。", "客行益遠心益泰，即今何羨開元中。"]'),
('61e79b73-c801-49fd-904c-3bb1e1501092','和米芾李公炤家二王以前帖宜傾囊購取寄詩','薛紹彭','宋','宋诗','song-poetry','','[]','聖草神蹤手自持，心潜模範識前規。',144,'全唐诗/poet.song.64000.json','["聖草神蹤手自持，心潜模範識前規。", "惜哉法書垂世久，妙帖堂堂或見遺。", "寶章大軸首尾俱，破古欺世完使離。", "當時鑒目獨子著，有如痼病工難醫。", "至今所收上卷五，流傳未免識者嗤。", "世間無論有晉魏，幾人解得真唐隋。", "文皇鑒定號得士，河南精識能窮微。", "即今未必無褚獠，寧馨動俗千金貲。", "古囊織褾可復得，白玉爲躞黄金題。"]'),
('b33812c2-9066-4b26-bae5-8b363bc40fcd','和米芾爲梁唐不收慰問帖寄詩','薛紹彭','宋','宋诗','song-poetry','','[]','聖賢尺牘間，吊問相酬答。',168,'全唐诗/poet.song.64000.json','["聖賢尺牘間，吊問相酬答。", "下筆或無意，興合自妍捷。", "名迹後人貴，品第分真雜。", "前世無大度，危亂相乘躡。", "白髮如蓮帽，騧馬似瓜貼。", "觸事爲不祥，凶語棄玉躞。", "料簡純吉書，乃有十七帖。", "當時博搜訪，所得固已狹。", "于此半千歲，歷世同灰劫。", "真聖掃忌諱，盡入淳化篋。", "巍巍覆載量，細事見廣業。", "唐人工臨寫，野馬成百疊。", "硬黄脫真迹，勾填本摹榻。", "今惟典刑在，後世皆可法。"]'),
('8e8a26e1-28a5-40c9-b7b7-de04647f73cf','和米芾越竹紙詩','薛紹彭','宋','宋诗','song-poetry','','[]','書便瑩滑如碑版，古來精紙惟聞繭。',64,'全唐诗/poet.song.64000.json','["書便瑩滑如碑版，古來精紙惟聞繭。", "杵成剡竹光凌亂，何用區區書素練。", "細分濃淡可評墨，副以谿巖難乏硯。", "世間此語誰復知，千里同風未相見。"]'),
('b3318dd6-398e-41d0-b67f-e8ec2a0c3617','論筆硯間物','薛紹彭','宋','宋诗','song-poetry','','[]','研滴須琉璃，鎮紙須金虎。',48,'全唐诗/poet.song.64000.json','["研滴須琉璃，鎮紙須金虎。", "格筆須白玉，研磨須墨古。", "越竹滑如苔，更須加萬杵。", "自封翰墨卿，一書當千戶。"]'),
('9f03d5cb-a8d3-44c6-bd9d-61a2d2eaaefe','秘閣觀書','薛紹彭','宋','宋诗','song-poetry','','[]','訪古求書二十年，二王真蹟幾人傳。',384,'全唐诗/poet.song.64000.json','["訪古求書二十年，二王真蹟幾人傳。", "每尋同好得消息，聞韶忘味心拳拳。", "諸家真贋可屈指，緹巾入手分媸妍。", "道山東觀富奇古，世人想望如雲天。", "此生塵俗分不到，九重有路來無緣。", "豈知司存預符璽，芸臺高議開賓筵。", "翰林入坐中執法，未容凡吏陪諸仙。", "酒闌接武上秘閣，皇居紫禁凌非烟。", "晉康法書在寶櫝，傍架牙籤一一穿。", "紫衣黄門許一見，忽開復閉嚴關鍵。", "右軍盡善歷代寶，八法獨高東晉賢。", "宏文舊物印章在，開元小篆朱猶鮮。", "草行無窮少真楷，硬黄色浄昏麻牋。", "鳳翥龍翔斜復直，烟霏霧結斷還連。", "溟漲筆力老轉劇，臨池尚嘆張學專。", "言奴得法號神俊，逼人體勢殊翩翩。", "自方家尊聘豪翰，駸駸欲過驊騮前。", "崇虛鵝羣最真蹟，萬里古色星日懸。", "筆乾墨淡不可搨，拙手添暈難磨湔。", "小璽肥書兩貞觀，每角一字居四邊。", "南朝妙鑒各題檢，懷充在後前僧權。", "爭妍取勢押縫尾，磐石卧虎推滿騫。", "琅琊世譜今乃識，寶章十代何蟬聯。", "忠良賊孽無去取，茂宏處仲同一編。"]'),
('a4221ba6-b14a-48ed-95d0-e3b483b72257','清閟閣','薛紹彭','宋','宋诗','song-poetry','','[]','虛堂幽幽竹森森，直節常便靜者心。',96,'全唐诗/poet.song.64000.json','["虛堂幽幽竹森森，直節常便靜者心。", "秋檻風高聲戛玉，夜庭月白影篩金。", "檀欒相對復何有，掛壁丹青古名手。", "飛泉激石湧崖間，更愛霜鴻下葦灘。", "錦題玉軸照清閟，夐無一點塵埃氣。", "百尋砌下日相親，千畝渭川空自翠。"]'),
('9ad110ab-1bb8-461e-a53a-49051a89464e','二花','薛紹彭','宋','宋诗','song-poetry','','[]','鮮鮮中園菊，粲粲籬東畔。',60,'全唐诗/poet.song.64000.json','["鮮鮮中園菊，粲粲籬東畔。", "的的秋水蓮，嫋嫋西風岸。", "迢迢白衣人，皓皓涉江腕。", "重陽尊酒親，霧夕容光爛。", "物生各有宜，不計年華晏。"]'),
('01533034-f928-4b57-ab75-eea1d9a914b2','奉寄魯直學士','薛紹彭','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','瘴地經行促棹謳，周南太史幾年留。',64,'全唐诗/poet.song.64000.json','["瘴地經行促棹謳，周南太史幾年留。", "後來遥識猶青眼，別久懸知半白頭。", "宋玉又經巫峽去，謫仙初罷夜郎遊。", "長江風水追難及，悵望春波一葉舟。"]'),
('6b2197e0-c630-4b21-b37a-92db6109a1b1','漢高帝試劍石','薛紹彭','宋','宋诗','song-poetry','','[]','豐沛布衣吳芮客，回首咸秦坐悽惻。',115,'全唐诗/poet.song.64000.json','["豐沛布衣吳芮客，回首咸秦坐悽惻。", "漫隨霸楚西道遷，未甘漢地山河窄。", "隨身三尺青龍子，曾斷當塗素靈死。", "手提巖上試秋水，大石迎風開披靡。", "東歸欲整堂堂陣，吳兒未足勞餘刃。", "炎靈天啟定中原，大言成事人方信。", "君不見不侯飛將能射虎，誤中他山猶飲羽。"]'),
('b3257e8c-4f15-489b-bfb0-b1f8aedbf72b','馬伏波事','薛紹彭','宋','宋诗','song-poetry','','[]','人生在衣食，但取飽與溫。',96,'全唐诗/poet.song.64000.json','["人生在衣食，但取飽與溫。", "下澤駕款段，曾不羨華軒。", "仕爲郡掾吏，身自守丘園。", "鄉里稱善人，此外不足論。", "志大心自勞，福厚禍有根。", "提兵泊浪間，薏苡讒謗喧。", "飛鳶跕跕墮，卧視瘴水昏。", "永懷平生時，空愧少游音。"]'),
('3966a0ee-4689-41c0-bbcb-de320a41e7fb','白石潭','薛紹彭','宋','宋诗','song-poetry','','[]','輕舟繫石依蒹葭，春後清江便是家。',32,'全唐诗/poet.song.64000.json','["輕舟繫石依蒹葭，春後清江便是家。", "蓬底爨烟將稚子，共携漁網曬晴沙。"]'),
('fbe0440e-7f59-4be7-96b3-7fbeec08147c','荼䕷','薛紹彭','宋','宋诗','song-poetry','','[]','野白荼䕷夾路長，迎風不斷挹濃芳。',32,'全唐诗/poet.song.64000.json','["野白荼䕷夾路長，迎風不斷挹濃芳。", "鳳池荀令曾來否，幾許薰鑪敵此香。"]'),
('56c23c85-e39e-4361-912d-009574f4d7ac','經行三首  其一','薛紹彭','宋','宋诗','song-poetry','','[]','辯士祠邊半嶺松，不容凡木亂江風。',32,'全唐诗/poet.song.64000.json','["辯士祠邊半嶺松，不容凡木亂江風。", "筇枝拄到峰頭閣，天籟都歸十八公。"]'),
('ce419762-a997-48cd-b741-b0494a0f7c98','經行三首  其二','薛紹彭','宋','宋诗','song-poetry','','[]','水石相迎擊目新，兩峰秀色引朱輪。',32,'全唐诗/poet.song.64000.json','["水石相迎擊目新，兩峰秀色引朱輪。", "使君自比蘭亭後，金字磨崖更幾人。"]'),
('0c27d063-eb52-499b-9d66-5a4a013a6c58','經行三首  其三','薛紹彭','宋','宋诗','song-poetry','','[]','月分圓影委金波，峰面無塵瑩不磨。',32,'全唐诗/poet.song.64000.json','["月分圓影委金波，峰面無塵瑩不磨。", "應是飛仙梳洗處，碧臺青綬掛雲蘿。"]'),
('20456b82-f756-4f99-9525-066e7396cef6','皇華','薛紹彭','宋','宋诗','song-poetry','','[]','橘樹松林綠徑長，竹籬縈繞當城隍。',32,'全唐诗/poet.song.64000.json','["橘樹松林綠徑長，竹籬縈繞當城隍。", "皇華何異投荒客，已過山川是夜郎。"]'),
('d9e98b21-81a4-46f9-915b-003fed00f00e','詩一首','薛紹彭','宋','宋诗','song-poetry','','[]','東晉風流勝事多，一時人物盡消磨。',32,'全唐诗/poet.song.64000.json','["東晉風流勝事多，一時人物盡消磨。", "不因醉本蘭亭在，後世誰知舊永和。"]'),
('6ce6de34-54e9-46dd-8d3f-05f40c058019','雲頂山','薛紹彭','宋','宋诗','song-poetry','','[]','山壓衆峰首，寺占紫雲頂。',204,'全唐诗/poet.song.64000.json','["山壓衆峰首，寺占紫雲頂。", "西遊金泉來，登山緩歸軫。", "昨暮下三峽，出谷已延頸。", "山名高劍外，回首陋前嶺。", "躋攀困難到，頼此晝亦永。", "巍巍石城出，步步松徑引。", "青霄屋萬楹，下俯二川境。", "玉壘連金雁，西軒列阡畛。", "青城與岷峨，天際暮雲隠。", "少城白烟裏，水墨澹微影。", "江流一練带，不復辨漁艇。", "東慚梓隘闕，右喜錦川迥。", "磐陀石不轉，枯枿弄芒穎。", "四更月未出，蕙帳天風緊。", "客行弊帤垢，到此凡慮屏。", "暫時方外遊，聊愜素心靜。", "明朝武江路，拘窘逐炎景。"]'),
('24e5e84d-390b-4181-a564-42afe9b9c3d8','左綿山中多青松風俗賤之止供樵爨之用郡齋僧剎不見一本余過而太息輒諷通守晉伯移植佳處使人知爲可貴東川距綿百里餘入境遂不復有晉伯因以爲惠沿流而來至此皆活作詩述謝并代簡師道史君','薛紹彭','宋','宋诗','song-poetry','','[]','越王樓下種成行，濯濯分來一葦杭。',64,'全唐诗/poet.song.64000.json','["越王樓下種成行，濯濯分來一葦杭。", "偃蓋可須千歲榦，封條已傲九秋霜。", "含風便有笙竽韵，带雨偏垂玉露光。", "免作爨烟茅屋底，華軒自在拂雲長。"]'),
('06784c9d-04ad-4893-940e-b20ce434f944','和巨濟韵','薛紹彭','宋','宋诗','song-poetry','','[]','通泉字法出官奴，日日臨池恨不如。',64,'全唐诗/poet.song.64000.json','["通泉字法出官奴，日日臨池恨不如。", "雙鯉可無輕素練，數行惟作硬黄書。", "鄉關何處三秦路，馬足經年萬里餘。", "多謝玉華宮畔客，新詩未覺故人疏。"]'),
('519dcaca-c3ba-4688-84dd-05306737a823','詩一首','薛紹彭','宋','宋诗','song-poetry','','[]','晉大司馬至洛陽，威略已著推砍羌。',96,'全唐诗/poet.song.64000.json','["晉大司馬至洛陽，威略已著推砍羌。", "聲馳江龍傳國光，右軍筆陣爭堂堂。", "妙用作意驅後鋩，驚鴻乍起游龍翔。", "仁祖無奕烏衣郎，排名篇末流遺芳。", "開元散落王涯藏，聯翩飛動茂密行。", "料簡鑒賞盛有唐，傳授視此真印章。"]'),
('533473fc-a6ff-4738-8cb8-9035eec52330','句  其一','薛紹彭','宋','宋诗','song-poetry','','[]','雨不濕行逕，雲猶依故山。',12,'全唐诗/poet.song.64000.json','["雨不濕行逕，雲猶依故山。"]'),
