('88f562ac-966a-4be8-ad7c-c01e583b739f','句  其二二','薛紹彭','宋','宋诗','song-poetry','','[]','自然鷗鳥親，日與漁樵遇。',12,'全唐诗/poet.song.64000.json','["自然鷗鳥親，日與漁樵遇。"]'),
('9943e853-d40e-48a6-8f25-3e51436310c9','句  其二三','薛紹彭','宋','宋诗','song-poetry','','[]','去意已輕千里陌，深杯難醉九迴腸。',32,'全唐诗/poet.song.64000.json','["去意已輕千里陌，深杯難醉九迴腸。", "灞陵葉落秋風裏，忍對霜天數雁行。"]'),
('35982fda-b02d-4588-a847-c0bddb20c44a','宿草堂寺','薛嗣昌','宋','宋诗','song-poetry','','[]','馳車晚叩古禪林，喬木參天一徑深。',64,'全唐诗/poet.song.64000.json','["馳車晚叩古禪林，喬木參天一徑深。", "門外亂山連翠色，竹間流水潄清音。", "幽懷暫喜來栖處，高士遺蹤悉訪尋。", "誰會宗風當日意，庭前蒼檜尚青陰。"]'),
('8ba49e5a-88ca-4586-b0b8-ee5d0e8cd613','棲巖寺','薛嗣昌','宋','宋诗','song-poetry','','[]','出郭自然塵事少，携家况作棲巖行。',64,'全唐诗/poet.song.64000.json','["出郭自然塵事少，携家况作棲巖行。", "千尋盡處暮雲碧，萬籟息時霜月明。", "林外扶疏竹影碎，嶺頭依約松風聲。", "他年若此卜幽隠，興來更遂登臨情。"]'),
('49044e45-8d00-4dd9-b64a-5ec7e2808884','遊洞霄宮','潘良正','宋','宋诗','song-poetry','','[]','石壇風冷露華凝，羣玉崢嶸簇畫屏。',64,'全唐诗/poet.song.64000.json','["石壇風冷露華凝，羣玉崢嶸簇畫屏。", "水赤久傳丹作井，山高時借翠爲庭。", "鶴迎仙馭迷三島，雲入洞天朝百靈。", "回首武陵歸去路，碧桃零落晚峰青。"]'),
('ddaa1cbe-3e08-42bc-a18e-53506816ac03','秋霜閣','丁惟','宋','宋诗','song-poetry','','[]','高閣何年結構成，朱簾捲處眼偏明。',64,'全唐诗/poet.song.64000.json','["高閣何年結構成，朱簾捲處眼偏明。", "階前古木寒雲色，澗底流泉碎石聲。", "山近烟嵐浮几席，樓高星斗在簷楹。", "我來三伏炎蒸候，便覺清風兩腋生。"]'),
('27807317-6043-4af2-8e62-ba82936a762e','詠邛江','榮咨道','宋','宋诗','song-poetry','','[]','平生林壑性，客宦久羈束。',36,'全唐诗/poet.song.64000.json','["平生林壑性，客宦久羈束。", "得麾邛江隈，雖遠愜所欲。", "雲水遠重城，青山長在目。"]'),
('b771312d-3b64-4ed3-b88e-4e06fbc1ad25','絕句','鄧春卿','宋','宋诗','song-poetry','','[]','在巷愧無顔子志，過廬難稱魏公心。',32,'全唐诗/poet.song.64000.json','["在巷愧無顔子志，過廬難稱魏公心。", "望塵不敢希潘岳，雲滿南山雪滿簪。"]'),
('e25b32ee-399b-4e41-b5ae-800665450df2','詠地藏殿牡丹一莖五花','鍾離景伯','宋','宋诗','song-poetry','','[]','春風榮萬木，此卉異常葩。',48,'全唐诗/poet.song.64000.json','["春風榮萬木，此卉異常葩。", "海角逢三月，僧房見五花。", "馨香驚俗眼，燦爛照高牙。", "公子休追賞，如來會上誇。"]'),
('c6749d83-fb83-4ac6-9794-c4b0370ef75a','關山月','宋構','宋','宋诗','song-poetry','','[]','關山月，關山月，千里寒光射冰雪。',64,'全唐诗/poet.song.64000.json','["關山月，關山月，千里寒光射冰雪。", "一聲羌管裂青雲，隴上行人腸斷絕。", "腸斷絕兮將奈何，爲君把酒問常娥。", "冰輪桂魄圓時少，應似人間離別多。"]'),
('7df03dd7-47c0-46e7-b157-ef69e8fa8f9c','關山雪','宋構','宋','宋诗','song-poetry','','[]','關山雪，關山雪，遠接洮西千里白。',64,'全唐诗/poet.song.64000.json','["關山雪，關山雪，遠接洮西千里白。", "試登隴首瞰八荒，表裏高低都一色。", "日高融液流車轍，凍作堅冰敲不裂。", "早晚春風動地來，消盡寒威百花發。"]'),
('6bc461be-eae3-40a9-9c6f-8da4619e6962','東山高卧','林放','宋','宋诗','song-poetry','','[]','三間老屋青山幽，清風灑灑寒颼颼。',80,'全唐诗/poet.song.64000.json','["三間老屋青山幽，清風灑灑寒颼颼。", "脫巾坦腹卧其下，此身直與淵明儔。", "老松飛翠落夏簟，六月不暑凉於秋。", "人生百年一夢幻，世間萬事空悠悠。", "一聲野鶴忽驚醒，山爐活火茶烟浮。"]'),
('f87343d4-5121-41ef-9826-3f62033d00a9','贈琴僧','林放','宋','宋诗','song-poetry','','[]','霜林凋落雲影垂，朔風獵獵鼓寒威。',112,'全唐诗/poet.song.64000.json','["霜林凋落雲影垂，朔風獵獵鼓寒威。", "偶來禪房訪虛寂，上人爲我彈金徽。", "此調悠悠泯千載，今日忽聞一嗟咨。", "上人所彈不在指，我亦非於耳聽之。", "霜天玉磬敲清曉，夜月秋聲動翠微。", "舉世紛紛愛箏筑，寂寥古意誰能知。", "過門不是鍾期子，慎勿汗漫調朱絲。"]'),
('0b754002-42ba-49a0-8d45-6021108cc90a','上堂偈','微禪師','宋','宋诗','song-poetry','','[]','日暖風和柳眼青，冰消魚躍浪花生。',32,'全唐诗/poet.song.64000.json','["日暖風和柳眼青，冰消魚躍浪花生。", "當鋒妙得空王印，半夜崑崙戴雪行。"]'),
('68a7e14b-804a-429d-b22f-10c4a71395f8','頌','釋清滿','宋','宋诗','song-poetry','','[]','饑餐松柏葉，渴飲澗中泉。',40,'全唐诗/poet.song.64000.json','["饑餐松柏葉，渴飲澗中泉。", "看罷青青竹，和衣自在眠。", "更有山懷爲君說，今年年是去年年。"]'),
('9b9412a7-47fc-4a98-8751-d4481a1862ce','偈','釋清滿','宋','宋诗','song-poetry','','[]','不是道，不是禪。',20,'全唐诗/poet.song.64000.json','["不是道，不是禪。", "每逢三五夜，皓月十分圓。"]'),
('2114a131-9349-4193-9fd6-4c9d0ae8ccc3','上堂偈','廣禪師','宋','宋诗','song-poetry','','[]','月頭東畔出，月向西邊沒。',48,'全唐诗/poet.song.64000.json','["月頭東畔出，月向西邊沒。", "來去急如梭，催人成白骨。", "山僧有一法，堪爲保命術。", "生死不相干，打破精魂窟。"]'),
('571af014-4b74-468d-8651-7c5fe4e381ba','濯泉亭','朱蒙正','宋','宋诗','song-poetry','','[]','風浪江頭正激湍，小亭溪上水平寬。',32,'全唐诗/poet.song.64000.json','["風浪江頭正激湍，小亭溪上水平寬。", "濯纓不做彈冠想，一曲滄浪釣雪寒。"]'),
('768764e3-c623-42b3-9f8b-0f2960d3dedc','臨寂偈  其一','釋若愚','宋','宋诗','song-poetry','','[]','本自無家可得歸，雲邊有路許誰知。',32,'全唐诗/poet.song.64000.json','["本自無家可得歸，雲邊有路許誰知。", "溪光搖落西山月，正是仙潭夢斷時。"]'),
('37c3717d-2304-4f1f-ac1f-31d7f1deb229','臨寂偈  其二','釋若愚','宋','宋诗','song-poetry','','[]','室裏千花羅網，夢中七寶蓮池。',28,'全唐诗/poet.song.64000.json','["室裏千花羅網，夢中七寶蓮池。", "踏得西歸路穩，更無一點狐疑。"]'),
('a6a5dc9c-291c-4f1c-9fe8-f2456724afb2','題玉泉','黄璞','宋','宋诗','song-poetry','','[]','水性能方圓，泉色常珪璧。',48,'全唐诗/poet.song.64000.json','["水性能方圓，泉色常珪璧。", "雲山靜有輝，瓊液來無迹。", "泉上修禪人，曹溪分一滴。", "鑑止更澄源，紛紛萬緣息。"]'),
('6970bd33-1b4b-42aa-b697-44b702b9180b','書鄧先生石几','項傳','宋','宋诗','song-poetry','','[]','昔聞河上公，今見濠上翁。',24,'全唐诗/poet.song.64000.json','["昔聞河上公，今見濠上翁。", "姓名氏時易，道德經解同。"]'),
('66dd158d-1477-495a-ab25-267432627725','戲題指紋鬭牛圖','謝舉廉','宋','宋诗','song-poetry','','[]','左者前其角，右者後其足。',56,'全唐诗/poet.song.64000.json','["左者前其角，右者後其足。", "浼君雙指螺，戰此兩觳觫。", "草長水遠日悠悠，不向桑間自在休。", "蝸頭尚可屠蠻觸，壁上從今鬭二牛。"]'),
('7b280c3e-df57-461d-8f31-00fbfdb5d0f0','西捷口號','謝舉廉','宋','宋诗','song-poetry','','[]','聖明陛下如先帝，闢國謀臣似召公。',64,'全唐诗/poet.song.64000.json','["聖明陛下如先帝，闢國謀臣似召公。", "不遣毛嬙嬪漠北，只將魏尚守雲中。", "百年境土逡巡復，萬里窠巢指顧空。", "今日版圖非昔日，玉關西有嶺名葱。"]'),
('338cf9d5-d619-4948-8e18-05b2d41b66e4','浴日亭','謝舉廉','宋','宋诗','song-poetry','','[]','煌煌太陽精，浴以滄溟水。',24,'全唐诗/poet.song.64000.json','["煌煌太陽精，浴以滄溟水。", "光潤無纖滓，畏愛從此始。"]'),
('4b68615a-d943-4f52-b11c-433f5d4580f5','句  其一','謝舉廉','宋','宋诗','song-poetry','','[]','萬里一時開驥足，百年今始破天荒。',16,'全唐诗/poet.song.64000.json','["萬里一時開驥足，百年今始破天荒。"]'),
('d4a4f5c4-289d-4f7b-a2b8-d556476c515a','句  其二','謝舉廉','宋','宋诗','song-poetry','','[]','秋風鱠鱸絲，霜月持蟹螯。',12,'全唐诗/poet.song.64000.json','["秋風鱠鱸絲，霜月持蟹螯。"]'),
('2e3eabad-324e-49f1-b9b1-56e128f3e471','鑑湖亭','李翔','宋','宋诗','song-poetry','','[]','古寺蕭蕭愁思濃，檻荷高下望秋風。',64,'全唐诗/poet.song.64000.json','["古寺蕭蕭愁思濃，檻荷高下望秋風。", "一塵不到真幽處，萬象都含清景中。", "但見溪光來遠近，略無雲氣礙虛空。", "誰知刺史標名意，一片靈臺事事通。"]'),
('1af07b93-9ef1-4b68-99c2-efba4118fbf2','朝天堤','李翔','宋','宋诗','song-poetry','','[]','兩山吞浪白如烟，忽見橋梁接岸邊。',64,'全唐诗/poet.song.64000.json','["兩山吞浪白如烟，忽見橋梁接岸邊。", "已是築成堤上路，不須重喚渡頭船。", "千年野鶴歸華表，百尺長虹駕巨川。", "歲物已收人力暇，閭閻爭頌使君賢。"]'),
('216c09cd-48be-4484-baf4-6349040dc8b6','滄浪烟雨','李翔','宋','宋诗','song-poetry','','[]','峰澗烟波翠靄濃，危亭飛聳到晴空。',64,'全唐诗/poet.song.64000.json','["峰澗烟波翠靄濃，危亭飛聳到晴空。", "鴛來菡萏紅香裏，人在琉璃翠影中。", "洗出嵐光全是雨，捲回秋暑却因風。", "使君夜宴冰壺裏，更有銀河一派通。"]'),
('4824623f-f073-49f7-974b-c7364ae321d2','句','許轂','宋','宋诗','song-poetry','','[]','一條碧水練鋪地，萬疊好山屏倚天。',16,'全唐诗/poet.song.64000.json','["一條碧水練鋪地，萬疊好山屏倚天。"]'),
('f45f6198-4253-42a7-9ec3-178f8fc1b4f4','呈東坡','袁點','宋','宋诗','song-poetry','','[]','青蓋美人回鳳带，繡衣男子返雲車。',32,'全唐诗/poet.song.64000.json','["青蓋美人回鳳带，繡衣男子返雲車。", "上天一笑渾無事，從此人間樂有餘。"]'),
('35a28b3d-7254-411a-9097-1b5874e5348e','詩一首','張大亨','宋','宋诗','song-poetry','','[]','方寸平田便有餘，子孫無復廢耕鋤。',32,'全唐诗/poet.song.64000.json','["方寸平田便有餘，子孫無復廢耕鋤。", "已將不死爲嘉種，更向無何築隠居。"]'),
('35486d7d-a8fd-40a0-8c9f-67099a44598a','福聖觀','姚祜','宋','宋诗','song-poetry','','[]','織女機成未剪裁，練光浮出五雲開。',64,'全唐诗/poet.song.64000.json','["織女機成未剪裁，練光浮出五雲開。", "日邊瑩彩憑空落，澗底寒聲動地來。", "望徹九霄人錯愕，勢傾三井雪崩摧。", "卧龍欲起爲霖雨，肯逐洪波去不回。"]'),
('abe77eda-d9b3-47e1-80e7-b8b51163bb22','遊虎丘','虞賓','宋','宋诗','song-poetry','','[]','相期到虎丘，出郭始乘舟。',48,'全唐诗/poet.song.64000.json','["相期到虎丘，出郭始乘舟。", "曠野雲山路，平原水國秋。", "客心還未喜，木葉已先愁。", "那得真僧在，重教石點頭。"]'),
('1a1fd8c4-4887-405f-8ab1-43a203c09e26','醉仙崖','魯百能','宋','宋诗','song-poetry','','[]','高倚青冥插酒星，山崖誰作醉仙形。',32,'全唐诗/poet.song.64000.json','["高倚青冥插酒星，山崖誰作醉仙形。", "從來天地爲衾枕，應笑人間有獨醒。"]'),
('1fc3a6ea-2115-4bef-994a-e81416720340','同慶府','魯百能','宋','宋诗','song-poetry','','[]','山占仇池地，江分白馬氐。',24,'全唐诗/poet.song.64000.json','["山占仇池地，江分白馬氐。", "潭深龍自蟄，亭迥鳳曾棲。"]'),
('0016919e-c319-4ab1-a146-4474cdd5e488','九里','李熙載','宋','宋诗','song-poetry','','[]','巖穴玲瓏幾度秋，簪峰高插聳鼇頭。',64,'全唐诗/poet.song.64000.json','["巖穴玲瓏幾度秋，簪峰高插聳鼇頭。", "化人舊有阿羅漢，喜客今逢老比丘。", "石罅日聞甘露滴，山間時見慶雲浮。", "靈巖特爲南鄉設，從此生賢繼不休。"]'),
('25afcd7e-cce8-4283-8f20-85362163f1f4','句','李熙載','宋','宋诗','song-poetry','','[]','一門萃忠孝，竹帛寫家聲。',12,'全唐诗/poet.song.64000.json','["一門萃忠孝，竹帛寫家聲。"]'),
('4cf9e90b-56b0-4c6d-aa38-f34c22b7f720','麻姑山','范柔中','宋','宋诗','song-poetry','','[]','嵐迎曉日碧烟收，霜薄風清勝會遊。',64,'全唐诗/poet.song.64000.json','["嵐迎曉日碧烟收，霜薄風清勝會遊。", "虎駕不來空紫府，真人應接又瀛洲。", "巖前野草冬猶秀，亭下飛泉凍亦流。", "他日卜鄰深有意，竟須平步揖浮丘。"]'),
('eb5a1b37-ad94-4584-9a1d-6fa70e2ca997','泊舟','黄伯厚','宋','宋诗','song-poetry','','[]','片帆寂寞繞孤村，茅屋驚寒半掩門。',32,'全唐诗/poet.song.64000.json','["片帆寂寞繞孤村，茅屋驚寒半掩門。", "行草不成風斷雁，一江烟雨正黄昏。"]'),
('c43b7e6b-9f6b-4fac-b403-97f01c50b774','椒屯墟','黄伯厚','宋','宋诗','song-poetry','','["\u897f\u6e56"]','喬水村墟十里秋，漁鹽微利競蠅頭。',64,'全唐诗/poet.song.64000.json','["喬水村墟十里秋，漁鹽微利競蠅頭。", "平坡淺草眠黄犢，小渚輕波泛白鷗。", "竹外客喧山市散，柳陰人醉酒旗收。", "清幽彷彿西湖上，惆悵歸來獨倚樓。"]'),
('d95aed0e-4bef-4d16-9027-ac5240cc9931','句','楊希仲','宋','宋诗','song-poetry','','[]','回環萬木森幢蓋，縹緲三山落市廛。',16,'全唐诗/poet.song.64000.json','["回環萬木森幢蓋，縹緲三山落市廛。"]'),
('d66958b7-6503-43c0-8d9e-bae8c5ff8d26','仙都山','胡份','宋','宋诗','song-poetry','','[]','鳥道盤空上，松根抱石生。',24,'全唐诗/poet.song.64000.json','["鳥道盤空上，松根抱石生。", "羽人分兩舍，鷄犬自聞聲。"]'),
('6b836e88-3532-4db9-a76a-3c98f8ce7ae1','遊雁門山','胡份','宋','宋诗','song-poetry','','[]','羲和前珥節，雲鎖已先開。',48,'全唐诗/poet.song.64000.json','["羲和前珥節，雲鎖已先開。", "仙鶴迎人至，山花拂酒來。", "問奇緣石室，伐陰出層臺。", "人影半空落，歸鷂足下迴。"]'),
('35580a43-0c9c-4aad-be30-9f6b4ade14c3','句','胡份','宋','宋诗','song-poetry','','[]','絕艷更無花得似，暗香惟有月明知。',16,'全唐诗/poet.song.64000.json','["絕艷更無花得似，暗香惟有月明知。"]'),
('8762dfff-7683-41e7-b81d-54b19de19cf9','何仙姑祠','梅蟠','宋','宋诗','song-poetry','','[]','昔聞謝自然，今祠何女仙。',108,'全唐诗/poet.song.64000.json','["昔聞謝自然，今祠何女仙。", "昌黎久不作，奇事相留傳。", "當其始生時，紫雲光燭天。", "煉服雲母丹，紅玉飛瓊烟。", "窈窕顔不老，霞帔尚翩翩。", "琪花露含蕊，瑶水月在蓮。", "恍若坐深閨，真息長眇綿。", "左携魏夫人，右挾夏嬋娟。", "不入天台路，永同龍漢年。"]'),
('890ea5d5-033e-4a1a-8948-03ab6b86f7d7','句  其一','梅蟠','宋','宋诗','song-poetry','','[]','滄海有風鵬翼健，青雲得路馬蹄輕。',16,'全唐诗/poet.song.64000.json','["滄海有風鵬翼健，青雲得路馬蹄輕。"]'),
('1398d6b8-0467-451f-b03e-928b3a832fe1','句  其二','梅蟠','宋','宋诗','song-poetry','','[]','延相堂前偏利市，衮衣相次又來迎。',16,'全唐诗/poet.song.64000.json','["延相堂前偏利市，衮衣相次又來迎。"]'),
('31540ed0-01aa-446c-9d81-46ac20b4bd10','寄郴守阮戶部','閻孝忠','宋','宋诗','song-poetry','','[]','郴陽古名邦，四座拱山色。',24,'全唐诗/poet.song.64000.json','["郴陽古名邦，四座拱山色。", "秀氣鍾異人，闤闠儼仙宅。"]'),
('7a52d52f-645c-40aa-a8a4-0ff696004594','俯春亭','閻孝忠','宋','宋诗','song-poetry','','[]','城上危亭可摘雲，四邊山色翠爲鄰。',32,'全唐诗/poet.song.64000.json','["城上危亭可摘雲，四邊山色翠爲鄰。", "下窺城郭無餘藴，草色花光盡是春。"]'),
('b3de496e-d7d9-4aa3-83b8-e2fc9a9d6ef7','黄相山','閻孝忠','宋','宋诗','song-poetry','','[]','東带連山接五羊，西分郴水下三湘。',32,'全唐诗/poet.song.64000.json','["東带連山接五羊，西分郴水下三湘。", "路人到此休南去，嶺外千峰盡瘴鄉。"]'),
('576e7ff7-81df-4dbe-b468-13f7b8a5fe38','句  其一','閻孝忠','宋','宋诗','song-poetry','','[]','不辭遠作瀟湘客，且入三仙洞裏來。',16,'全唐诗/poet.song.64000.json','["不辭遠作瀟湘客，且入三仙洞裏來。"]'),
('684e9203-467f-4bd4-9127-896df4b2de09','句  其二','閻孝忠','宋','宋诗','song-poetry','','[]','橘柚人家黄壓帽，松篁僧寺翠爲鄰。',16,'全唐诗/poet.song.64000.json','["橘柚人家黄壓帽，松篁僧寺翠爲鄰。"]'),
('3af37129-cdaa-47f5-a215-43a32b1b1570','句  其三','閻孝忠','宋','宋诗','song-poetry','','[]','賢如贈扇揚風日，貧似開門卧雪時。',16,'全唐诗/poet.song.64000.json','["賢如贈扇揚風日，貧似開門卧雪時。"]'),
('42cffc31-07f0-4510-a18c-152ba609225d','贈鼓琴文照大師','劉發','宋','宋诗','song-poetry','','[]','寶琴何所得，所得甚幽微。',48,'全唐诗/poet.song.64000.json','["寶琴何所得，所得甚幽微。", "聊借絲桐韵，還超智慧機。", "霜風悲玉軫，江月入珠徽。", "向此諸緣盡，人間孰是非。"]'),
('b4a8a4eb-5aa9-464f-979a-486ca9f95c66','游洞霄山中','陳律','宋','宋诗','song-poetry','','[]','白日黄塵客路迷，偶尋幽事入烟扉。',64,'全唐诗/poet.song.64000.json','["白日黄塵客路迷，偶尋幽事入烟扉。", "雲行翠岫鶴爭舞，月落青林人未歸。", "自喜身心無世繫，願從巖谷謝朝衣。", "祥光洞口仙題在，讀罷令人悟昨非。"]'),
('47aa9586-69c2-4582-91b4-4de53e674756','到九鎖陸永仲出迎次韵二絕  其一','陳律','宋','宋诗','song-poetry','','[]','失身名利易沉浮，晚悟真筌盍退休。',32,'全唐诗/poet.song.64000.json','["失身名利易沉浮，晚悟真筌盍退休。", "咫尺洞天無間阻，百巖芝蕨爲吾留。"]'),
('d81f1a1c-41f6-4c81-b12a-b9b96d8aa246','到九鎖陸永仲出迎次韵二絕  其二','陳律','宋','宋诗','song-poetry','','[]','老木陰陰擁澗深，九山鎖鎖問知音。',32,'全唐诗/poet.song.64000.json','["老木陰陰擁澗深，九山鎖鎖問知音。", "白雲仙侶藏雲竇，先與好風吹醉吟。"]'),
('d881757b-9be5-4b1d-be71-c3f9980c58ee','題西門亭','陳律','宋','宋诗','song-poetry','','[]','吾家四正峰前住，射策君門亦快哉。',64,'全唐诗/poet.song.64000.json','["吾家四正峰前住，射策君門亦快哉。", "三島路從天外去，一枝香折月中來。", "鯉魚晴躍桃花浪，鸚鵡春傾竹葉杯。", "預宴瓊林非所望，偶先英俊步金臺。"]'),
('771392f9-f7a7-4fad-8682-a64b1cf94787','春日湖上書事','桑正國','宋','宋诗','song-poetry','','[]','巵傾好酒逢時盛，早遇春融媚景天。',64,'全唐诗/poet.song.64000.json','["巵傾好酒逢時盛，早遇春融媚景天。", "龜暖戲挨初綠草，燕飛輕拂乍晴烟。", "遲遲晝影花籠檻，郁郁香風蝶舞筵。", "眉似柳開眸似水，怡情自愛賞湖邊。"]'),
('c15fe2f3-8b73-4021-b160-19a99a79c2a4','會課乾明寺','桑正國','宋','宋诗','song-poetry','','[]','悠悠意得自疏通，寂地因居樂性空。',64,'全唐诗/poet.song.64000.json','["悠悠意得自疏通，寂地因居樂性空。", "幽思曉風清迫枕，靜聽寒雨細霑桐。", "修莖竹韵澄簫玉，綠影松垂亂鬢蓬。", "儔侶好邀同此適，搜吟得到幾匆匆。"]'),
