('7649ad2f-c06e-4582-9ee6-c61248899b30','句  其一','阮閱','宋','宋诗','song-poetry','','[]','無水不如三峽險，有山皆似七閩深。',16,'全唐诗/poet.song.64000.json','["無水不如三峽險，有山皆似七閩深。"]'),
('6fde7fe3-24d6-4cc5-bec7-b736693e8d5d','句  其二','阮閱','宋','宋诗','song-poetry','','[]','萬壑深連郴水出，千山高擁石門開。',16,'全唐诗/poet.song.64000.json','["萬壑深連郴水出，千山高擁石門開。"]'),
('4a9949e7-e308-4c65-903a-1717b5dfd89d','題馬上元所藏趙墨隠畫淵明四詩','吳可','宋','宋诗','song-poetry','','[]','我不識趙子，見此便得之。',144,'全唐诗/poet.song.64000.json','["我不識趙子，見此便得之。", "談笑出丘壑，粲然備四時。", "似聞月旦評，氣壓淵明詩。", "馬卿宰白下，慣作烟雲嬉。", "歸來九衢塵，舊好不少移。", "慇懃著懷袖，亦足慰夢思。", "我本家北阜，一官老京師。", "頗懷月下松，披圖覓幽姿。", "正恐林間鶴，怨我歸無期。", "那知此心在，衡宇終棲遲。", "誰憐阿堵中，幾有一斛泥。", "願分溪上山，供我笏拄頤。"]'),
('9f67bcdd-ff88-42ca-9a73-5ae1a4ae379d','吳秀才出示孫尚書詩求鄙作','吳可','宋','宋诗','song-poetry','','[]','往時家分寧，風俗喜追隨。',288,'全唐诗/poet.song.64000.json','["往時家分寧，風俗喜追隨。", "挽留杯酒間，往往醉如泥。", "比年舍臨汝，閉關無相知。", "牢落三週星，淹泊一水湄。", "人事即漸熟，鄰曲不復疑。", "聞有長者客，清談頗忘疲。", "宗盟晚相遇，佳此野鶴姿。", "過我忽長鳴，傾倒胸中奇。", "借問所從來，半世游京師。", "羣賢共文字，聲名冠當時。", "自得固有餘，足能攀桂枝。", "上以榮北堂，下以光衰遲。", "故山未暇往，舊游不足思。", "牆東或可隠，便擬營茅茨。", "奇懷傲南窗，幽花擷東籬。", "是亦差可樂，去此將何爲。", "恨未識胥鄧，論交尚差池。", "不妨氣類求，相與慰渴饑。", "同姓紛在眼，邈然棄如遺。", "此道已澆薄，君乃敦篤之。", "何當美盛德，老矣徒嗟咨。", "黄嬭厄兵火，荒唐廢文辭。", "毛子素偃蹇，豈復能發揮。", "誰爲國士重，自有尚書詩。"]'),
('a340e706-d4f3-4bc1-a1e7-8a5cc3930a16','題質龜軒','吳可','宋','宋诗','song-poetry','','[]','清江料事錯，來作刳腸翁。',72,'全唐诗/poet.song.64000.json','["清江料事錯，來作刳腸翁。", "不知幾許靈，墮此朽骨中。", "時出縱橫文，隨意侮兒童。", "誰識軒中人，本自無吉凶。", "平生不驚俗，要與衆客同。", "人言可爲鑒，試卜來年豐。"]'),
('24238623-4a0f-49e2-90a0-7182a3048e1d','巖齋','吳可','宋','宋诗','song-poetry','','[]','誰知望雲眼，犯此沒馬塵。',108,'全唐诗/poet.song.64000.json','["誰知望雲眼，犯此沒馬塵。", "故山招不歸，定爲猿鶴嗔。", "煌煌帝王州，喜有東山人。", "頻來雲霧齋，閱公碧璘珣。", "要償風月債，痛吟巖壑春。", "賢哉萬卷藏，膏馥餘八珍。", "空腸借一飽，已覺笑語新。", "肯學解頤公，鑿壁惱四鄰。", "大勝不求直，樂我平生真。"]'),
('642e40be-1b0e-44cc-8e5b-7e2a8295b7c6','筠寮','吳可','宋','宋诗','song-poetry','','[]','解衣一寮上，物色太窘束。',120,'全唐诗/poet.song.64000.json','["解衣一寮上，物色太窘束。", "栢禪費酬對，松官縛爵祿。", "此君真有道，虛心自巖谷。", "每以閱世人，得之定超俗。", "夜夜幽露寒，驚我庭下綠。", "獨出萬物表，清蟾映疏玉。", "嘉此烟霧姿，本無霜雪辱。", "朔風舞郊野，秀氣壓羣木。", "舊根走苔徑，新梢出雲屋。", "要令千畝廣，會待春雨足。"]'),
('a339a108-c733-4dbe-b421-40bd817234ee','贈連楚狂','吳可','宋','宋诗','song-poetry','','[]','誰有畫魚癖，詩社尋楚狂。',48,'全唐诗/poet.song.64000.json','["誰有畫魚癖，詩社尋楚狂。", "真成戲新荷，徑欲穿垂楊。", "餘生墮轍中，恍然得濠梁。", "寓興亦差樂，江湖庶相忘。"]'),
('011e6b03-55b5-4621-8ebd-9ec31184074e','舟中即事','吳可','宋','宋诗','song-poetry','','[]','四顧彭蠡湖，獨知廬阜尊。',288,'全唐诗/poet.song.64000.json','["四顧彭蠡湖，獨知廬阜尊。", "疊嶂遍圍繞，拱立猶兒孫。", "扶筇望瀑布，玉虹走祇園。", "回步尋虛亭，餘流潄瑶琨。", "三峽誇幽險，下有萬雷喧。", "龍淵神物家，孰敢窺清渾。", "歸來有餘思，妙音傳夢魂。", "易舟大孤傍，山川出籠樊。", "生平數佳士，歡然笑語溫。", "殊鄉愛遠客，一見如弟昆。", "直有卜鄰意，便擬營柴門。", "惜別屢往還，遺酒盈瓶盆。", "回首幽居雲，忽作聚墨昏。", "岡巒互起伏，時爲烟霧吞。", "遥知急雨來，坐看風水奔。", "浮家若漂泊，且繫古柳根。", "晚來喜新霽，遥岑淡餘痕。", "岸花自娬媚，始怪秋色繁。", "近沙羣鷺驚，炯如積雪翻。", "林間問茅屋，欲與漁父言。", "想像翠靄中，疑有桃花源。", "津子請息肩，買醉溪上村。", "我亦睡篷底，輾轉吟東屯。", "痛彼日月遠，念此骨肉存。"]'),
('1654b4b8-5171-4db1-8288-f4c6b4f77410','送李四清','吳可','宋','宋诗','song-poetry','','[]','連侯愛畫魚，李侯愛畫山。',228,'全唐诗/poet.song.64000.json','["連侯愛畫魚，李侯愛畫山。", "詩情動幽懷，摹寫不少閒。", "騷雅移丹青，妙寄雲水間。", "翻然欲登涉，試尋芷與蘭。", "我不一音解，早年便挂冠。", "養拙頹簷下，任真亦足歡。", "敵騎踐江浙，少長奔荆蠻。", "却行虎狼區，益知行路難。", "亂來戰未息，老去食轉艱。", "前年治南畝，頗喜人牛安。", "力耕日以廣，心事日以寬。", "行當遂野性，策杖尋江干。", "雲深幾茅屋，柳映一柴關。", "扁舟鳴撥剌，危亭秀孱顔。", "安得兩玉人，鄰曲相追攀。", "真賞會心處，應當謝毫端。", "長哦洗兵馬，隨意羅杯盤。", "伯雅要傾倒，莫厭數往還。", "願如三徑松，餘生同歲寒。"]'),
('002a97f0-33ff-4065-bfc1-e7cfd18ef62d','送王觀','吳可','宋','宋诗','song-poetry','','[]','文正活國手，頗恨見不及。',96,'全唐诗/poet.song.64000.json','["文正活國手，頗恨見不及。", "宦遊識其孫，想像高冠岌。", "豈但爲交承，自是賢友執。", "尤思談性命，微到鬼神泣。", "吾曹飲滄海，百川羹一吸。", "失却大官味，卷舌舐泥汁。", "因依既云久，臨別百憂集。", "去去好護持，雨荷終不濕。"]'),
('8adbc798-c68f-4843-91e1-f639ac692093','避地桂楊山門招友人晚飲','吳可','宋','宋诗','song-poetry','','[]','荒城住行李，故人亦淹留。',72,'全唐诗/poet.song.64000.json','["荒城住行李，故人亦淹留。", "稍遷墟丘間，愛此石泉幽。", "長夏晴復雨，風氣如清秋。", "開樽茅茨下，焉能消百憂。", "客懷滯荆楚，念之成白頭。", "今宵理歸夢，一棹隨風流。"]'),
('8740303c-e880-4283-a604-2db4c5300da6','過許醉吟痛飲月下戲書','吳可','宋','宋诗','song-poetry','','[]','塵埃沒我馬，掉鞅吟公詩。',144,'全唐诗/poet.song.64000.json','["塵埃沒我馬，掉鞅吟公詩。", "詩中有江山，不覺在京師。", "下馬自叩門，來尋元紫芝。", "欲掃名利心，笑挹丘壑姿。", "東簷坐無氈，北風吹酒巵。", "蟹螯互勸酬，墜車兩不辭。", "聽公擊節吟，悲壯亦自奇。", "看公醉山倒，了不遣客歸。", "客歸意亦好，月色到處隨。", "詩成月下寫，淡墨任傾欹。", "平生不知韵，興來聊續之。", "詞達語更正，識者未必嗤。"]'),
('b74fc7c1-bf22-45a1-af5f-f3cb67eec7b8','探梅','吳可','宋','宋诗','song-poetry','','[]','探春逼殘歲，幽香度寒原。',84,'全唐诗/poet.song.64000.json','["探春逼殘歲，幽香度寒原。", "欲看枝橫水，會待月掛村。", "誰憐槁木中，妙有春風根。", "孤芳自一丘，不受烟霧昏。", "飽霜分疏瘦，下笑浪蕊繁。", "喜無蜂蝶知，那與桃李言。", "要當碧雲暮，殷勤賦離魂。"]'),
('fae88b05-b656-4b3d-b392-9e7e74f09761','泰定齋詩','吳可','宋','宋诗','song-poetry','','[]','寂然數椽下，獨耀一宇內。',48,'全唐诗/poet.song.64000.json','["寂然數椽下，獨耀一宇內。", "脫落山水因，妙出仁智外。", "君看鑑中事，作止本無礙。", "年來識坐忘，唯餘照心在。"]'),
('cb449c78-3b6c-4327-b5fa-c8973fee9bf1','安靜齋詩','吳可','宋','宋诗','song-poetry','','[]','歸來便閒適，松檜自儔侶。',84,'全唐诗/poet.song.64000.json','["歸來便閒適，松檜自儔侶。", "扶疏媚虛堂，初無一禽語。", "長哦柴桑詩，妙香吐雲縷。", "平生壑源好，蓮甌發新乳。", "痛洗朝來忙，得意乃如許。", "輪蹄不到門，幽壁掛犀麈。", "笑拂維摩床，西窗睡秋雨。"]'),
('0d9a10df-7bac-4a5c-b604-e149e5a66b20','失題','吳可','宋','宋诗','song-poetry','','[]','熱官惱狂士，冰山倚嚴冬。',144,'全唐诗/poet.song.64000.json','["熱官惱狂士，冰山倚嚴冬。", "此計定不長，會作須臾空。", "先生踏金門，大節孝與忠。", "能事不掛口，處之如無功。", "高隠百僚上，妙有淵明風。", "東垣著巖岫，南榮著檜松。", "疏窗澹山影，雲霧穿玲瓏。", "澄流粲錦石，一練搖青紅。", "笑携玉色醪，酌彼千石鍾。", "良時飲文字，此興與誰同。", "爲君指佳處，不落捷徑中。", "從來論丘壑，風味過庾公。"]'),
('f1e4fb7c-f9de-4cf4-9c72-51439d6ec44c','祕古堂詩','吳可','宋','宋诗','song-poetry','','[]','羣兒只解祕金玉，百歲作癡空潤屋。',160,'全唐诗/poet.song.64000.json','["羣兒只解祕金玉，百歲作癡空潤屋。", "君家勝味渠不知，掉頭歸來北窗讀。", "插架整整三萬籤，誰何有書真不然。", "是中文字到蝌蚪，補亡應得由庚篇。", "異錦千囊更妙好，中有玉奩藏小草。", "不煩脫帽苦揮毫，漫說驚蛇雜飛鳥。", "摩挲鼎彝自笑語，碧暈堆花久瘞土。", "懸知百好墮兒戲，此物一出吞萬古。", "客來錯惡初不解，把玩慇懃定爲怪。", "我知此老極不淺，規模正欲超三代。"]'),
('f3abe40b-ae41-46ef-b55d-9e0e52c0d67b','題翹翠軒詩','吳可','宋','宋诗','song-poetry','','[]','老木拔雲蒼翠起，新篁挾雨枝葉美。',64,'全唐诗/poet.song.64000.json','["老木拔雲蒼翠起，新篁挾雨枝葉美。", "下有數峰莓苔寒，先生俯仰一笑喜。", "乘興把書坐秋風，超然吐論飛長虹。", "客星忽去璧月上，陶陶醉卧玻璃中。"]'),
('385e1cb5-e61e-4961-9c64-8c2d486ff140','李氏娛書齋','吳可','宋','宋诗','song-poetry','','[]','李侯平生無他好，眼中黄卷常自娛。',96,'全唐诗/poet.song.64000.json','["李侯平生無他好，眼中黄卷常自娛。", "明窗危坐對賢聖，鼓吹不可一日無。", "欣然會意便忘食，心醉何止勤三餘。", "幾年携家避盜寇，尚得戲綵乘潘輿。", "攝官江外有何好，闊步日邊真良圖。", "試求假直亦不惡，他年不減行秘書。"]'),
('ca637d5d-b584-4672-8463-5037ed27ef9c','故人來自舂陵出示初寮翰墨感時懷舊輒爲長句','吳可','宋','宋诗','song-poetry','','[]','先生視草白玉堂，文章一出自名世。',243,'全唐诗/poet.song.64000.json','["先生視草白玉堂，文章一出自名世。", "分光蓮燭真爲榮，拭吐龍巾何足擬。", "艮岑夜召趨神霄，憐我婆娑百僚底。", "紫禁歡傳拜左轄，漫刺走賀城南第。", "羸僮瘦馬堂階下，歎我粗官殊少味。", "驚聞一麾出燕山，旆旌遽下雲漢間。", "睿思官曹方顧寵，笑我翻然歸挂冠。", "金兵南來郡國破，二聖北狩天步艱。", "黎元鼎沸死鄉土，士夫雲擾奔荆蠻。", "一人嘗膽固不易，諸將束胸今何難。", "朝來喜見舂陵客，問訊先生多翰墨。", "懷古傷時初不忘，回首長安淚橫臆。", "君不見虎踞龍盤氣象雄，王者都此成大功。", "遥知廟堂有高論，似聞天蹕移江東。", "幾年中興要賢俊，頗懷仲父安東晉。"]'),
('b1ac4fc1-808a-465d-b232-8b2063c7caf7','醉鄉詩','吳可','宋','宋诗','song-poetry','','[]','飲中境界妙四海，楚屈未知風俗淳。',112,'全唐诗/poet.song.64000.json','["飲中境界妙四海，楚屈未知風俗淳。", "陶然席地已忘載，夜縛甕下初不嗔。", "逃禪駡坐本真率，時一中之眇萬物。", "縱兵端欲捲愁城，樂賢未始忘歡伯。", "佳處風光殊可人，好德懸知必有鄰。", "黄花解勸張季鷹，俗婦那識劉伯倫。", "世間萬物敗人意，不如常作箇中計。"]'),
('bd51712f-4c47-4730-9c35-7e866a75773c','山居見梅','吳可','宋','宋诗','song-poetry','','[]','孤吟梅花望神京，澆愁恨無雙玉瓶。',96,'全唐诗/poet.song.64000.json','["孤吟梅花望神京，澆愁恨無雙玉瓶。", "上林顧影一坐傾，高樓忍作昭華聲。", "避兵南州老雲壑，風味依然殊不惡。", "歲暮渾無驛使來，一笑天涯共流落。", "行尋嶺頭路幾許，欲買幽園歎貧窶。", "清客那知日邊事，獨坐茅茨對烟雨。"]'),
('6d372cbe-e723-40a9-9968-4266c239fdec','夜聞警','吳可','宋','宋诗','song-poetry','','[]','幾年官軍破郡邑，遠客孤村誰脫急。',96,'全唐诗/poet.song.64000.json','["幾年官軍破郡邑，遠客孤村誰脫急。", "卧聽鄰雞三鼓鳴，流言敵騎一宵及。", "抱衾携幼强趨走，複嶺重山且深入。", "爲聞北人畏和暖，安得如今便驚蟄。", "長秋南奔苦嵐瘴，翠華連巡犯卑濕。", "顧我飄零豈足念，注目寒江忘久立。"]'),
('e6d12f31-0ccd-471d-8dd1-74e44a35c36f','即事','吳可','宋','宋诗','song-poetry','','[]','勁敵謀應大，春來勢轉雄。',48,'全唐诗/poet.song.64000.json','["勁敵謀應大，春來勢轉雄。", "烽烟驚北闕，鼙鼓戰東風。", "雪舞愁雲外，花飛淚眼中。", "翠華行樂處，戈甲照寒空。"]'),
('140b8826-f9a4-4932-9412-f2424a6e0bef','寄李道夫','吳可','宋','宋诗','song-poetry','','[]','亂後時通問，飄流尚此身。',48,'全唐诗/poet.song.64000.json','["亂後時通問，飄流尚此身。", "干戈傷白髮，桃李自青春。", "故國田疇遠，殊方盜賊頻。", "知君懷老伴，詩酒慰情親。"]'),
('aee8c84f-bd02-456f-baf1-697a6ca6c7f9','遊清凉寺','吳可','宋','宋诗','song-poetry','','[]','延步石城塢，迢迢去興長。',48,'全唐诗/poet.song.64000.json','["延步石城塢，迢迢去興長。", "野田耕晚雪，寒樹倚斜陽。", "載酒追狂客，論才得漫郎。", "無因遂高蹈，時復借山房。"]'),
('d9943adb-50c3-48b4-85b3-b18e3995e1ac','養竹','吳可','宋','宋诗','song-poetry','','[]','渭川分一種，親植隠巖東。',48,'全唐诗/poet.song.64000.json','["渭川分一種，親植隠巖東。", "有實終來鳳，無心自化龍。", "疏陰留夜月，清韵起秋風。", "待養鼇竿就，滄溟作釣翁。"]'),
('fc2efc59-43e7-432f-b4ec-325f06706c6e','登臨川城','吳可','宋','宋诗','song-poetry','','[]','時危傷去國，歲晚强登城。',48,'全唐诗/poet.song.64000.json','["時危傷去國，歲晚强登城。", "過雁書難問，窮途淚欲傾。", "江湖歸客夢，梅柳故園情。", "倚杖空凝竚，行藏竟不成。"]'),
('8b32138f-be8e-4d85-9b6d-9ac758f3544e','懷歸','吳可','宋','宋诗','song-poetry','','[]','久客江湖遠，頻年道路艱。',48,'全唐诗/poet.song.64000.json','["久客江湖遠，頻年道路艱。", "干戈侵海內，猿鶴老山間。", "地僻林泉古，雲深日月閒。", "餘生猶轉徙，清夢遶柴關。"]'),
('0c91ae67-b4b6-41b5-9fe2-dd64d3b16a3b','次韵曾中父登臨川郡樓書事','吳可','宋','宋诗','song-poetry','','[]','戈甲何爲盛，田園已就荒。',240,'全唐诗/poet.song.64000.json','["戈甲何爲盛，田園已就荒。", "僅能移北阜，未暇隠東牆。", "寂寞交親遠，漂零道路長。", "歸心隨斷雁，離思感垂楊。", "避寇湘江外，依劉汝水傍。", "閭閻嗟偪仄，登眺喜寬凉。", "遠岫誰能屐，寒溪竟欲航。", "冰盤悲玉井，風簟愛筠床。", "地盡妖氛氣，春餘草木光。", "寶薰烟霧細，仙茗笑談香。", "接武青雲路，論文綠野堂。", "虎皮空自悅，猿臂定誰攘。", "取友真多益，求田苦未臧。", "撐腸披錦繡，潄石飽膏肓。", "隠逸追元亮，風騷近子昂。", "栖鴉啼古堞，幽檻倚斜陽。", "離亂知誰健，行藏只自傷。", "舊巢看燕燕，今雨任浪浪。", "道勝依鶖子，才高歎夜郎。", "五峰興不淺，星漢擬文章。"]'),
('f4b7ea72-3f93-4f7a-b4a6-fbb29f280d8a','友人惠笋豉','吳可','宋','宋诗','song-poetry','','[]','野稅那知笋豉香，伊蒲淡泊喜初嘗。',64,'全唐诗/poet.song.64000.json','["野稅那知笋豉香，伊蒲淡泊喜初嘗。", "自憐老去能忘肉，誰謂朝來已徹薑。", "膾玉有名汙浄供，蒪絲無味誑枯腸。", "此君苗裔風流在，三韭何須學庾郎。"]'),
('85d61760-04bd-4aff-a6ca-bc033455244a','謝友人約居橫林','吳可','宋','宋诗','song-poetry','','[]','遠煩招隠費長吟，緩急方知故舊心。',64,'全唐诗/poet.song.64000.json','["遠煩招隠費長吟，緩急方知故舊心。", "懷土若爲家直瀆，避喧真欲客橫林。", "人材何敢追連璧，氣類聊能擬斷金。", "卜築要須孤絕處，落花流水恐相尋。"]'),
('51b53ffe-6914-4102-b273-902edee0de57','春雪後寄范長民','吳可','宋','宋诗','song-poetry','','[]','回首長安淚滿衣，東風如舊鬢成絲。',64,'全唐诗/poet.song.64000.json','["回首長安淚滿衣，東風如舊鬢成絲。", "扶持衰病元無術，感歎飄零漫有詩。", "那信夢魂隨北雁，忍看霜雪滿南枝。", "幽居只合從公等，自笑年來見事遲。"]'),
('bd84e10b-d183-486a-a1c8-2244741b465b','呈秦楚材','吳可','宋','宋诗','song-poetry','','[]','倒指烟塵歲月深，引杯看劍漫悲吟。',64,'全唐诗/poet.song.64000.json','["倒指烟塵歲月深，引杯看劍漫悲吟。", "平生自歎雕蟲手，末路空慚舐犢心。", "賸喜星郎上雲漢，苦憐鶴髮避山林。", "君家伯仲真廊廟，痛爲中興惜寸陰。"]'),
('dc3c0aca-7b55-49bc-a41a-8ff3ef84c3d6','和人聞笛','吳可','宋','宋诗','song-poetry','','[]','鄰笛聲哀不自安，轉移宮調幾多般。',64,'全唐诗/poet.song.64000.json','["鄰笛聲哀不自安，轉移宮調幾多般。", "夢回飛蝶三千里，月照高樓十二欄。", "別鶴唳長秋露重，老龍吟苦夜潭寒。", "清愁一晌知何限，待啟菱花向曉看。"]'),
('dde5d2f4-9417-404d-b436-0aff9aed8fa2','簇翠亭','吳可','宋','宋诗','song-poetry','','[]','此老作亭蒼翠間，定知胸次有東山。',64,'全唐诗/poet.song.64000.json','["此老作亭蒼翠間，定知胸次有東山。", "朝陽破霧烘林影，醉袖扶花繞髻鬟。", "露警丹哥傳妙響，雲眠碧友自清閒。", "欲專一壑從來事，回首塵埃亦厚顔。"]'),
('e89c472a-6ac8-4be0-8b46-fe229869e003','廬山香林訪趙德麟','吳可','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','艤舟星渚得幽尋，問訊先生隠翠岑。',64,'全唐诗/poet.song.64000.json','["艤舟星渚得幽尋，問訊先生隠翠岑。", "欲禮光明依浄社，便隨氣類老香林。", "貂金且換陶潜醉，囊錦聊追白傅吟。", "坡客飄零有公在，與誰揮淚說知音。"]'),
('6a10d597-64b2-49ab-8166-79e55ff5f274','探梅','吳可','宋','宋诗','song-poetry','','[]','柳未搖金草未芽，尋幽逸興屬詩家。',64,'全唐诗/poet.song.64000.json','["柳未搖金草未芽，尋幽逸興屬詩家。", "不辭山下五六里，爲愛枝頭三四花。", "噴月清香猶吝惜，印溪疏影恣橫斜。", "固應羞澀怯寒峭，結子成陰已有涯。"]'),
('96b642e3-6604-4f4c-bb19-a2b84b08ee9f','送李秀才爲道士','吳可','宋','宋诗','song-poetry','','[]','聖澤朝來浄世緣，不教仙骨墮儒門。',64,'全唐诗/poet.song.64000.json','["聖澤朝來浄世緣，不教仙骨墮儒門。", "金龜換酒當年客，白鹿昇天後世孫。", "泉石招君友猿鶴，利名憐我醉朝昏。", "麻衣笑著掉頭去，何處抱琴追綺園。"]'),
('c4aa3f31-7a21-400c-a40b-ef670f213042','豫章道中','吳可','宋','宋诗','song-poetry','','[]','僕已疲勞馬已頹，忍能日日犯風埃。',64,'全唐诗/poet.song.64000.json','["僕已疲勞馬已頹，忍能日日犯風埃。", "前山斷處後山出，舊雨晴時新雨來。", "梅子有情沿路熟，麥花無數及時開。", "一春客裏消磨盡，舉眼豫章安在哉。"]'),
('a9be8422-dc62-416a-b264-31ca1f42bd00','九日','吳可','宋','宋诗','song-poetry','','[]','佳節初回苦未凉，疏林高下半青黄。',64,'全唐诗/poet.song.64000.json','["佳節初回苦未凉，疏林高下半青黄。", "佩茱頗喜人猶健，採菊還憐蝶尚狂。", "不惜登山聊舉句，欲因戲馬漫擎蒼。", "笑欹醉帽歸來晚，稍覺幽庭月似霜。"]'),
('8d62e359-e3d0-4d17-9edd-aac3a74ea545','次韵黄簿九日','吳可','宋','宋诗','song-poetry','','[]','客裏登高意若何，笑扶藜杖興還多。',64,'全唐诗/poet.song.64000.json','["客裏登高意若何，笑扶藜杖興還多。", "葉金委地誰能布，山劍橫天不受磨。", "隨遇可無揮翰手，感時空有斷腸歌。", "尚憐把菊烟塵外，自鏡衰容半欲酡。"]'),
('65572705-9c19-4212-82f8-fcf7df930809','寄米元暉','吳可','宋','宋诗','song-poetry','','[]','田廬寂寂近塘坳，仕路紛紛久絕交。',64,'全唐诗/poet.song.64000.json','["田廬寂寂近塘坳，仕路紛紛久絕交。", "多病未能從五柳，避喧端欲老三茅。", "白雲那忍閒歸岫，紫燕空慚漫累巢。", "聞道金壇有仙隠，夢回清月墮林梢。"]'),
('dd03b976-7f9e-4b8c-9c29-29cf3e82b6d9','野步','吳可','宋','宋诗','song-poetry','','[]','密竹藏啼鳥，荒村起白烟。',24,'全唐诗/poet.song.64000.json','["密竹藏啼鳥，荒村起白烟。", "人行秋色裏，家在夕陽邊。"]'),
('228ccfb7-a888-4c11-aeec-fb71f26edccd','夜坐','吳可','宋','宋诗','song-poetry','','[]','索索風搖幕，亭亭月過牆。',24,'全唐诗/poet.song.64000.json','["索索風搖幕，亭亭月過牆。", "晴雷推粉磨，夜雨壓槽床。"]'),
('d8dc2c22-1518-4e22-934d-28ef85746498','春霽','吳可','宋','宋诗','song-poetry','','[]','南國春光一半歸，杏花零落雨霏微。',32,'全唐诗/poet.song.64000.json','["南國春光一半歸，杏花零落雨霏微。", "新晴院宇寒猶在，曉絮欺風不肯飛。"]'),
('f1d738fe-272d-4131-8200-61bef4e2aec5','春晚  其一','吳可','宋','宋诗','song-poetry','','[]','門外綠楊啼乳鴉，弄黄梅子壓枝斜。',32,'全唐诗/poet.song.64000.json','["門外綠楊啼乳鴉，弄黄梅子壓枝斜。", "殘書讀罷無功課，遶徑來尋未落花。"]'),
('fb7c8952-a9fb-4b93-9f3a-d573951ebb71','春晚  其二','吳可','宋','宋诗','song-poetry','','[]','蜂兒擷蕊趁花心，燕子銜泥掠柳陰。',32,'全唐诗/poet.song.64000.json','["蜂兒擷蕊趁花心，燕子銜泥掠柳陰。", "處處浸秧黄乍吐，護田肥水半篙深。"]'),
('a470adb8-7458-4dcf-9e14-cb20f3f92c49','踏青','吳可','宋','宋诗','song-poetry','','[]','幽居懶慢養餘生，强爲春風處處行。',32,'全唐诗/poet.song.64000.json','["幽居懶慢養餘生，强爲春風處處行。", "藉草弄花終少味，尋山愛竹尚多情。"]'),
('3a34f3c6-5332-45a3-9145-2002897d3e64','過巢邑','吳可','宋','宋诗','song-poetry','','[]','竹杖芒鞋蹋短蓬，沒篙春水飽帆風。',32,'全唐诗/poet.song.64000.json','["竹杖芒鞋蹋短蓬，沒篙春水飽帆風。", "兩關三寺山無數，盡在濛濛烟雨中。"]'),
('894bc28b-6fa8-45c5-8aba-06a9dfcdb185','村居','吳可','宋','宋诗','song-poetry','','[]','鑿井耕田僅萬家，農夫農婦畢絲麻。',32,'全唐诗/poet.song.64000.json','["鑿井耕田僅萬家，農夫農婦畢絲麻。", "夜來得雨陂塘足，村北村南罷踏車。"]'),
('5c873d73-a35d-49cd-9c16-3ee7237b0d00','荒陂','吳可','宋','宋诗','song-poetry','','[]','荒陂終日水車鳴，村北村南共一聲。',32,'全唐诗/poet.song.64000.json','["荒陂終日水車鳴，村北村南共一聲。", "掠面輕風吹小雨，鄙夫詩向此時成。"]'),
('e886fb23-3dab-494c-8877-ae9465c444bc','松','吳可','宋','宋诗','song-poetry','','[]','秋色何妨陪露菊，歲寒真欲友霜筠。',32,'全唐诗/poet.song.64000.json','["秋色何妨陪露菊，歲寒真欲友霜筠。", "只應澗底桃花笑，苦愛微官不避秦。"]'),
('ab93a832-c5cd-4c41-9380-290127bff548','晚步','吳可','宋','宋诗','song-poetry','','[]','野樹疏疏透夕陽，歸鴉零亂不成行。',32,'全唐诗/poet.song.64000.json','["野樹疏疏透夕陽，歸鴉零亂不成行。", "春風可是閒來往，時送江梅一陣香。"]'),
('d1acdf88-d828-4eb4-b246-668ca724d035','書却暑圖後','吳可','宋','宋诗','song-poetry','','[]','冰柱雪車誰復作，礬頭凌面未能摹。',32,'全唐诗/poet.song.64000.json','["冰柱雪車誰復作，礬頭凌面未能摹。", "北窗揮汗渾無奈，漫借君家却暑圖。"]'),
('f935a40e-833f-4c17-9f9f-093d893ed2b1','偶贈陳居士','吳可','宋','宋诗','song-poetry','','[]','楚酒困人三日醉，園花著雨百般紅。',32,'全唐诗/poet.song.64000.json','["楚酒困人三日醉，園花著雨百般紅。", "憑誰畫出陳居士，亭角尋詩滿袖風。"]'),
('f050335b-545f-4dd8-af3c-41c0546e4525','村巷詩','吳可','宋','宋诗','song-poetry','','[]','村巷深深桑柘烟，園林寂靜落花天。',32,'全唐诗/poet.song.64000.json','["村巷深深桑柘烟，園林寂靜落花天。", "柴門有客忙相揖，搖手低聲蠶大眠。"]'),
('7fd68ecb-6ca2-4a6e-a6b1-bc5b450f3941','田家女','吳可','宋','宋诗','song-poetry','','[]','兩兩垂髫窈窕娘，含羞無語蒔青秧。',32,'全唐诗/poet.song.64000.json','["兩兩垂髫窈窕娘，含羞無語蒔青秧。", "翻思貴室千金女，笑倚紅樓抹曉粧。"]'),
('dfff3e07-a80a-4424-8246-6075e33f9d1c','初凉','吳可','宋','宋诗','song-poetry','','[]','初凉宜夜透衣羅，時見流星度絳河。',32,'全唐诗/poet.song.64000.json','["初凉宜夜透衣羅，時見流星度絳河。", "漸覺露漙金掌重，梧桐影外月明多。"]'),
('51a57965-ee6a-4d2a-8381-8cc86c298a58','小醉','吳可','宋','宋诗','song-poetry','','[]','小醉初醒過竹村，數家殘雪擁籬根。',32,'全唐诗/poet.song.64000.json','["小醉初醒過竹村，數家殘雪擁籬根。", "風前有恨梅千點，溪上無人月一痕。"]'),
('03ea2dec-00dc-4fdd-a40c-1eb3518bddad','病酒','吳可','宋','宋诗','song-poetry','','[]','無聊病酒對殘春，簾幕重重更掩門。',32,'全唐诗/poet.song.64000.json','["無聊病酒對殘春，簾幕重重更掩門。", "惡雨斜風花落盡，小樓人下欲黄昏。"]'),
('49f3aeda-b4f3-4c04-8a9d-87f23633e96f','戲作冷語','吳可','宋','宋诗','song-poetry','','[]','□□□□□□□，□□□□□□□。',48,'全唐诗/poet.song.64000.json','["□□□□□□□，□□□□□□□。", "□□□□思如冬，露下紫薇花影中。", "長哦白雪明光宮，衆泉涌此萬卷胸。"]'),
('acca66d0-8ae6-4026-907e-fb6ee1db92f2','次韵劉元舉子規','吳可','宋','宋诗','song-poetry','','[]','蜀魄悲鳴楚國春，試憑清些與招魂。',64,'全唐诗/poet.song.64000.json','["蜀魄悲鳴楚國春，試憑清些與招魂。", "柔腸欲斷雲橫嶺，幽夢初回月挂村。", "客舍花光隨野水，故園柳色負柴門。", "飽聞錦里無窮樂，早晚歸來訪子孫。"]'),
('1449fcfb-115a-4d62-a9f4-ac3b71ee5062','贈戴彥衡','吳可','宋','宋诗','song-poetry','','[]','病來謾喜折釵股，老去尚懷雙脊龍。',32,'全唐诗/poet.song.64000.json','["病來謾喜折釵股，老去尚懷雙脊龍。", "他日扁舟會乘興，摩挲圭璧小從容。"]'),
('d1b86fa8-46fc-4f04-b6de-87df87694381','學詩  其一','吳可','宋','宋诗','song-poetry','','[]','學詩渾似學參禪，竹榻蒲團不計年。',32,'全唐诗/poet.song.64000.json','["學詩渾似學參禪，竹榻蒲團不計年。", "直待自家都了得，等閒拈出便超然。"]'),
('56e4ff56-82e3-4447-aff7-d235ed99b80a','學詩  其二','吳可','宋','宋诗','song-poetry','','[]','學詩渾似學參禪，頭上安頭不足傳。',32,'全唐诗/poet.song.64000.json','["學詩渾似學參禪，頭上安頭不足傳。", "跳出少陵窠臼外，丈夫志氣本衝天。"]'),
('6115ba86-a7a2-4662-8624-69a3ccc524a4','學詩  其三','吳可','宋','宋诗','song-poetry','','[]','學詩渾似學參禪，自古圓成有幾聯。',32,'全唐诗/poet.song.64000.json','["學詩渾似學參禪，自古圓成有幾聯。", "春草池塘一句子，驚天動地至今傳。"]'),
('673f40fb-c88a-4906-8aa1-da3ee160e6d4','句','吳可','宋','宋诗','song-poetry','','[]','壽寧閑鎖翰林春，月明空照瓊花影。',16,'全唐诗/poet.song.64000.json','["壽寧閑鎖翰林春，月明空照瓊花影。"]'),
('5165ecf1-016c-4ee5-a372-3f77fce197a8','君家誠易知曲','張耒','宋','宋诗','song-poetry','','[]','君家誠易知，易知獨難忘。',84,'全唐诗/poet.song.64000.json','["君家誠易知，易知獨難忘。", "西風牆頭吹葉黄，蟲絲當戶理秋光。", "翠屏碧簟生朝凉，床頭蟋蟀見焚香。", "鮫綃纈，雙鳳凰，上元綠鬢遮耳璫。", "來車去馬官道旁，碧雲傳情何處郎，相望玉樹啼寒螿。"]'),
('5407619a-0b66-497a-aa81-95d1fdbbbe6b','于湖曲','張耒','宋','宋诗','song-poetry','','[]','武昌雲旗蔽天赤，夜築于湖洗鋒鏑。',131,'全唐诗/poet.song.64000.json','["武昌雲旗蔽天赤，夜築于湖洗鋒鏑。", "巴滇騄駿風作蹄，去如滅沒來不嘶。", "日圍萬里纏孤壁，虜氣如霜已潜釋。", "蛇矛賤士識天顔，玉帳髯奴落妖魄。", "君不見銅駝陌上塵沙起，胡騎春來飲瀍水。", "浮江天馬是龍兒，蹙踏揚州開帝里。", "王氣高懸五百秋，弄兵老濞空白頭。", "石城戰骨卧秋草，更欲君王分上流。"]'),
('30a3e314-67d0-402a-8585-8bf149d73870','襄陽曲','張耒','宋','宋诗','song-poetry','','[]','西津折葦鳴策策，蟾蜍光入芙蓉白。',80,'全唐诗/poet.song.64000.json','["西津折葦鳴策策，蟾蜍光入芙蓉白。", "山頭不雨賈船稀，日日門前江水窄。", "將欲烜赫招行人，旋起丹樓照長陌。", "銀屏深蔽玉笙閒，自擘新橙飲北客。", "倏離暫合心未果，淚瑩雙眸爲誰墮。"]'),
('dcddb875-075a-489a-b4ed-ca500e8e576a','寄衣曲','張耒','宋','宋诗','song-poetry','','[]','秋風西來入庭樹，攀條正念征人苦。',64,'全唐诗/poet.song.64000.json','["秋風西來入庭樹，攀條正念征人苦。", "空窗自織不敢任，鳴機愁寂如鳴艣。", "練成欲裁新絲香，抱持含愁叔姑堂。", "別來不見衣覺窄，試比小郎身更長。"]'),
('20d8f30a-1d1c-4821-bbad-97ab8f1c1b39','江南曲','張耒','宋','宋诗','song-poetry','','[]','江蒲芽白江水綠，江頭花開自幽淑。',96,'全唐诗/poet.song.64000.json','["江蒲芽白江水綠，江頭花開自幽淑。", "人家晨炊欲熟時，旋去網魚惟所欲。", "往來送租只用船，未省泥沙曾污足。", "有錢買酒醉鄰畔，終日數口常在目。", "不學長安貴公卿，每念離心寄朱轂。", "朝遊巖廊暮海島，譴人未歸身自到。"]'),
('cf6d734c-2f3f-4aa1-b9d8-36cab82a411f','怨曲二首  其一','張耒','宋','宋诗','song-poetry','','[]','白首南朝女，愁聽異域歌。',48,'全唐诗/poet.song.64000.json','["白首南朝女，愁聽異域歌。", "收兵頡利國，飲馬胡盧河。", "毳布腥羶久，穹廬歲月多。", "雕窠城上宿，吹笛淚滂沱。"]'),
('263ce69d-f97f-4dd9-852c-f8b981101741','怨曲二首  其二','張耒','宋','宋诗','song-poetry','','[]','祖席駐征橈，開帆復信潮。',48,'全唐诗/poet.song.64000.json','["祖席駐征橈，開帆復信潮。", "隔筵桃葉泣，吹管杏花飄。", "船去鷗飛閣，人歸鹿上橋。", "別離惆悵淚，江鷺宿紅蕉。"]'),
('0ad51e4c-fddd-4d50-842c-5497e85aa73e','壽陽歌','張耒','宋','宋诗','song-poetry','','[]','壽陽樓前淮水碧，壽陽美女如脂白。',160,'全唐诗/poet.song.64000.json','["壽陽樓前淮水碧，壽陽美女如脂白。", "李郎青鬢照青衫，曾在花前作狂客。", "伯勞睡重花枝晚，時許蜻蜓一偷眼。", "歡娛雖少恨已多，纖手紅箋揮翠管。", "淮陽歸來春已暮，夜夜夢魂淮上去。", "欲歌舊曲只添愁，畫得雙蛾不能語。", "有客南來從壽春，衆人笑問動精神。", "自從柳別章臺後，攀折風光知幾人。", "已伴春衫辭側帽，不怕嬌啼隨意笑。", "嗟君耿耿獨相思，須信多情是年少。"]'),
('c041c069-09d5-47f5-95dc-c91e5e2c7d51','勞歌','張耒','宋','宋诗','song-poetry','','[]','暑天三月元無雨，雲頭不合惟飛土。',96,'全唐诗/poet.song.64000.json','["暑天三月元無雨，雲頭不合惟飛土。", "深堂無人午睡餘，欲動身先汗如雨。", "忽憐長街負重民，筋骸長彀十石弩。", "半衲遮背是生涯，以力受金飽兒女。", "人家牛馬繫高木，惟恐牛軀犯炎酷。", "天工作民良久艱，誰知不如牛馬福。"]'),
('84cb492c-cffe-4b33-996a-81750cc6fe6c','春雨謠','張耒','宋','宋诗','song-poetry','','[]','晚雲欲著樹，中夜一犂雨。',56,'全唐诗/poet.song.64000.json','["晚雲欲著樹，中夜一犂雨。", "老農呼子孫，力作莫辭苦。", "風吹潤土如炊香，烹雞爲黍餉南岡。", "我知聖人在明堂，元年已是豐年祥。"]'),
('34b90acc-71dc-44bc-8cad-d4c31b6ca2cf','少年行三首  其一','張耒','宋','宋诗','song-poetry','','[]','騂弓鵲角蒼雕羽，金錯旂竿畫貔虎。',64,'全唐诗/poet.song.64000.json','["騂弓鵲角蒼雕羽，金錯旂竿畫貔虎。", "長驅直踏老上庭，手拔干將斬狂虜。", "歸來解甲見天子，金印懸腰封萬戶。", "自爲大漢上將軍，高揖羣公佐明主。"]'),
('378e4880-c332-43eb-a6b5-675c21f83905','少年行三首  其二','張耒','宋','宋诗','song-poetry','','[]','人生豈合長貧賤，師事黄公曾習戰。',64,'全唐诗/poet.song.64000.json','["人生豈合長貧賤，師事黄公曾習戰。", "英雄天子伐匈奴，初拜將軍二十餘。", "黄塵晝飛羽如插，身射單于碎弓甲。", "從來書生輕武夫，坐遣揮毫寫勳業。"]'),
('e4f8eb07-88c2-40e6-be21-b281a29867e3','少年行三首  其三','張耒','宋','宋诗','song-poetry','','[]','少年賣珠登主門，主家千金惜一身。',64,'全唐诗/poet.song.64000.json','["少年賣珠登主門，主家千金惜一身。", "綠韝請罪見天子，尚得君王呼主人。", "鬭雞走馬長安道，豪傑驅來奉談笑。", "漢庭碌碌公與侯，畏禍憂誅先白頭。"]'),
('5e3ad2bb-3ef6-424a-b36d-1933494f8071','謫官黄州至南頓驛同李從聖叔姪小飲','張耒','宋','宋诗','song-poetry','','[]','共飯何草草，客來從遠道。',56,'全唐诗/poet.song.64000.json','["共飯何草草，客來從遠道。", "傾壺得殘酒，聊以開懷抱。", "年將半百兩鬢華，謫官憔悴來天涯。", "神理可馮吾道在，不應長遣路人嗟。"]'),
('22b17430-061e-4fef-9788-48edf17f3bfb','代贈','張耒','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞房飛香作春霧，仙人勸酒香中語。',128,'全唐诗/poet.song.64000.json','["洞房飛香作春霧，仙人勸酒香中語。", "明眸第二紫雲娘，鶯學歌聲柳如舞。", "蹙眉長歌澧有蘭，銀鈎請君春草篇。", "繁弦高張燭燒夜，玉壺未盡參在天。", "春泥雪消淮上路，東風浪頭驚客艣。", "惱公舊事幾夢魂，過眼相逢一風雨。", "黄流清洛上天漢，吳山洞庭藏水府。", "謾題詩句寄歸舟，江口風狂那得渡。"]'),
('751aec47-b362-4983-b888-b2d759de295c','代嘲','張耒','宋','宋诗','song-poetry','','[]','過作拋人去，非真我獨知。',24,'全唐诗/poet.song.64000.json','["過作拋人去，非真我獨知。", "如何立不定，却有獨來時。"]'),
('7613f5d0-f04b-4190-b38a-e881a9c34e9f','牧牛兒','張耒','宋','宋诗','song-poetry','','[]','牧牛兒，遠陂牧。',136,'全唐诗/poet.song.64000.json','["牧牛兒，遠陂牧。", "遠陂牧牛芳草綠，兒怒掉鞭牛不觸。", "澗邊古柳南風清，麥深蔽日野田平。", "烏犍礪角逐春行，老牸卧噍饑不鳴。", "犢兒跳梁沒草去，隔林應母時一聲。", "老翁念兒自携餉，出門先上岡頭望。", "日斜風雨濕蓑衣，拍手唱歌尋伴歸。", "遠村放牧風日薄，近村牧牛泥水惡。", "珠璣燕趙兒不知，兒生但知牛背樂。"]'),
('b220edd8-a067-4fc4-90ef-6034bc6e0b18','贈人三首次韵道卿  其一','張耒','宋','宋诗','song-poetry','','[]','未必蝤蠐如素領，故應新月學蛾眉。',64,'全唐诗/poet.song.64000.json','["未必蝤蠐如素領，故應新月學蛾眉。", "引成密約因言笑，試得真情是別離。", "罇酒且傾寒琥珀，淚妝更看薄臙脂。", "北城月落烏啼後，便是孤舟腸斷時。"]'),
('770f8e3f-7ab0-4db2-8e9f-4a0c3a6376ca','贈人三首次韵道卿  其二','張耒','宋','宋诗','song-poetry','','[]','醉裏紛紛散別筵，醒來客枕一燈前。',64,'全唐诗/poet.song.64000.json','["醉裏紛紛散別筵，醒來客枕一燈前。", "黄茅野岸三更月，春水長亭十里船。", "一點淚憑誰寄與，十年香在恨依然。", "空疑窗外梅花發，珠箔青樓若箇邊。"]'),
('f35b5244-839d-43d6-994f-1abac2ad381a','贈人三首次韵道卿  其三','張耒','宋','宋诗','song-poetry','','[]','可是相逢意便深，爲郎巧笑不須金。',64,'全唐诗/poet.song.64000.json','["可是相逢意便深，爲郎巧笑不須金。", "門前一尺春風髻，窗外三更夜雨衾。", "別燕從教燈見淚，夜窗惟有月知心。", "東西芳草渾相似，欲望高城何處尋。"]'),
('48866f33-5aaf-4c74-96f7-2454c422cba2','採蓮子','張耒','宋','宋诗','song-poetry','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5973\u5b50", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd"]','菡萏香蓮十頃陂，小姑貪戲採蓮池。',32,'全唐诗/poet.song.64000.json','["菡萏香蓮十頃陂，小姑貪戲採蓮池。", "晚來弄水船頭濕，更脫新裙裹鴨兒。"]'),
('7dcc05d3-397f-42af-a914-c8098b099576','倚聲製曲三首  其一','張耒','宋','宋诗','song-poetry','','[]','春絲惹恨鬢雲垂，媚態愁容半在眉。',64,'全唐诗/poet.song.64000.json','["春絲惹恨鬢雲垂，媚態愁容半在眉。", "早是思深難語別，可堪肌瘦不勝衣。", "眼前有恨景尤速，門外無情車載脂。", "自笑不如天上月，尊前猶有見郎時。"]'),
('03bf9a35-280f-4037-8938-ae190160a321','倚聲製曲三首  其二','張耒','宋','宋诗','song-poetry','','[]','不恨因緣不恨天，强持牙板向罇前。',64,'全唐诗/poet.song.64000.json','["不恨因緣不恨天，强持牙板向罇前。", "陽關一曲動山月，別淚千行盈酒船。", "薄命有情今已矣，傍人無意亦凄然。", "願君學取梁間燕，秋去春來到妾邊。"]'),
('b856b2fc-ae50-4598-9ffd-1e7938966817','倚聲製曲三首  其三','張耒','宋','宋诗','song-poetry','','[]','山未高兮水不深，此情此意薄千金。',64,'全唐诗/poet.song.64000.json','["山未高兮水不深，此情此意薄千金。", "今朝酒伴雙垂淚，明夜燈前獨擁衾。", "玉筯異時空見跡，麈犀千里亦通心。", "桃源路絕無人到，應許劉郎再訪尋。"]'),
('c8a800f1-2a56-45af-a0d8-5f9a847c844e','劉壯輿是是堂歌','張耒','宋','宋诗','song-poetry','','[]','讀堂中之書兮，以致子之眠。',65,'全唐诗/poet.song.64000.json','["讀堂中之書兮，以致子之眠。", "飲堂中之酒兮，以休子之言。", "是非雜然於子之耳兮，付庭中之嘆蚓，與夫木上之鳴蟬。", "庶幾養生而保和兮，窮子之年。"]'),
('7abe8ca3-2cf9-463b-9499-de870e2c4e87','獨處愁','張耒','宋','宋诗','song-poetry','','[]','高高花飛驚愁顔，珠簾晝鎖春風閒。',64,'全唐诗/poet.song.64000.json','["高高花飛驚愁顔，珠簾晝鎖春風閒。", "少年金鞍照秦地，玉巵雙覆塵埃間。", "花間蝴蝶雙飛舞，感觸深心心更苦。", "昨夜陰雲數尺許，連宵變作西窗雨。"]'),
('7bcbd2f1-8c29-4e34-a222-0737123d8575','遠別離','張耒','宋','宋诗','song-poetry','','[]','遠別離，明當入蜀去。',122,'全唐诗/poet.song.64000.json','["遠別離，明當入蜀去。", "酒酣日落客心驚，起與僕夫先議路。", "引車在庭牛在槽，桐枝嫋嫋秋風豪。", "別情惆悵氣不下，酒觴翻污麒麟袍。", "緩緩清歌慰幽獨，不惜更長更燒燭。", "贈君髮上古搔頭，莫易此心如此玉。", "平生每笑花飛片，東家吹落西家怨。", "但得歸時似別時，相知何必長相見。"]'),
('35d85dcc-46ca-4080-b301-5e4023ad21a7','行路難','張耒','宋','宋诗','song-poetry','','[]','人生動與衣食關，百年役役誰爲閒。',96,'全唐诗/poet.song.64000.json','["人生動與衣食關，百年役役誰爲閒。", "四時睡足鞍馬上，去歲錢塘今長安。", "車愁羊腸夜險折，船畏人鮓晨驚湍。", "九州一身恨自惜，使我顔色常鮮歡。", "天地一氣成萬象，融即是江結是山。", "再願洪罏瀉融結，萬世更無行路難。"]'),
('b41fa706-aa22-4cf1-8a5c-1c4c1b00678b','白紵詞二首效鮑照  其一','張耒','宋','宋诗','song-poetry','','[]','摇輕裾，曳長袖，爲楚舞，千萬壽。',48,'全唐诗/poet.song.64000.json','["摇輕裾，曳長袖，爲楚舞，千萬壽。", "新詞白紵聲按舊。", "朔風捲地來崢嶸，燕雁避霜饑不鳴。", "高堂酒多華燈明。"]'),
('cb266dc8-d9e8-43b2-80aa-4e8289f7f943','白紵詞二首效鮑照  其二','張耒','宋','宋诗','song-poetry','','[]','回纖腰，出素手，髻墮鬢傾釵欲溜，爲君歌舞君飲酒。',48,'全唐诗/poet.song.64000.json','["回纖腰，出素手，髻墮鬢傾釵欲溜，爲君歌舞君飲酒。", "歲云暮矣七澤空，湯湯漢沔天北風。", "玉壺之酒樂未終。"]'),
('573f0086-2d71-4bb4-b3e0-19768b6fcd19','七夕歌','張耒','宋','宋诗','song-poetry','','["\u4e03\u5915\u60c5\u4eba\u8282", "\u53d9\u4e8b", "\u7231\u60c5", "\u4e03\u5915\u8282", "\u6545\u4e8b"]','人間一葉梧桐飄，蓐收行秋回斗杓。',224,'全唐诗/poet.song.64000.json','["人間一葉梧桐飄，蓐收行秋回斗杓。", "神官召集役靈鵲，直渡銀河雲作橋。", "河東美人天帝子，機杼年年勞玉指。", "纖成雲霧紫星衣，辛苦無歡容不理。", "帝憐獨居無與娛，河西嫁與牽牛夫。", "自從嫁得廢織紝，綠鬢雲鬟朝暮梳。", "貪歡不歸天帝怒，謫歸却理來時路。", "但令一歲一相見，七月七日橋邊渡。", "別長會少知奈何，却悔從來歡愛多。", "匆匆萬事說不盡，燭龍已駕隨羲和。", "河邊靈官催曉發，令嚴不管輕離別。", "空將淚作雨滂沱，淚痕有盡愁無歇。", "我言織女君莫歎，天地無窮會相見。", "猶勝姮娥不嫁人，夜夜孤眠廣寒殿。"]'),
('a7213663-860f-4f4d-aab6-ed310494d756','琉璃瓶歌贈晁二','張耒','宋','宋诗','song-poetry','','[]','火維荒茫地軸傾，下有積水潜鯤鯨。',288,'全唐诗/poet.song.64000.json','["火維荒茫地軸傾，下有積水潜鯤鯨。", "鰲身翻瀾山爲崩，金烏下啄獰龍騰。", "狂鬚奇鬣萬族朋，巨神日月雙手擎。", "夸娥愁思烏戢翎，老魚戰死風雨腥。", "長彗下掃千里驚，淺洲一席塊爲城。", "蠻兒夷女奇弁纓。", "大舶映天日百程，怒帆吼風戰飛鵬。", "舟中之人怪眉睛，獸肌鳥舌髻翹撐。", "萬金明珠絡如繩，白衣夜明非縞繒。", "以有易無百貨傾，室中開橐光出楹。", "非石非玉色紺青，昆吾寶鐵雕春冰。", "表裏洞徹中虛明，宛然而深是爲瓶。", "補陀真人一銖衣，攀膝燕坐花雨飛。", "兜羅寶手親挈携，楊枝取露救渴饑。", "海師跪請顙有胝，番禺寶市無光輝。", "流傳人間入吾手，包以百襲吳綿厚。", "擇人而歸今子授。", "爛然光輝子文章，清明無垢君肺腸。", "比君之德君勿忘，與君同升白玉堂。"]'),
('7e2be653-7eef-4e08-8e8d-09688c9d30ba','九江千歲龜歌贈无咎','張耒','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','靈龜千年口不食，以背負床飲其息。',364,'全唐诗/poet.song.64000.json','["靈龜千年口不食，以背負床飲其息。", "吾家兩龜豈徒不食亦不息，壽與萬古無終極。", "濟南晁君博物天地通，夜窺牛斗頗似晉司空。", "指我兩龜有名字，大龜爲九江，小龜號千歲。", "老龍洞庭怒，蕩覆堯九州。", "禹咄嗟，水平流。", "九江無波拍天浮，中有大靈背如丘。", "南風吹楚澤，蓮葉清欲秀。", "有物中作巢，一寸立介胄。", "霞衣仙人鬢如霜，飲以南極之光芒。", "丹顱老客不相見，飛渡東海巢扶桑。", "邇來蟠桃枝，有子大如缶。", "浮游輕于鳥，江海一回首。", "青珊瑚柱碧瑶宮，水仙焚香吹作風。", "朝戲蓮葉西，暮遊蓮花東。", "秋風蓮子熟，歸去清江國。", "小千歲，大九江，我久不見之，向君案前雙。", "我謂晁君二物有似我與子，國有守龜吾子是。", "燦然天下之寶器，黄金之縢紫瑶匱。", "天王端冕史再拜，一逆二從定大事。", "我身百無用，頗似千歲潜深淵。", "不願人間貯金藉玉享富貴，但願寄身江上一葉之秋蓮。", "萬物才不才，用舍不任天。", "寄聲問晁君，然不然。"]'),
('afa940ae-8290-40c7-9509-1238c0279382','大雪歌','張耒','宋','宋诗','song-poetry','','[]','老農占田得吉卜，一夜北風雪漫屋。',128,'全唐诗/poet.song.64000.json','["老農占田得吉卜，一夜北風雪漫屋。", "屋壓欲折君勿悲，隴頭新麥一尺泥。", "泥深麥牢風莫吹，明年作餠大如箕。", "野人食飽官事少，莫畏瑟縮寒侵肌。", "高堂晨興何所爲，門無馬跡人更稀。", "珠樓玉閣互飛動，坐見貧屋生光輝。", "無功及物慚受祿，豐穰幸頼天與之。", "棄糧遺粒待雞犬，吾羹何得長烹藜。"]'),
('b1555e26-cb16-481e-b1be-3192032334b7','孫彥古畫風雨山水歌','張耒','宋','宋诗','song-poetry','','[]','山深巖高石壁青，白日忽變天晦冥。',192,'全唐诗/poet.song.64000.json','["山深巖高石壁青，白日忽變天晦冥。", "黑風驅雲走不停，驚電疾雨來如傾。", "山前雨點大如手，山下水湧危槎橫。", "崩崖古樹老有靈，吼怒直與風雲爭。", "枝披葉偃鬭不怯，萬竅却欲藏雷霆。", "鞭馿疾驅者誰子，石路嶮澀馿凌兢。", "目迷心懾愈不及，來憩樹下如寒蠅。", "蒼茫直與鬼神接，恍惚不保龍蛇驚。", "平居此樂忽入眼，孫家古圖纔可辨。", "奈何一幅一尺餘，欲奪天地之奇變。", "我心愛之良有以，昔苦山行親遇此。", "一生兩足不下堂，輸爾朱家貴公子。"]'),
('e58d162d-88be-4386-a37f-895d5ed0172c','歲暮歌','張耒','宋','宋诗','song-poetry','','[]','北風卷雪送暮冬，重雲如山爭塞空。',128,'全唐诗/poet.song.64000.json','["北風卷雪送暮冬，重雲如山爭塞空。", "百年老樹吼欲折，塌翼不見南飛鴻。", "堂下幽姿亦可悅，點綴小樹花玲瓏。", "老人重裘不能煖，永夜惟守深爐紅。", "啾啾寒雀飛不起，饑啄凍土藏枯叢。", "青春欲回水官怒，摧拉未使陽和通。", "天時平分各司一，興廢誰得專其雄。", "杜門解轡聊有待，行看馬脚春泥融。"]'),
('7aea62f0-7cd6-4527-8a83-986c32300a55','光山謠','張耒','宋','宋诗','song-poetry','','[]','艤舟淮南望新息，天遣清淮限南北。',128,'全唐诗/poet.song.64000.json','["艤舟淮南望新息，天遣清淮限南北。", "崎嶇細路入光山，野色蒼凉秋日白。", "八月穫稻田無水，蚱蜢羣飛稻乾死。", "危橋絕澗聞水聲，喧喧汲水爭瓶罌。", "昏昏落日銜遠山，鳥啼車轍未得閒。", "縣公吳生我世舊，爲我烹羊酤斗酒。", "燈前醉飽紛就眠，五更開門星滿天。", "長年他鄉心惘然，遠途辛勤難具言。"]'),
('f4a5f541-71ed-4221-8d6e-ce6eecb3f90e','用劉夢得三題  其一','張耒','宋','宋诗','song-poetry','','[]','春向晚，斜日在高樓。',34,'全唐诗/poet.song.64000.json','["春向晚，斜日在高樓。", "幽花愁脈脈，輕絮去悠悠。", "冉冉三更雨，蕭蕭通夜愁。"]'),
('3680439f-fb5b-499a-a44b-c51874611dbd','用劉夢得三題  其二','張耒','宋','宋诗','song-poetry','','[]','春已暮，把酒送春歸。',34,'全唐诗/poet.song.64000.json','["春已暮，把酒送春歸。", "花落鳴禽散，草長遊客稀。", "去年堂上燕，故故傍人飛。"]'),
('a1f09f7c-de62-40d8-ab31-eba281c44208','用劉夢得三題  其三','張耒','宋','宋诗','song-poetry','','[]','春竟去，白髮感生平。',34,'全唐诗/poet.song.64000.json','["春竟去，白髮感生平。", "流水去不斷，夕陽猶有情。", "舊時桃李月，悄悄向人明。"]'),
('bb882268-5e89-423c-a960-78939f2bd01a','年年歌','張耒','宋','宋诗','song-poetry','','[]','年年西風白露天，爛醉村釀秋池原。',192,'全唐诗/poet.song.64000.json','["年年西風白露天，爛醉村釀秋池原。", "今年杜門不復出，爲愛我庭風日寬。", "東西相望兩叢竹，正色森森立青玉。", "朝烟暮雨恣陵奪，翠鳳文章終鬰鬰。", "石榴新栽果不實，下有蕭條冒霜菊。", "人情雖欲薦我酒，物意豈願贏君菊。", "東欄黄葵色貴麗，氣壓滿欄香撲蔌。", "月桂凄凉何足數，蛛網挂蟲窘如束。", "安能卒歲不改芳，正自榮枯隨衆木。", "陶陶吾意方有在，瑣瑣眼前安足錄。", "朝來默坐有佳思，病去身輕如脫梏。", "從來北客望江南，何用登樓傷遠目。"]'),
('d792d05b-1529-47b7-b8f1-f2e07639915c','鵯鵊詞','張耒','宋','宋诗','song-poetry','','[]','樹頭玄衣郎，神爽聲復清。',72,'全唐诗/poet.song.64000.json','["樹頭玄衣郎，神爽聲復清。", "睡先萬目覺，起對殘月星。", "憫世耽睡昏，體穢神不靈。", "招使離衽席，啼呼每丁寧。", "幽人最憐汝，未旦起坐聽。", "荒山多嘉樹，春盡故園情。"]'),
('3c7a8f65-e298-417e-a852-ce3ba7be4f65','圍棋歌戲江瞻道兼呈蔡秘校','張耒','宋','宋诗','song-poetry','','[]','蔡子圍棋非我敵，我謹事之如大國。',224,'全唐诗/poet.song.64000.json','["蔡子圍棋非我敵，我謹事之如大國。", "主盟召會不敢辭，近忽憑陵有驕色。", "鄒人戰魯固非宜，于越入吳誰可測。", "願君勿以大自驕，知小深謀戰須克。", "區區江子似邾婁，我如强魯端能役。", "凌兢螳臂屢見拒，我但憐子心難得。", "近來措置尤小獰，何異穿窬時有獲。", "可憐癡將不知兵，請視吾旂豈冥北。", "饑魚貪餌不知鈎，口雖暫美身遭食。", "雖然吾亦守疆埸，防患猶須謹蟊賊。", "上攀蔡子雖已遼，晉楚周旋終有日。", "下觀江子行逾遠，我進駸駸未知極。", "嗟予自謂敢忘謙，事有真誠難掩抑。", "爲君聊發一笑端，欲開吾棋視斯檄。"]'),
('fdc2ac4a-2c81-4341-bc37-1d8a88acf01c','周氏行','張耒','宋','宋诗','song-poetry','','[]','亭亭美人舟上立，周氏女兒年二十。',320,'全唐诗/poet.song.64000.json','["亭亭美人舟上立，周氏女兒年二十。", "少時嫁得刺船郎，郎身如墨妾如霜。", "嫁後妍媸誰復比，淚痕不及人前洗。", "天寒守舵雨中立，風順張帆夜深起。", "百般辛苦心不惜，妾意私悲鑑中色。", "不如江上兩鷺鷥，飛去飛來一雙白。", "長淮杳杳接天浮，八月搗衣南國秋。", "謾說鯉魚能託信，祇應明月見人愁。", "淮邊少年知妾名，船頭致酒邀妾傾。", "賊兒惡少謾調笑，妾意視爾鴻毛輕。", "白衫烏帽誰家子，妾一見之心欲死。", "人間會合亦偶然，灘下求船忽相值。", "郎情何似似春風，靄靄吹人心自融。", "河中逢潬還成阻，潮到蓬山信不通。", "百里同船不同枕，妾夢郎時郎正寢。", "山頭月落郎起歸，沙邊潮滿妾船移。", "郎似飛鴻不可留，妾如斜日水東流。", "鴻飛水去兩不顧，千古萬古情悠悠。", "情悠悠兮何處問，倒瀉長淮洗難盡。", "祇應化成淮上雲，往來供作淮邊恨。"]'),
('e102f41b-30ec-4be2-aed7-75a8449bf4ab','啄木詞','張耒','宋','宋诗','song-poetry','','[]','紅錦長絛當背垂，紫檀槽穩橫朱絲。',160,'全唐诗/poet.song.64000.json','["紅錦長絛當背垂，紫檀槽穩橫朱絲。", "美人亭亭面如雪，纖手當弦金桿撥。", "彈成丁丁啄木聲，春林蔽日春晝晴。", "徘徊深枝穿翠葉，玉喙勞時還暫歇。", "深園斷嶺人不知，中有槎枒風雨枝。", "蠹多蟲老飽可樂，山靜花深終日啄。", "雄雌相求飛且鳴，高枝礪嘴枝有聲。", "無功忍使饑腸飽，有意却教枯樹青。", "疾彈如歌細如語，曲欲終時情更駐。", "一聲穿樹忽驚飛，葉動枝摇不知處。"]'),
('c1f18932-507b-475b-914f-7bd82dc497a0','瓦器易石鼓文歌','張耒','宋','宋诗','song-poetry','','[]','周綱既季宣王作，提劍揮呵天地廓。',288,'全唐诗/poet.song.64000.json','["周綱既季宣王作，提劍揮呵天地廓。", "朝來吉日差我馬，夜視雲漢憂民瘼。", "桓桓方召執弓鉞，藹藹申韓賜圭爵。", "北驅獫狁走豺狼，南伐淮夷斬鯨鱷。", "明堂車馬走爭先，清廟笙鏞尸載樂。", "岐陽大獵紀功伐，石鼓巖巖萬夫鑿。", "千年兵火變朝市，後世紙筆傳冥漠。", "迹荒事遠貴者寡，歎惜風霜日摧剝。", "君誠嗜古更過我，易以瓦器尤奇卓。", "滿盤蒼玉列我前，制古形奇異雕琢。", "羲黄已亡巧僞起，采椽土木消純樸。", "何爲獲此上古器，經歷萬古遭搜掠。", "寥寥墨翟骨已朽，尚有遺風傳隠約。", "又疑晏子矯齊俗，陶土摶泥從儉薄。", "或云古者宗廟器，斥棄金玉先誠確。", "是時此物參鼎俎，蕢桴土鼓誠爲樂。", "嗚呼二物信奇絕，頼有吾徒與提握。", "不然烏瓦與荒碑，坐見塵埃就零落。"]'),
('4ac05e3c-99d1-4295-ada4-2be38b9b6abb','片雪歌','張耒','宋','宋诗','song-poetry','','[]','瑶池一片孤飛雪，風急身輕飛不歇。',160,'全唐诗/poet.song.64000.json','["瑶池一片孤飛雪，風急身輕飛不歇。", "誰將翠袖遮得歸，十斛明珠換與誰。", "金龜貴客迎將去，玉作輜軿載塵霧。", "人間不解桃李心，獨與琵琶自相語。", "主人白頭情不親，朱樓夜鎖梨花春。", "願同花落寄流水，飄出朱門隨路塵。", "長恐此生空已矣，從此失身輕薄子。", "人生但樂兩知心，誰是瓊瑶孰泥滓。", "鶯驚中彈花辭樹，蝶散蜂驚春日暮。", "風光不斷流水長，不知片雪今何處。"]'),
('bf0d301d-556f-4afd-aa83-6737f8d8a7b0','梁父吟','張耒','宋','宋诗','song-poetry','','[]','豪俊昔未遇，白日無光輝。',240,'全唐诗/poet.song.64000.json','["豪俊昔未遇，白日無光輝。", "隆中卧龍客，長嘯視羣兒。", "九州英雄爭著鞭，黄星午夜照中原。", "君看慷慨有心者，乃是山東高帝孫。", "老瞞赤壁抱馬走，紫髯江左空回首。", "世上男兒能幾人，眼看袁呂真何有。", "永安受詔堪垂涕，手挈庸兒是天意。", "渭上空張復漢旂，蜀民已哭歸師至。", "堂堂八陣竟何爲，長安不見漢官儀。", "鄧艾老翁誇至計，譙周鼠子辨興衰。", "梁父吟，君聽取，擊節高歌爲君舞。", "躬耕貧賤志功名，功名入手亡中路。", "逢時兒女各稱雄，運去英雄非曆數。", "梁父吟，悲復悲。", "古今人事半如此，所以達士觀如遺。", "龐公可是無心者，何事鹿門招不歸。"]'),
('12c92583-c541-4d49-a063-a7b03a4527a0','度關山','張耒','宋','宋诗','song-poetry','','[]','度關山，意悠哉，秦關路險行車摧。',192,'全唐诗/poet.song.64000.json','["度關山，意悠哉，秦關路險行車摧。", "秋雲沉沉天未曉，關吏正眠關未開。", "孟嘗逃秦畏秦逐，一日歸齊未爲速。", "重扉當道可奈何，搔首蒼茫空駐轂。", "主君無言客無計，仰看天星俯相視。", "風鳴木響心自驚，咄嗟謾養三千士。", "下客趨前敢獻誠，爲君試效晨雞鳴。", "引聲未絕羣雞應，軋軋重門俄徹扃。", "馬嘶人語車輪轉，斗柄斜橫夜初半。", "奔風捷足欲何追，虎口脫身非素願。", "孟嘗好士竟何爲，纔得雞鳴狗盜兒。", "可憐當日慇懃意，輟食分衣竟爲誰。"]'),
('6d68617c-d5a3-40aa-9941-1d5c91843e0e','天馬歌','張耒','宋','宋诗','song-poetry','','[]','風霆冥冥日月蔽，帝遣真龍下人世。',227,'全唐诗/poet.song.64000.json','["風霆冥冥日月蔽，帝遣真龍下人世。", "降精神馬育天駒，足躡奔風動千里。", "蕭條寄産大宛城，我非爾乘徒爾生。", "小羌雜種漫羈絏，櫪上秋風時一鳴。", "萬里名聞漢天子，內府鑄金求騄駬。", "將軍受詔玉關開，靈旂西指宛王死。", "天馬出城天駟驚，塞沙颯颯邊風生。", "執驅校尉再拜馭，護羌使者清途迎。", "騏驎殿下瞻天表，天質龍姿自相照。", "翠蕤黄屋兩邐迤，玉鐙金鞍相炫耀。", "東游封祀被和鑾，甲子北來巡朔邊。", "展才自覺逢時樂，致遠不知行路難。", "物生從類如有神，地無遠近終相親。", "君不見莘野磻溪耕釣叟，一朝吐氣佐明君。"]'),
('eb5b60bf-ad0a-456a-90f6-56768b57b7e4','江南曲','張耒','宋','宋诗','song-poetry','','[]','平湖碧玉烟波闊，芰荷風起秋香發。',128,'全唐诗/poet.song.64000.json','["平湖碧玉烟波闊，芰荷風起秋香發。", "採蓮女兒紅粉新，舟中笑語隔烟聞。", "高繫紅裙袖雙卷，不惜浮萍沾皓腕。", "爭先採得隠船篷，多少相欺互相問。", "吳兒蕩槳來何事，手指荷花示深意。", "郎指蓮房妾折絲，蓮不到頭絲不止。", "月上潮平四散歸，舟輕楫短去如飛。", "斷腸脈脈兩無語，寄情流水傳相思。"]'),
('82334bab-0060-4ab9-8deb-44f0257e94aa','籠鷹詞','張耒','宋','宋诗','song-poetry','','[]','八月穫黍霜野空，蒼鷹羽齊初出籠。',128,'全唐诗/poet.song.64000.json','["八月穫黍霜野空，蒼鷹羽齊初出籠。", "劍翎鈎爪目如電，利吻新淬龍泉鋒。", "少年臂爾平郊去，草動人呼躍寒兔。", "竦身下擊霹靂忙，毛逐奔風血濡距。", "爾能搏兔不能食，未飽中腸行復擊。", "主人厭兔爾尚饑，一生不快爲人役。", "蒿間黄雀鳴啾啾，饑啄野粟心無求。", "賦形雖小技能薄，不受羈縻得自由。"]'),
('0508622d-ffe2-4ce8-83f2-2802f8ba5648','拳毛駒歌','張耒','宋','宋诗','song-poetry','','[]','北窗掃壁陳圖書，殺氣凜凜生坐隅。',146,'全唐诗/poet.song.64000.json','["北窗掃壁陳圖書，殺氣凜凜生坐隅。", "誰將尺素畫駿馬，云是文皇昔日拳毛駒。", "龍顱虎脊視天地，若滅若沒三萬里。", "皇天産此誰得之，虯鬚十八真天子。", "擒王滅竇如塵埃，英氣貫日天爲開。", "黄金甲光照天地，大白羽箭馳風雷。", "真龍在廄萬馬疾，下視四海皆駑駘。", "榛棘昭陵一抔土，柏城六馬莓苔古。", "嗚呼駿馬已埃塵，雖有燕昭難再睹。"]'),
('ea881645-1b60-4c8d-ab51-a371bc630bd1','寒鴉詞','張耒','宋','宋诗','song-poetry','','[]','寒鴉來時九月天，黄梁蕭蕭人刈田。',160,'全唐诗/poet.song.64000.json','["寒鴉來時九月天，黄梁蕭蕭人刈田。", "啼聲清哀晚紛泊，迭和羣音和且樂。", "朋飛聚噪動百千，頸腹如霜雙翅玄。", "風高日落田中至，部隊崩騰鉦鼓沸。", "高林古道榆柳郊，落葉晴霜荆棘地。", "志士朝聞感歲華，田家候爾知寒事。", "壠頭雪消牛挽犁，蕩漾春風吹爾歸。", "投寒避暖竟何事，長伴燕鴻南北飛。", "我滯窮城未知返，爲爾年年悲歲晚。", "扁舟東下會有期，明年見爾長淮岸。"]'),
('d3945d50-03f9-4ed3-97b9-71cd03e5c9ed','寒食歌','張耒','宋','宋诗','song-poetry','','[]','東風芳草長，寒食春茫茫。',184,'全唐诗/poet.song.64000.json','["東風芳草長，寒食春茫茫。", "人家掩門去，雞犬自相將。", "原頭簇簇柳與花，行人往來長歎嗟。", "舊墳新塚累累是，裂錢澆酒何人家。", "桑上鳴鳩喚山雨，雨脚蕭蕭山日暮。", "歸來門巷正春寒，花底殘紅落無數。", "北里悲啼夜未休，清弦脆管起南樓。", "古今歌笑何時盡，芳草白楊春復秋。", "去年巧笑鞦韆女，今年嫁作東家婦。", "綵繩畫柱似當年，只有朱顔不如故。", "百人學仙無一成，麻姑不見但聞名。", "萬斛春醪須痛飲，江邊漁父笑人醒。"]'),
('14ad8390-4840-4825-bdd2-913566dd761a','飛螢詞','張耒','宋','宋诗','song-poetry','','[]','碧梧含風夏夜清，林塘五月初飛螢。',195,'全唐诗/poet.song.64000.json','["碧梧含風夏夜清，林塘五月初飛螢。", "翠屏玉簟起凉思，一點秋心從此生。", "方池水深溪雨積，上下輝輝亂凝碧。", "幸因簾捲到華堂，不畏人驚照瑶席。", "漢宮千門連萬戶，夜夜熒煌暗中度。", "光流太液池上波，影落金盤月中露。", "銀闕蒼蒼玉漏遲，年年爲爾足愁思。", "長門怨妾不成寐，團扇美人還賦詩。", "避暑風廊人語笑，欄下撲來羅扇小。", "已投幽室自分明，更伴殘星碧天曉。", "君不見連昌宮殿洛陽西，破瓦頹垣今古悲。", "荒榛腐草無人迹，只有秋來熠燿飛。"]'),
('02f882de-2e07-49be-bac3-6d99a97d3c60','齊安行','張耒','宋','宋诗','song-poetry','','[]','黄州楚國分三戶，葛蔓爲城當樓櫓。',128,'全唐诗/poet.song.64000.json','["黄州楚國分三戶，葛蔓爲城當樓櫓。", "江邊市井數十家，城中平田無一步。", "土岡瘦竹青復黄，引水種稻官街旁。", "客檣朝集暮四散，夷言啁哳來湖湘。", "使君麗譙塗堊赭，門狹不能行兩馬。", "滿城蛙噪亂更聲，谷風穀穀黄鴉鳴。", "最愁三伏熱如甑，北客十人八九病。", "百年生死向中州，千金莫作齊安遊。"]'),
('7465a960-519b-4eb7-9fb7-9c070de1e1f3','一百五歌','張耒','宋','宋诗','song-poetry','','[]','山民歲時事莽鹵，猶知拜掃一百五。',96,'全唐诗/poet.song.64000.json','["山民歲時事莽鹵，猶知拜掃一百五。", "平明士女出城闉，黄土岡前列尊俎。", "篛包粉餌蒸野蔬，富家烹羊貧薦魚。", "日暮肩輿踏風雨，江鄉人家無犢車。", "插花飲酒山邊市，醉後歌聲動鄰里。", "南人聞歌笑相尋，北人聞歌淚滿襟。"]'),
('95833da0-190a-41b4-809b-98599494df13','秋風謠','張耒','宋','宋诗','song-poetry','','[]','秋風起，秋雲高。',72,'全唐诗/poet.song.64000.json','["秋風起，秋雲高。", "連山草木如波濤，大江蕩潏魚龍逃。", "羲和奔忙日車逸，八柱傾側恐不牢。", "柯山老人揜蓬茅，畏寒理我舊縕袍。", "粗餐在盤有濁醪，醉飽高卧從呼號。"]'),
('a79d92a3-f08a-403b-a207-a6e83e876cd2','東皋行','張耒','宋','宋诗','song-poetry','','[]','秋雲捲盡秋天清，東皋蕭條雞犬聲。',64,'全唐诗/poet.song.64000.json','["秋雲捲盡秋天清，東皋蕭條雞犬聲。", "黄葉吟風聲不平，芙蕖半落更有情。", "歸來僮饑羸馬疲，城頭樹暗烏欲栖。", "誰家朱樓人夜宿，微紅一點簾間燭。"]'),
('2f7d584c-eba8-4a80-93ea-a05b5307550d','正月詞','張耒','宋','宋诗','song-poetry','','[]','紅梢一夜櫻桃雨，簾捲曉晴鴝鵒語。',64,'全唐诗/poet.song.64000.json','["紅梢一夜櫻桃雨，簾捲曉晴鴝鵒語。", "簾旌細浪滾東風，迎得春歸與爲主。", "玉手嬌慵添繡線，欄下菖蒲近相見。", "雲屏曉睡翠翹橫，樓上寒時正五更。"]'),
('6ef6f6c4-2d40-467b-a1b9-7a3d74a89c30','二月詞','張耒','宋','宋诗','song-poetry','','[]','滾風畫幕長廊靜，簾下人眠初日永。',64,'全唐诗/poet.song.64000.json','["滾風畫幕長廊靜，簾下人眠初日永。", "嚶嚶不動採花蜂，夜來露重薔薇冷。", "芳草長時寒食天，紅牆低處見鞦韆。", "人家無事雞犬閒，日暮芳郊留醉眠。"]'),
('fc01d7ed-34a3-41f6-a386-bf76990f5619','饑烏詞','張耒','宋','宋诗','song-poetry','','[]','北風夜雨烏翅濕，低飛野畦啄遺粒。',64,'全唐诗/poet.song.64000.json','["北風夜雨烏翅濕，低飛野畦啄遺粒。", "啄食不飽還畏人，嗚呼隔隴自求羣。", "我行陳宋經大澤，田荒生茅不種麥。", "空腸待飽明年禾，鴉鴉爾饑獨奈何。"]'),
('6d35e292-02dd-42c5-85c9-cc49ccad0316','苦寒行二首  其一','張耒','宋','宋诗','song-poetry','','[]','淮南苦寒不可度，積雪連山風倒樹。',64,'全唐诗/poet.song.64000.json','["淮南苦寒不可度，積雪連山風倒樹。", "長淮凍絕魚龍愁，哀鴻傍人飛不去。", "雪中寒日無暖光，六龍瑟縮不肯驤。", "老憊孤舟且復止，堅冰三尺厚於牆。"]'),
('fe8c59b6-b37a-4075-a314-cab0f0861b33','苦寒行二首  其二','張耒','宋','宋诗','song-poetry','','[]','茫茫楚鄉仲冬月，白屋無烟飛走絕。',64,'全唐诗/poet.song.64000.json','["茫茫楚鄉仲冬月，白屋無烟飛走絕。", "空林號風冰斷枝，長淮無人冰照雪。", "凍埋釣艇不復漁，南羹未嚼淮中魚。", "要須下擘澄湫水，剸取寒蛟烹腹腴。"]'),
('d472efc9-b83d-48eb-9e72-1748d8b6676a','春詞','張耒','宋','宋诗','song-poetry','','[]','寶刀裁花碎羅縠，带臘圓紅黄染粟。',64,'全唐诗/poet.song.64000.json','["寶刀裁花碎羅縠，带臘圓紅黄染粟。", "枝頭幾日即花開，世上人情何太速。", "東風未轉北風嚴，返挂銅鈎不上簾。", "莫怪蛾眉呵素指，層簷冰碧玉纖纖。"]'),
('0f6700cd-e52a-4c56-ac8e-361bc0df550c','宮詞效王建五首  其一','張耒','宋','宋诗','song-poetry','','[]','夜來霜重著欄干，玉殿無塵玉甃寒。',32,'全唐诗/poet.song.64000.json','["夜來霜重著欄干，玉殿無塵玉甃寒。", "日日君王罷朝早，禁廷無事一冬閒。"]'),
('5e0283d6-6c9b-43b3-9a50-893c1ee608b5','宮詞效王建五首  其二','張耒','宋','宋诗','song-poetry','','[]','簾外微明燭下妝，殿門放鑰待君王。',32,'全唐诗/poet.song.64000.json','["簾外微明燭下妝，殿門放鑰待君王。", "玉階地冷羅鞋薄，衆裏偷身倚御床。"]'),
('d5e2dffb-88a0-4405-ad9f-59fbfa44610c','宮詞效王建五首  其三','張耒','宋','宋诗','song-poetry','','[]','昨夜新霜滿玉階，初冬處處火爐開。',32,'全唐诗/poet.song.64000.json','["昨夜新霜滿玉階，初冬處處火爐開。", "中官逐院傳宣賜，南國諸侯進橘來。"]'),
('e2a4dded-bc63-4c17-b3c6-c7e32234cfba','宮詞效王建五首  其四','張耒','宋','宋诗','song-poetry','','[]','玉墀夜色晝昏昏，催放朝班散侍臣。',32,'全唐诗/poet.song.64000.json','["玉墀夜色晝昏昏，催放朝班散侍臣。", "隨駕上樓同看雪，萬重宮殿一時新。"]'),
('20c0bfcd-ce15-4360-99ba-a2576f3bd919','宮詞效王建五首  其五','張耒','宋','宋诗','song-poetry','','[]','蓮燭千枝夜宴遲，君王索筆寫新詩。',32,'全唐诗/poet.song.64000.json','["蓮燭千枝夜宴遲，君王索筆寫新詩。", "宮人和得爭先進，偏愛宋家兄弟詞。"]'),
('76f659e4-557b-46b1-a925-328873e7f004','旱謠','張耒','宋','宋诗','song-poetry','','[]','七月不雨井水渾，孤城烈日風揚塵。',96,'全唐诗/poet.song.64000.json','["七月不雨井水渾，孤城烈日風揚塵。", "楚天萬里無纖雲，旱氣塞空日晝昏。", "土龍蜥蜴竟無神，田中水車聲相聞。", "努力踏車莫厭勤，但憂水勢傷禾根。", "道傍執送者何人，稻塍爭水殺厥鄰。", "五湖七澤水不貧，正頼老龍一屈伸。"]'),
('e84c2e9c-8788-43bf-9cba-ac339fb1e86b','貽潘邠老','張耒','宋','宋诗','song-poetry','','[]','有屋可以讀書，有竹可以忘憂。',144,'全唐诗/poet.song.64000.json','["有屋可以讀書，有竹可以忘憂。", "採庭之菊香有餘，烹園之蔬甘且柔。", "賢哉二子，又復何求。", "鬼不爾責，人不爾仇。", "沽酒可飲，江魚可羞。", "又安用列鼎食珍，佩印封侯。", "我居柯西，相隔一里，可以杖履朝往而夕遊。", "必未厭我乞醯與借馬，但只恐勤君赤脚與露頭。", "不然將吾顔子簞食瓢飲屢空之樂，又欲翻董生清明玉杯繁露之春秋。"]'),
('db3be6f4-00da-4ce3-a944-1a89f1d7426e','醉中雜言','張耒','宋','宋诗','song-poetry','','[]','老人攀花復藉草，春力著人如醉倒。',98,'全唐诗/poet.song.64000.json','["老人攀花復藉草，春力著人如醉倒。", "未容作計試留春，東風已與人俱老。", "東君惜春不惜花，千紅萬紫委泥沙。", "已教白日張錦繡，更欲平地興雲霞。", "我欲呼客無酒肉，摘花插頭悲髮禿。", "安得釀酒萬甕屠千羊，花間醉飽踏春陽。"]'),
('56caf996-0ccd-4902-abda-bca825e7b055','龜山祭淮詞二首 迎神','張耒','宋','宋诗','song-poetry','','[]','木梟梟兮蒼山巔，回洑重深兮其下九淵。',109,'全唐诗/poet.song.64000.json','["木梟梟兮蒼山巔，回洑重深兮其下九淵。", "東風歌兮春水舞，庭肅肅兮神來下。", "神來下兮翠帷舉，谷冥冥兮春山雨。", "雨三休兮神三燕，游雲高兮見極蒲，安我舟楫兮君不怒。", "水濱之人兮苦思君，菖蒲生兮楊柳春。", "解君旂兮醉君御，聊樂一日兮莫予棄。"]'),
('1057efae-5aa8-4266-b898-60974e6bebb2','龜山祭淮詞二首 送神','張耒','宋','宋诗','song-poetry','','[]','楚巫醉兮君不留，春風起兮木蘭舟。',105,'全唐诗/poet.song.64000.json','["楚巫醉兮君不留，春風起兮木蘭舟。", "弭余楫兮飲君酒，君既不顧兮駕龍以出遊。", "凌九江兮勒滄海，萬龍舞兮百靈會。", "君孔樂兮我思君，望君故居兮其上片雲。", "水淪淪兮石碌碌，空祠草長兮風雨入君屋。", "山中春兮鳥鳴悲，明月皎皎兮中夜來。"]'),
('188839ff-f9f7-4a89-bccd-4348dc491770','惠別','張耒','宋','宋诗','song-poetry','','[]','洞簫奏兮瑶瑟御，日不足兮繼以夜。',351,'全唐诗/poet.song.64000.json','["洞簫奏兮瑶瑟御，日不足兮繼以夜。", "吾寧獨此湛樂兮，嘉予美之宜修。", "披浮雲出明月兮，揮衆星不與謀。", "既成言以命予兮，顧永予之光明。", "豈獨謂不然兮，託東風以惠聲。", "嗟言獨何容易兮，有傾身者鬼神。", "中懷著而必見兮，卷蘭舌而交信。", "予雖不執子明燭兮，光輝其舍予。", "兩相審者不媒兮，予既獲子於鼻息。", "舒子聲以歌兮，鳳凰將聞而振羽。", "結子佩而起舞兮，星斗視子而上下。", "獨翩翩其不可留兮，君之居可知而不可得。", "春水渙渙兮，予獨飲君河之曲。", "鳥鳴羣飛兮，其下芳草。", "柳舒舒其可攬結兮，桃李始就其膏沐。", "行者懷兮別者思，酌君酒兮壽君以不衰。", "撫君舟之悠然兮，將浩渺以浮航。", "三江震澤兮，舟師告憊而一息。", "引日星之煌煌兮，吾獨望子於南極。", "想子其下兮，鼓聖濤而鞭蛟龍。", "使宓妃不敢巧笑兮，皇英斂衽而來從。", "南風之來兮，入予裾悅余心。", "獨條暢而清婉兮，曰是爲故人之風。"]'),
('feab454e-aa20-4264-8c0f-94b3a0cd61ce','愬魃','張耒','宋','宋诗','song-poetry','','[]','帝治下土兮遠於民，撫御萬方兮周無垠。',423,'全唐诗/poet.song.64000.json','["帝治下土兮遠於民，撫御萬方兮周無垠。", "物類億千兮莽蓁蓁，出入日月兮運星辰。", "廣必有容兮潜姦昏，不上愬兮帝曷聞。", "歲庚申兮斗建巳，旬逾十兮雨不施。", "秀者燋兮實者悴，麥莽莽兮不出塊。", "舊穀既沒兮待新以食，奪其所望兮民憂以惑。", "捨耒而兵兮奪攘剽賊，急不知慮兮求生頃刻。", "民幸帝兮詔雲師，氣朝升兮斂陽暉。", "孰鼓風兮震川岳，上者揚兮旁者剝。", "雲雖仁兮不得施，野童童兮草木摧。", "熟揚塵兮蔽朝日，紛霏霏兮冒萬物。", "昏迷蒙兮浩恍惚，瞭者瞀兮失南北。", "瘞根莖兮腐葩實，世慘錯兮澤蓬㶿。", "霍霍然兮侵萬室，飄雨塵兮以旦以夕。", "民曰誰爲兮尸是有物，其名曰魃兮旱是司。", "惡潤忌澤兮盜陽威，淫視槁木兮疾華滋，憎飽妬飫兮幸民饑。", "亢不伏兮風以助之，慘懷柔茂兮塵埃是吹。", "來炎火兮爛煒煌，馭回祿兮驂畢方。", "朱旂旐兮絳帷裳，坦無畏兮樂洋洋。", "朋疫癘兮友疾殃，徒甚劇兮黨甚强。", "慢帝威兮分害戕，竊祠禱兮傲驅攘。", "民頼帝仁兮以衣以食，上帝孔昭兮愬無禍責。", "幸帝震怒兮降魃罪疾，無俾在世兮幽沉深溺。", "雷伐鼓兮電揚旂，雨卷壑兮雲張帷。"]'),
('3b5177ea-c3dd-43ef-808c-6eddd99aeec8','敘雨','張耒','宋','宋诗','song-poetry','','[]','西山之泉兮冽以清，淳注萬古兮無虧盈。',410,'全唐诗/poet.song.64000.json','["西山之泉兮冽以清，淳注萬古兮無虧盈。", "應龍蟠守兮謹防扃，有神司之兮帥羣靈。", "神君曷處兮山之穹，雲郛霧闕兮都邃宮。", "騰駕逸景兮馭清風，上友仙聖兮佑帝躬。", "惟今之旱兮非神曷愬，家無餘糧兮麥不庇雨。", "土飄塵揚兮迷行錯步，魃威孔張兮熾莫予禦。", "挹水一勺兮薦羔豚，曷求於水兮神實憑。", "土有蔬兮林有實，芼馨香兮葅芳鬰。", "神我饗兮臨我堂，酌芝醑兮御椒漿。", "巫甚祇兮時甚良，哀我疾兮降我祥。", "神君仁兮念下民，撫民災兮號帝閽。", "帝念神君兮詔雨官，叱馭六龍兮奮互飛。", "騫掣飛電兮鼓雷震，俾霈爾澤兮正無限。", "山靈川怪兮更騰奔，角毛羽鬣兮爛鱗鱗。", "前幢後旆兮玄雙輪，椎轟喧呵兮翻乾坤。", "神龍九鬣兮雜蛟鯤，瞠眼飛涎兮翻齶齦。", "伏潜羲和兮止星辰，一洒萬里兮傾河津。", "妖風失威兮斂以奔，魃濡厥裳兮伏以蹲。", "槁蘇焦澤兮息惔焚，優渥潤沃兮無涯垠。", "菽麰詵詵兮奮裳紳，秋種既即兮農則勤。", "既足而止兮披霧昏，朝陽清明兮斂游塵。", "功成不居兮駕歸雲，空山寥寥兮夜無聞。", "靈泉幽幽兮湛奫淪，竭誠莫報兮仁哉君。"]'),
('24386c47-4bca-461f-b0e7-3ec3157f0d60','友山','張耒','宋','宋诗','song-poetry','','[]','張子官於福昌，塊然獨居，無與爲友。',248,'全唐诗/poet.song.64000.json','["張子官於福昌，塊然獨居，無與爲友。", "賓客不至，遺朋失舊。", "經時閉門，終日鉗口。", "出無與遊，居無與就。", "誰同我食，誰酌我酒。", "歸守妻孥，出對廝走。", "駕言出遊，田童野叟。", "氣否莫交，情包不剖。", "塞聰蔽明，盤足袖手。", "披書閱簡，眩目疲肘。", "厭然成痼，不可針灸。", "於是張子，滌慮除煩。", "披庭掃堂，枕手而眠。", "恍若有遇，有神降焉。", "曰我實哀汝，獨無友朋。", "我有教告，子乎我聽。", "凡世之人，百愚一賢。", "古昔所歎，非獨今然。", "得賢與朋，善固無儷。", "賢不可得，將愚與比。", "友賢實難，幸然後值。", "不幸友愚，與無孰利。", "諂笑傾辟，韜情晦實。", "測心獻計，因隙投策。"]'),
('4999da60-db47-4c44-81af-7ad5fbe5429c','種菊','張耒','宋','宋诗','song-poetry','','[]','何馨香之芬敷兮，昌綠葉而紫莖。',277,'全唐诗/poet.song.64000.json','["何馨香之芬敷兮，昌綠葉而紫莖。", "是其名爲菊兮，爰植予之中庭。", "性清平而不躁兮，味甘爽而充烹。", "當秋露之慘凄兮，舒煌煌之華英。", "色正而麗兮，氣芬以清。", "純靜秀潔兮，族茂羣榮。", "採食以時兮，天和以寧。", "穎輕竅達兮，瞳子清明。", "散敗流濁兮，風宣滯行。", "仙聖所餌兮，屏除臭腥。", "久嗜不廢兮，將延爾齡。", "嗟予生兮，蹇薄煩冥。", "憂饑畏寒兮，微祿以生。", "終曷歸兮，山林是營。", "膏粱鼎食兮，方丈縱橫。", "炙熊之蹯兮，龍醢羊羹。", "彼得有命兮，吾奚爾榮。", "惟茲佳菊兮，野實以生。", "採擷咀食兮，薦俎盈登。", "求之孔易兮，世焉莫爭。", "我有久疾兮，壅塞煩昏。", "支節堅痹兮，氣閼於元。", "憊不能支兮，外壅中乾。", "疥癬得志兮，蟯蛔伏蟠。"]'),
('0582e79c-4e54-4b28-ba95-fabfe80593f9','逐蛇','張耒','宋','宋诗','song-poetry','','[]','嗟堯之時兮大水滂，橫潰四海兮包陵岡。',436,'全唐诗/poet.song.64000.json','["嗟堯之時兮大水滂，橫潰四海兮包陵岡。", "蕩流湧汩兮周無防，龍騰蛇奔兮嬉以狂。", "腥鱗頑鬣兮更披猖，城居穴處兮亂厥常。", "頹蟲糾結兮肆害戕，陸盤淵據兮傲不臧。", "朋屯黨集兮蕃以昌，穿穴噬囓兮民盡傷。", "下民既病兮帝弗康，黄熊幽殛兮羽山陽。", "乃命伯禹兮行四方，乘高趨卑兮陵復航。", "鑿山疏源兮導河江，萬水下走兮來洋洋。", "經畫九野兮興農桑，驅龍放蛇兮屏諸荒。", "焚山燎野兮無遺芒，野巢窟居兮保厥疆。", "敢有弗率兮斷爾吭，伯益作志兮稽妖祥。", "帝虞耄勤兮黜予商，天授神禹兮夏是王。", "九牧作貢兮金鑑鍠，大冶鼓鑄兮騰精鋩。", "巖巖九鼎峙且剛，奇形詭質兮走與翔。", "鱗毛羽倮兮兮雜短長，求情抉態兮幽微彰。", "制馭百怪兮嚴紀綱，獸蟲人鬼兮安其鄉。", "殊宮別域兮異存亡，曷爲茲蛇兮宅我居。", "妖頑堅老兮傲驅除，深潜居此兮坦無虞。", "下飲我沼兮稍林株，朱眸丹舌兮玄鱗膚。", "恍惚遽速兮疑有無，居者畏避兮行者徐。", "險奪我圃兮駭我徒，盜竊祭禱兮欺羣愚。", "我咨爾蛇兮潜山而穴野，陰蟠遠伏兮與人乎異舍。", "冬居夏游兮時以行，食爾之食兮朋爾朋。", "儧亂我居兮常失經，叛棄爾守兮帝有刑。"]'),
('1fbf9833-288b-4d6e-a7f1-4553b5e1d8ab','登高','張耒','宋','宋诗','song-poetry','','[]','懷不展兮居無聊，默誶語兮浩長謠。',551,'全唐诗/poet.song.64000.json','["懷不展兮居無聊，默誶語兮浩長謠。", "寫我心兮登彼高，陟萬仞兮捫九霄。", "命清風兮披浮雲，瞰四荒兮視天垠。", "大海蕩潏兮潜龍鯤，吐吞日月兮制明昏。", "醖釀元氣兮函星辰，羽載四海兮芥浮坤。", "四岳列峙兮嵩中蹲，牽連脈絡兮子復孫。", "草蔓木布兮升降如朋，障南蔽北兮東散西分。", "如掌列塊兮盤羅豆罇，黄流中貫兮發源崑崙。", "東騖大海兮縈如繚紳，南方炎炎兮火之所宅。", "朱鳥屹峙兮丹膺絳翮，騫飛以翔兮煇煌爛赫。", "從擁萬羽兮紛羅羽翼，煌煌尊嚴兮有斗在北。", "升降玉都兮運量帝側，呼吸陰陽兮秉持禍福。", "真仙逍遙兮澹不可挹，西有王母兮戴勝穴居，壽歷萬古兮忘終泯初。", "超遼恍惚兮獨與道俱，驂友日月兮羣靈走趨。", "既又左而東顧兮觀大明之始生，震沸九淵兮麗天升精。", "披攘羣陰兮重幽昭明，有神司馭兮朱裳絳纓。", "呼造物以致問兮吾將考乎太初，彼天地其孰始兮日與月其代除。", "四荒漫其何極兮人胡爲而中居，火何爲而南宅兮水孰使其在北。", "安知東之主生兮西配刑而主殺，斗建寅而氣分兮疇爲四時之消息。", "世徒知其已然兮遂推類而立說，彼厥初其誰造兮孰布施而殊別。", "抑其不得不然兮或者私智之所設，將忽然而自爾兮遂已成而不可絕。", "造物爲余究察兮曰此曷可以言陳而意悉，彼混沌之一氣兮吾不知誰合而爲一。", "忽洞達而兩分兮夫亦安知其誰闢，爰升清而降濁兮水赴陰而火陽。", "東升氣而敷生兮西或成而害戕，强名之曰自然兮曷足以究其必至。"]'),
('3c0dd378-2c82-48b5-b100-042b24d2e51f','和歸去來詞','張耒','宋','宋诗','song-poetry','','[]','歸去來兮，行世不偶予曷歸。',346,'全唐诗/poet.song.64000.json','["歸去來兮，行世不偶予曷歸。", "其出無所爲喜兮，舍去而何悲。", "眄一世之無與兮，古之人逝莫追。", "求不疚於予義兮，又奚恤餘子之是非。", "彼好惡之罔極兮，或顛倒其裳衣。", "顧吾涉之已深兮，愧哲人之見微。", "吾歸甚安，無所事奔。", "既守吾室，又杜吾門。", "一氣孔神，於中夜存。", "納至和於靈根兮，挹天醖於玄尊。", "既充溢於幽闕兮，亦粹然而見顔。", "往有坎而茲夷兮，昔或危而今安。", "將從化人於西域兮，面藏吏於函關。", "將以一世爲芻狗兮，廢與興吾厭觀。", "彼福禍之一源兮，必茲出而茲還。", "彼自以爲無隙兮，何異夫石槨之宋桓。", "歸去來兮，吾悲夫斯人不返兮，豈招仙聖與之游。", "昔惠我以好音，忽遠去而莫求。", "予曷異於世人兮，初爲哽塞而增憂。", "彼錢鎛則深藏兮，盍視夫已墾之田疇。", "萬古芸芸，共逝一舟。", "半夜而失，旦號其丘。", "畏達觀之誚予，涕已泣而不流。", "悟榮名之取憎兮，善斯人之獲休。"]'),
('11f4fbc2-ec61-4df6-9b45-abcefee34975','哭下殤','張耒','宋','宋诗','song-poetry','','[]','醫之不得其方耶，抑其命有短長耶。',92,'全唐诗/poet.song.64000.json','["醫之不得其方耶，抑其命有短長耶。", "獨爾能使吾悲若此耶，抑爲父者皆愛其子耶。", "蒼顱夷顙，秀眉清目。", "今其存亡，其猶有鬼也。", "使無物，則吾復何思。", "其尚有知也，則夫荒屋野寺。", "風霜雨露，食息誰汝視也。"]'),
('2c5b7951-1c04-40cd-b74e-434ff9869c14','休日同宋遐叔詣法雲遇李公擇黄魯直公擇烹賜茗出高麗盤龍墨魯直出近作數詩皆奇絕坐中懷无咎有作呈魯直遐叔','張耒','宋','宋诗','song-poetry','','[]','休日不造請，出遊賢友同。',144,'全唐诗/poet.song.64000.json','["休日不造請，出遊賢友同。", "城南上人者，宴坐花雨中。", "金貌散香霧，寶鐸韵天風。", "鳥語演寶相，飯香悟真空。", "尚書三二客，浄社繼雷宗。", "黄子發錦囊，句有造物功。", "握中一寸煤，海外千年松。", "誰降午睡魔，賜茗屠團龍。", "晁子卧城西，咫尺不可逢。", "豈無坐中客，終覺少此公。", "歸帽見新月，撲衫暮塵紅。", "困眠有餘想，却聽寺樓鐘。"]'),
('39c155d0-063b-4370-9a7c-3178183fbcaf','掛虎圖於寢壁示秸秠','張耒','宋','宋诗','song-poetry','','[]','畫工出幻事，縞素發原藪。',96,'全唐诗/poet.song.64000.json','["畫工出幻事，縞素發原藪。", "蕭蕭白茅低，凜凜北風走。", "眈然老於菟，舉步安不驟。", "目光炯雙射，怒吻呀欲受。", "彼彪擲其旁，文彩淡初就。", "雖然竊形似，已足走百獸。", "煩君衛吾寢，振此蓬蓽陋。", "坐令盜肉鼠，不敢窺白晝。"]'),
('0f9af3a0-21d5-4304-92ed-30e0877052d3','神運殿望香爐天池等峰晚宿官廳明日早發','張耒','宋','宋诗','song-poetry','','[]','遠公不出山，坐受天龍供。',168,'全唐诗/poet.song.64000.json','["遠公不出山，坐受天龍供。", "地祇敢愛寶，木石親輸送。", "巖巖千年屋，山立屹不動。", "風雲宿修梁，星斗近華棟。", "亭亭碧香爐，薝蔔時自涌。", "五雲嚴擁衛，天樂下鸞鳳。", "神池閟寶象，光怪發巖洞。", "誰能陟其巔，手攬湖龍鞚。", "東堂黄金藏，龍像儼環拱。", "蕭條亡國輦，拙樸昔誰用。", "掃堂爲一睡，清極乃無夢。", "思歸戒晨發，結束勤僕從。", "鴻鐘振林莽，月落朝嵐重。", "再往墮渺茫，猿鶴應嘲諷。"]'),
('9f2535bb-70a2-4c24-b045-2db8a4e269d5','贈張公賁','張耒','宋','宋诗','song-poetry','','[]','我昔爲諸生，奉書諫議公。',288,'全唐诗/poet.song.64000.json','["我昔爲諸生，奉書諫議公。", "後來辱稱奬，禮數賓客同。", "决科甫弱冠，年少氣如虹。", "歸來陪後乘，不責醉後恭。", "孤舟梁宋郊，旅態萃百窮。", "拜公睢陽府，笑語若春風。", "人事不可期，俯仰異吉凶。", "平生丹竈術，馬鬣哭新封。", "十年得吾弟，懷舊涕沾胸。", "清平守家法，眉宇肖德容。", "交臂是非外，爲僚兄弟中。", "東軒語長夏，葵竹羅青紅。", "西舍雪夜歡，玉顔醉瑶鍾。", "欲飲徑相就，三更叱閽翁。", "鯨吸絕遺滴，山頹信傾峰。", "搜抉盡醤茹，楂梨倒筐籠。", "通宵兩沈醉，午起頭如蓬。", "人生定當爾，事去挽驚鴻。", "河梁繫君馬，一笑喜相逢。", "憐君碧紗幌，夜淚哭葦叢。", "我方困虀鹽，酸寒官辟雝。", "同尋舊游地，塵壁罥絲蟲。", "啼鳥古寺間，夏陰小園空。", "酒市逢好好，琵琶失𤫩瓏。"]'),
('27e5f22a-c7cf-4bfe-ac49-458745e205a3','離黄州','張耒','宋','宋诗','song-poetry','','[]','扁舟發孤城，揮手謝送者。',96,'全唐诗/poet.song.64000.json','["扁舟發孤城，揮手謝送者。", "山回地勢卷，天豁江面瀉。", "中流望赤壁，石脚插水下。", "昏昏烟霧嶺，歷歷漁樵舍。", "居夷實三載，鄰里通假借。", "別之豈無情，老淚爲一洒。", "篙工起鳴鼓，輕艣健於馬。", "聊爲過江宿，寂寂樊山夜。"]'),
('924bffcb-b24d-486d-a97e-d3f80d98d604','宿樊溪','張耒','宋','宋诗','song-poetry','','[]','黄州望樊山，秀色如可攬。',96,'全唐诗/poet.song.64000.json','["黄州望樊山，秀色如可攬。", "扁舟橫江來，山脚繫吾纜。", "大川失洶涌，淺水澄可鑒。", "北風吹疏雨，夜枕舟屢撼。", "齊安不可望，滅沒孤城暗。", "奔流略溪口，龍蜃屢窺瞰。", "平生千金質，戒懼敢忘暫。", "茲遊定何名，耿耿有餘念。"]'),
('990d0ce8-89d7-405f-88e7-d40f1cb51f3a','道士磯','張耒','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','匡廬奠九江，苗裔遍南服。',96,'全唐诗/poet.song.64000.json','["匡廬奠九江，苗裔遍南服。", "橫江蔽原野，內外實一族。", "危磯插江生，石色擘青玉。", "蛟龍穴亂石，猱玃在喬木。", "我行季冬月，江蹟在山腹。", "扁舟如鏡面，清浄不可觸。", "躋攀既不可，千古長幽獨。", "緬想邃古初，巢居戒樵牧。"]'),
('01e76d7f-19ad-4e19-bfce-52a7745c8596','離樊口宿巴河遊馬祈寺','張耒','宋','宋诗','song-poetry','','[]','扁舟下樊溪，江南正清瀉。',108,'全唐诗/poet.song.64000.json','["扁舟下樊溪，江南正清瀉。", "曉登巴河岸，極目望春野。", "步尋修竹寺，古木爭偃亞。", "云昔孫仲謀，刑牲致師禡。", "雄圖邈已矣，英概足悲咤。", "石梯造雲霧，丹白開廣厦。", "山僧安寂寞，畏冷不出舍。", "勞生遇閒境，頓使我心寫。", "晚江平若席，風勢欲相借。"]'),
('4897e78b-e358-4c60-90ad-f633d545b6d0','龜陵灣阻風三日遙禱孤山而風止','張耒','宋','宋诗','song-poetry','','[]','積水多疾風，三日阻我舟。',108,'全唐诗/poet.song.64000.json','["積水多疾風，三日阻我舟。", "天寒波濤惡，岸窟騰龍虬。", "五更船篷鳴，冷風入衾裯。", "平明諸山雪，爛漫鋪琳球。", "篙工笑相顧，拍拍我船頭。", "水魄小孤神，霧鬢橫星眸。", "倉卒禱即應，知我厭滯留。", "稍晴景物好，柳色含新柔。", "春風我故舊，迎我入東州。"]'),
('db3e0862-0c17-4f29-a4b5-403cae630eca','自離富池凡三禱順濟龍求便風皆獲應又風日清霽舟行安穩委曲如所欲感而成詩','張耒','宋','宋诗','song-poetry','','[]','旗尾指船頭，篙工告風便。',144,'全唐诗/poet.song.64000.json','["旗尾指船頭，篙工告風便。", "張帆弛雙艣，去勢如脫箭。", "船傍兩高山，過目若流電。", "波平船穩馳，客寢兀未變。", "吾聞西江龍，神力回宇縣。", "往來萬夫禱，正直巧獲願。", "嗟予何所恃，誠確無所薦。", "神豈哀我窮，有賜不待獻。", "乃知人窮我，本不坐神譴。", "人間事若異，未易以言辯。", "坐令千里遠，近若在几研。", "慚非謝宣城，攫筆賦浄練。"]'),
('771ec34b-501e-4706-8c2c-a7b82150b152','出山','張耒','宋','宋诗','song-poetry','','[]','青山如君子，悅我非姿媚。',120,'全唐诗/poet.song.64000.json','["青山如君子，悅我非姿媚。", "相逢一開顔，便有論交意。", "今晨决然去，摻若執我袂。", "謂山無見留，此事寧久置。", "道邊青髮翁，下有白玉髓。", "斸之龍蛇窟，自足飽吾世。", "平生耽幽獨，乃若忘朝市。", "一官等塵垢，安得敗成計。", "草堂醉老子，虎溪大開士。", "寄語二主人，爲留三畝地。"]'),
('dc61c0a7-8a08-42b0-af6c-747f37a6dadc','朝雨','張耒','宋','宋诗','song-poetry','','[]','幽居感節物，僧舍值朝凉。',96,'全唐诗/poet.song.64000.json','["幽居感節物，僧舍值朝凉。", "空簷落寒雨，滴滴響秋堂。", "低飛林間翮，濕羽不能翔。", "危葉別故枝，幽花泫晚芳。", "悠悠清夜眠，促織催朝光。", "日月愴已徂，吾行獨迷方。", "采采幽圃蘭，歲晚日馨香。", "君子健明德，勿爲兒女傷。"]'),
('57c5f1de-89d5-4489-84c2-6aeef15d5ae9','離陽翟','張耒','宋','宋诗','song-poetry','','[]','驅車發潁川，回望失嵩少。',120,'全唐诗/poet.song.64000.json','["驅車發潁川，回望失嵩少。", "霜氣塞層空，黯澹寒日曉。", "原田際天平，百里見飛鳥。", "累累道傍丘，石獸卧衰草。", "不知誰氏碑，剝裂偶未倒。", "支離見隸字，書带漢筆妙。", "遺墳不可問，文彩竟何效。", "永年恃金石，此計久可笑。", "昔遊已三歲，存歿傷懷抱。", "飽諳人世憂，安得身不老。"]'),
('218769bb-94f1-4ec2-86e1-3363ec4024f9','次潁川','張耒','宋','宋诗','song-poetry','','[]','許昌古名都，氣象良未替。',120,'全唐诗/poet.song.64000.json','["許昌古名都，氣象良未替。", "客子遠道來，塵埃滿襟袂。", "黄昏造孤驛，買飯嚙枯胾。", "庭寬蟾蜍高，霜氣徹寒被。", "頼携朱提杯，可具一飯費。", "無人勸我酌，孤獨伴客醉。", "笙簫誰家樓，語笑月中市。", "何人不行樂，而我獨涕淚。", "夜長更漏稀，風急鼓鼙駛。", "天明卷席去，行止隨所值。"]'),
('0ef2cdf1-cb1f-43f8-87c4-766cff0a7378','昭陵六馬唐文皇戰馬也琢石象之立昭陵前客持石本示予爲賦此','張耒','宋','宋诗','song-poetry','','[]','天將剗隋亂，帝逢六龍來。',144,'全唐诗/poet.song.64000.json','["天將剗隋亂，帝逢六龍來。", "森然風雲姿，颯爽毛骨開。", "飆馳不及視，山立儼莫回。", "長鳴馳八表，擾擾萬駑駘。", "秦王龍鳳姿，魚鳥不足摧。", "腰間大白羽，中物如風雷。", "區區數豎子，縛取如提孩。", "手持掃天帚，六合無塵埃。", "艱難濟大業，一一非常材。", "惟時六驥足，績與英衛陪。", "功成鏘八鸞，玉輅行天街。", "荒凉昭陵闕，古石埋蒼苔。"]'),
('0a1a83a5-eec1-4618-b78a-b17a96adeaa2','同楊十二緱氏寺宿草酌張正民秀才見訪','張耒','宋','宋诗','song-poetry','','[]','契闊千里別，惻愴難具言。',144,'全唐诗/poet.song.64000.json','["契闊千里別，惻愴難具言。", "殷勤一宵語，願子未即眠。", "空堂燈火青，旅褐借僧氈。", "勞勞一杯酒，不解道路寒。", "經年相從樂，既別亦茫然。", "人間事盡爾，聚散亦何歎。", "但悲多難身，尚獲朋友歡。", "間關百憂中，一笑有萬錢。", "張子年未冠，已雄羣少年。", "巉巉坐我側，紫眸秀雙顴。", "壯志激衰懦，清談破愁煎。", "天明即分散，奈此情悁悁。"]'),
('e4589b59-d451-46c3-80b1-86bdf75e0c5d','初到都下供職寄黄九','張耒','宋','宋诗','song-poetry','','[]','千里不相見，勞勞復何辭。',96,'全唐诗/poet.song.64000.json','["千里不相見，勞勞復何辭。", "不遠一城中，耿耿令我思。", "僦舍酒家樓，推壚卷其旗。", "鼠壤敗晨炊，守翁噪羣兒。", "馬傍挾兩羸，雙踵待刻移。", "五日長安塵，故山夢中歸。", "何以洗我心，望君青松姿。", "懷情久不吐，古屋弦悲詩。"]'),
('4906f423-27f7-4a37-9ece-faff84e6b82e','次韵魯直夏日齋中','張耒','宋','宋诗','song-poetry','','[]','文章慚骯髒，談舌罷雋永。',72,'全唐诗/poet.song.64000.json','["文章慚骯髒，談舌罷雋永。", "年來屏百事，但願兩耳靜。", "黄公安禪室，不覺在市井。", "客來飽清風，可是徒造請。", "犧尊與社樗，妄計幸不幸。", "願君妙觀察，金門等雲嶺。"]'),
('450e3bfd-6115-4e23-b444-a448ae2972b7','晚歸寄无咎二首  其一','張耒','宋','宋诗','song-poetry','','[]','雨氣入古屋，薄帷生夜清。',48,'全唐诗/poet.song.64000.json','["雨氣入古屋，薄帷生夜清。", "想君擁鼻坐，端學苦吟生。", "泥深欺我馬，歸卧日半楹。", "浩然有奇想，非子定誰評。"]'),
('a465f294-fb31-4a34-83a4-21d4221698c1','晚歸寄无咎二首  其二','張耒','宋','宋诗','song-poetry','','[]','屋東雲移山，屋西日半壁。',48,'全唐诗/poet.song.64000.json','["屋東雲移山，屋西日半壁。", "餘天一劍清，遠雨萬絲白。", "官事癡可了，未遭官長責。", "惟應晁夫子，不可別頃刻。"]'),
('dfe02449-e3b3-4453-ad50-419726f20a2c','送呂際秀才南歸','張耒','宋','宋诗','song-poetry','','[]','咽咽幽谷泉，蕭蕭秋竹風。',144,'全唐诗/poet.song.64000.json','["咽咽幽谷泉，蕭蕭秋竹風。", "豈不愛孤潔，但傷愁且窮。", "呂子南國秀，滄溟貯其胸。", "出試輒不偶，低頭避兒童。", "離家五千里，客飯苦不豐。", "冷落卧寒齋，苦吟和秋蟲。", "昨者投我詩，九歎閱未終。", "欲知作者心，但視讀者容。", "文章出貧賤，此事今古同。", "但願子富貴，不願文日工。", "今日告我別，出門若驚鴻。", "各在天一方，何當復相逢。"]'),
('d85b79eb-ab2b-486e-a757-23f068d6425f','西山寒溪','張耒','宋','宋诗','song-poetry','','[]','茲行頗閒暇，聊此山水間。',276,'全唐诗/poet.song.64000.json','["茲行頗閒暇，聊此山水間。", "幸有所携人，臭味同一源。", "山溪並修澗，嘉木間蒲蓮。", "杉松鳴古剎，始覺此溪寒。", "孤亭出屋背，石磴相牽攀。", "迎客窮道人，俯僂鬚眉斑。", "釋子具粗糲，雖貧有餘歡。", "午登西山去，路作九曲彎。", "山禽慣不驚，夏木秀且繁。", "緬懷紫髯公，奠玉祠天壇。", "豪强有遺韵，興廢無留觀。", "空巖一泓泉，引予掏清甘。", "至人悲熱惱，遺此消昏煩。", "我茶非世間，天上蒼月團。", "爲爾惜不得，烹瀹澆晨餐。", "深谷晚易陰，快雨時斑斑。", "但見夾道松，龍髯濕蒼顔。", "念我亦閒人，屏居閉柴關。", "不使倒珠玉，濟我胸中慳。", "之官亦漫浪，遇勝却盤桓。", "平生據頑鈍，信命傲憂患。", "言歸徒旅疲，就蔭休征鞍。", "却視來時舟，一葉繫荒灣。"]'),
('7bdc12ec-44bd-4567-b39e-dcbf8839094c','送張天覺使河東席上分題得將字','張耒','宋','宋诗','song-poetry','','[]','張侯蜀都秀，玉立身堂堂。',96,'全唐诗/poet.song.64000.json','["張侯蜀都秀，玉立身堂堂。", "手持明光節，六月登太行。", "三晉雄中夏，朔方臨大荒。", "傳聲賢使者，父老相扶將。", "控弦百萬戶，十年廢耕桑。", "但使把鋤犂，自然息桁楊。", "主人延閣老，別酒泛蘭觴。", "寄聲梁諫議，欲試紫參方。"]'),
('c7e94c8e-2d58-4dc8-87cc-299971888a33','答仲車','張耒','宋','宋诗','song-poetry','','[]','先生居山陽，時事不挂齒。',48,'全唐诗/poet.song.64000.json','["先生居山陽，時事不挂齒。", "讀書逾五車，不肯著一字。", "今朝苦歎嗟，告我將老矣。", "我意與子殊，欲去依禪子。"]'),
('efc4f3d7-4558-45af-abc2-15cce4acdd74','和仲車元夜戲述','張耒','宋','宋诗','song-poetry','','[]','華燈耀廣陌，皎月臨重城。',48,'全唐诗/poet.song.64000.json','["華燈耀廣陌，皎月臨重城。", "惟我二三子，柴門通夜扃。", "展書對明燭，濁酒徐徐傾。", "崢嶸千萬慮，一醉皆能平。"]'),
('c401cdf0-b471-4d7b-b139-5930a46f5066','和魯直','張耒','宋','宋诗','song-poetry','','[]','濟物非僕僕，功名愧無心。',48,'全唐诗/poet.song.64000.json','["濟物非僕僕，功名愧無心。", "倚市安能美，汲泉不厭深。", "老人夙有尚，瓶缽好叢林。", "安能紅塵裏，徒使老駸駸。"]'),
('73581b3b-d2ca-4c30-8a27-9c51f1b1f9e0','書館直舍','張耒','宋','宋诗','song-poetry','','[]','紫禁斷人聲，蓬山轉春日。',96,'全唐诗/poet.song.64000.json','["紫禁斷人聲，蓬山轉春日。", "樓外晚鼓傳，城陰衛番出。", "循除擷新秀，紅紫間疏密。", "倚天黄金闕，龍虎氣鬰律。", "明時賦鉛槧，寓直守編帙。", "疏閒謝裨補，歲月感飄忽。", "謝公山林賞，不爲軒冕屈。", "體道無朝野，達情慚利物。"]'),
('a5b1581a-2172-43e2-a7c8-3fc028cdc896','宣城至日謁天慶觀行香呈郡僚','張耒','宋','宋诗','song-poetry','','[]','溪山慘殘歲，况乃值深冬。',96,'全唐诗/poet.song.64000.json','["溪山慘殘歲，况乃值深冬。", "清晨率其屬，肆禮凝琳宮。", "漠漠冒原露，凄凄隔水風。", "南方異氣候，霜葉未全紅。", "忽憶簪史筆，早趨闢蒼龍。", "拜舞東閣上，佳氣鬰葱葱。", "談笑出右掖，交游盡英雄。", "老大心已矣，依然魂夢中。"]'),
('84922dd3-0d7c-4bbe-96a0-b50c828c523b','秋日獨酌懷榮子邕','張耒','宋','宋诗','song-poetry','','[]','新秋一盃酒，風雨早凉天。',96,'全唐诗/poet.song.64000.json','["新秋一盃酒，風雨早凉天。", "眷言西鄰友，咫尺莫能前。", "豈無病羸馬，泥滑不勝鞭。", "端居何爲者，落寞掩書眠。", "高柳颯已疏，碧草留餘鮮。", "衰懷感徂節，客舍悲流年。", "孤吟誰與和，獨酌還醒然。", "新晴野路乾，期子南山邊。"]'),
('e7e8e9fe-06a9-4b94-8d5b-e2369eec88d2','夜初凉','張耒','宋','宋诗','song-poetry','','[]','庭木舞風雨，清秋來我堂。',96,'全唐诗/poet.song.64000.json','["庭木舞風雨，清秋來我堂。", "衾裯偃宵寐，燈火照新凉。", "昔我來清潁，庭花有晚芳。", "坐看桐葉暗，已近菊枝黄。", "歲月忽流駛，形骸變老蒼。", "淹留應有命，通塞詎能量。", "寂歷年華晚，優游永日長。", "憂時非我事，黄卷有虞唐。"]'),
('54778617-dd2f-40cb-8cbe-b53f8eb4fbe8','題陸羽祠堂兼寄李援援有詩殊佳二首  其一','張耒','宋','宋诗','song-poetry','','[]','陸子不可招，寥寥風月魂。',72,'全唐诗/poet.song.64000.json','["陸子不可招，寥寥風月魂。", "空堂掩遺像，幸此配老禪。", "舉世人澆薄，云誰知子賢。", "竟陵樵牧地，陳迹豈復存。", "我欲歌子詩，三歎撫無弦。", "瓦登薦秋菊，酌此石井泉。"]'),
('bc0b9e7b-b26d-4164-8c65-fa66730428f1','題陸羽祠堂兼寄李援援有詩殊佳二首  其二','張耒','宋','宋诗','song-poetry','','[]','清詩弔陸子，味若堂下泉。',48,'全唐诗/poet.song.64000.json','["清詩弔陸子，味若堂下泉。", "陸子骨已朽，青松代之言。", "松亦安能言，風至時蕭然。", "至談非牙舌，陸子意已傳。"]'),
('0f5ff29c-884d-4c56-9518-19a31729e89c','萬松亭有感','張耒','宋','宋诗','song-poetry','','[]','微雨濕青松，松間多好風。',48,'全唐诗/poet.song.64000.json','["微雨濕青松，松間多好風。", "翠光濃欲滴，對舞千蛟龍。", "可惜青玉釵，道邊委蒿蓬。", "幽人不汝棄，應有綠毛翁。"]'),
('06397ee5-33e2-421e-8641-1efff4c3cc52','今旦','張耒','宋','宋诗','song-poetry','','[]','今旦寒氣至，晨坐進一杯。',96,'全唐诗/poet.song.64000.json','["今旦寒氣至，晨坐進一杯。", "一杯未能已，三酌竟空罍。", "我有胸臆事，欲言誰使陪。", "往往中夜歎，鬰結無由開。", "頼此樽中君，破悶有後來。", "時時從之遊，報我以歡咍。", "古國多寒肴，老妻治炮煨。", "誰云一日富，此價萬瓊瑰。"]'),
('93b5f8c8-dbdf-43f5-9008-7fda81b174a3','摘梅花數枝插小瓶中輒數日不謝吟玩不足形爲小詩','張耒','宋','宋诗','song-poetry','','[]','疏梅插書瓶，潔白滋媚好。',48,'全唐诗/poet.song.64000.json','["疏梅插書瓶，潔白滋媚好。", "微香悠然起，鼻觀默自了。", "秀色定可憐，仙姿寧解老。", "禪翁心土木，對此成魔惱。"]'),
('dbf382e2-d1d9-48ab-a276-5387ece2a5dc','霜後步西園','張耒','宋','宋诗','song-poetry','','[]','濃霜失暄妍，短日淡無色。',72,'全唐诗/poet.song.64000.json','["濃霜失暄妍，短日淡無色。", "回風振中園，摇落聲策策。", "草根饑鳥啄，飛舞時嘖嘖。", "野荒無遺粒，卒歲將何食。", "鮮鮮西牆下，幽草弄寒碧。", "四時不吾欺，聊假汝頃刻。"]'),
('6373d3c2-064d-4b70-a160-39b99c3ca788','冬懷三首  其一','張耒','宋','宋诗','song-poetry','','[]','悲笳奏已罷，落月在西壁。',72,'全唐诗/poet.song.64000.json','["悲笳奏已罷，落月在西壁。", "卧聞中林鳥，先曉鳴嘖嘖。", "爾求亦易供，固合事安息。", "夜歸陵旦起，何爾更勞役。", "乾坤擾萬物，不使輕有獲。", "無求良獨難，何以休吾力。"]'),
('ad1dec34-7b88-495d-8bcd-f97a7f6d3576','冬懷三首  其二','張耒','宋','宋诗','song-poetry','','[]','揚雄老不遇，寂寞玩文史。',48,'全唐诗/poet.song.64000.json','["揚雄老不遇，寂寞玩文史。", "厠身虎狼間，乃卒脫其死。", "中恬遺外慕，獨樂異衆喜。", "但有載酒人，何用求知己。"]'),
('0fa727af-58bd-43e0-a9d7-81291fb2cc35','冬懷三首  其三','張耒','宋','宋诗','song-poetry','','[]','年來百事懶，惟樂靜中趣。',48,'全唐诗/poet.song.64000.json','["年來百事懶，惟樂靜中趣。", "天寒無來客，終日常閉戶。", "進取乏時才，窮通有天數。", "委身付造物，已矣隨所遇。"]'),
('a94fa11e-bee8-442b-90c4-420867bbe799','感春三首  其一','張耒','宋','宋诗','song-poetry','','[]','東風吹桃李，花落已滿地。',48,'全唐诗/poet.song.64000.json','["東風吹桃李，花落已滿地。", "摇摇新柳枝，薄蔭纔可芘。", "誰云同一時，榮謝兩異意。", "由來何足較，要之歸一致。"]'),
('6a449605-472a-4202-9dd2-f9fb8c76b764','感春三首  其二','張耒','宋','宋诗','song-poetry','','[]','默坐不復出，浮雲作朝陰。',48,'全唐诗/poet.song.64000.json','["默坐不復出，浮雲作朝陰。", "離離簷間花，隨雨下故林。", "物色一如此，朱顔坐凋侵。", "自歌陽春曲，吾不待知音。"]'),
('0bdd61c8-662c-4ea8-847e-c04ce0a9c03c','感春三首  其三','張耒','宋','宋诗','song-poetry','','[]','午日步西園，繁花亂相照。',48,'全唐诗/poet.song.64000.json','["午日步西園，繁花亂相照。", "夭夭海棠枝，顧我如欲笑。", "殷紅點輕素，含吐皆窈窕。", "持贈東鄰子，願言論久要。"]'),
('9a04bdf7-c92a-44a6-859f-306f25d216f8','春日雜詩六首  其一','張耒','宋','宋诗','song-poetry','','[]','啼鳥喚我覺，簷日行且午。',48,'全唐诗/poet.song.64000.json','["啼鳥喚我覺，簷日行且午。", "纍纍出葉鶯，庭雀鳴欲乳。", "妻兒病酒睡，鷄犬樂其侶。", "風光不我違，舍醉何有度。"]'),
('0fbb9767-2c36-4953-9d7c-2705a383c137','春日雜詩六首  其二','張耒','宋','宋诗','song-poetry','','[]','東風入我園，落落如急霰。',48,'全唐诗/poet.song.64000.json','["東風入我園，落落如急霰。", "感之復携酒，撫樹爲三歎。", "離離牆間草，滿地不可踐。", "陰陽本無情，榮謝欲誰怨。"]'),
('5675cdc1-9a96-4ac4-b5f1-294cdf3d423f','春日雜詩六首  其三','張耒','宋','宋诗','song-poetry','','[]','春晏百草秀，野花無復名。',48,'全唐诗/poet.song.64000.json','["春晏百草秀，野花無復名。", "悲哉桃李闌，念此聊掇英。", "翩翩雙飛蝶，天靜午日晴。", "悲憂浪自苦，有酒但知傾。"]'),
('b6c7ab7a-e30d-4a69-bf13-e4d537951c07','春日雜詩六首  其四','張耒','宋','宋诗','song-poetry','','[]','堂南老榆柳，清陰漸交映。',48,'全唐诗/poet.song.64000.json','["堂南老榆柳，清陰漸交映。", "飄飄風花乾，渥渥雨葉盛。", "鳥鳴日方遲，客去門逾靜。", "自無濟世略，耿耿欲誰省。"]'),
('5cfa1e36-5960-4454-80d5-3dad9afa0d89','春日雜詩六首  其五','張耒','宋','宋诗','song-poetry','','[]','三月行復至，青春坐侵尋。',48,'全唐诗/poet.song.64000.json','["三月行復至，青春坐侵尋。", "飛花去寂寂，新葉來駸駸。", "白日照芳草，荒園亂鳴禽。", "朱顔任自老，安事累吾心。"]'),
('1ae61681-972d-4f6a-bce7-7ea93e44d894','春日雜詩六首  其六','張耒','宋','宋诗','song-poetry','','[]','東風忽無情，吹我園中花。',48,'全唐诗/poet.song.64000.json','["東風忽無情，吹我園中花。", "繁紅與艷紫，零落委泥沙。", "鳴鳥亦何事，啾啾竟諠譁。", "須知盛已極，委棄欲誰嗟。"]'),
('ac12be93-940a-4e73-80ea-1018c7d57514','官閒','張耒','宋','宋诗','song-poetry','','[]','官閒吏歸早，歲晏寒欲盛。',48,'全唐诗/poet.song.64000.json','["官閒吏歸早，歲晏寒欲盛。", "槐稀庭日多，鳥下人語靜。", "幽花破寒色，過雁驚秋聽。", "酒賤莫厭沽，北風行欲勁。"]'),
('87df703c-c81e-44c7-8e85-779207f15f99','秋池','張耒','宋','宋诗','song-poetry','','[]','平生落寞意，况此秋池側。',48,'全唐诗/poet.song.64000.json','["平生落寞意，况此秋池側。", "寒水靜無波，衰荷委餘碧。", "蕭蕭動風鬢，照影感新白。", "來往雙浴鳬，爾生真自得。"]'),
('bd60ab55-4a8f-4d7f-b930-f0d50443f13e','雜咏三首  其一','張耒','宋','宋诗','song-poetry','','[]','隆中卧龍公，平昔事耕釣。',48,'全唐诗/poet.song.64000.json','["隆中卧龍公，平昔事耕釣。", "無言顧同儕，高視獨長嘯。", "彼寧惜開口，顧爾非同調。", "何事逢玄德，曹孫一言料。"]'),
('4d6df691-2ab7-465d-8972-69c615e051cd','雜咏三首  其二','張耒','宋','宋诗','song-poetry','','[]','六槐當我庭，春葉密如幄。',48,'全唐诗/poet.song.64000.json','["六槐當我庭，春葉密如幄。", "朝來南風起，已見萎葉落。", "盛衰同時來，豈必待蕭索。", "鄙哉兒女癡，倩倩情所樂。"]'),
('3f57e746-a8d6-404f-a842-452a43ad346c','雜咏三首  其三','張耒','宋','宋诗','song-poetry','','[]','鳥鳴高屋上，饑顧朝求食。',48,'全唐诗/poet.song.64000.json','["鳥鳴高屋上，饑顧朝求食。", "擾擾市井人，日夜衣食迫。", "豈伊理當然，或者養未得。", "我歌南風詩，歸坐還歎息。"]'),
('c1f84354-aab0-49e2-b964-2815b3ef5343','飛雲','張耒','宋','宋诗','song-poetry','','[]','時雨久不施，飛雲作朝陰。',48,'全唐诗/poet.song.64000.json','["時雨久不施，飛雲作朝陰。", "芃芃中原麥，頼此三日霖。", "朝陽忽清霽，披露南山岑。", "雖無濟物跡，膏澤在民心。"]'),
('95d0c4ad-4b31-4b52-8375-3836527293d2','和應之燈蛾','張耒','宋','宋诗','song-poetry','','[]','萬物皆畏死，爾生何獨愚。',48,'全唐诗/poet.song.64000.json','["萬物皆畏死，爾生何獨愚。", "由來附炎熱，鮮不喪其軀。", "淺淺權利客，躚躚輕薄夫。", "高門甚烈火，相勸以奔趨。"]'),
('dc34f176-aa4e-4916-bada-5214813b1c3c','自黄州至巴河遊靈巖寺觀孫仲謀刑馬壇相傳權于此刑馬祀江神遂提師伐壽春云','張耒','宋','宋诗','song-poetry','','[]','喬木隔塵埃，華堂敞深僻。',48,'全唐诗/poet.song.64000.json','["喬木隔塵埃，華堂敞深僻。", "人靜好鳥鳴，睡餘疏雨滴。", "悲愁感蕭瑟，弔古披荒寂。", "尚溯紫髯翁，誓師沉馬璧。"]'),
('d2018a36-6047-447c-81c3-ede1a1739779','雜詩二首  其一','張耒','宋','宋诗','song-poetry','','[]','獨居無與往，况此陰雨天。',48,'全唐诗/poet.song.64000.json','["獨居無與往，况此陰雨天。", "起來復何有，詩書散我前。", "偃卧一榻上，讀書疲復眠。", "經綸負夙志，跌蕩窮吾年。"]'),
('a3374f44-81eb-45a1-b282-c68f8b3a94de','雜詩二首  其二','張耒','宋','宋诗','song-poetry','','[]','高堂斷四聽，鳴雨曉未止。',48,'全唐诗/poet.song.64000.json','["高堂斷四聽，鳴雨曉未止。", "堂空雨聲大，滴滴清我耳。", "朝眠引幽夢，遇我同心子。", "談笑未容周，夢開坐千里。"]'),
('10f8eff4-ff72-46d6-9b9e-a8147fa932dd','搗藥','張耒','宋','宋诗','song-poetry','','[]','指可握而足，臂可攘無他。',48,'全唐诗/poet.song.64000.json','["指可握而足，臂可攘無他。", "何爲勤藥物，杵臼日諠譁。", "指臂何與人，正欲使其佳。", "念此慚吝生，達人其我嗟。"]'),
('858a15fb-f110-4d44-9823-93ad4672020e','烏臼','張耒','宋','宋诗','song-poetry','','[]','烏臼强知曉，譊譊鳴暗天。',48,'全唐诗/poet.song.64000.json','["烏臼强知曉，譊譊鳴暗天。", "我事不須早，援衾且復眠。", "朝暉方聵聵，慘凜蔽清妍。", "且復待午景，負此簷間暄。"]'),
('42de2e49-95f7-4061-8bd1-007952f48402','春林','張耒','宋','宋诗','song-poetry','','[]','春林露如雨，蕭蕭曉花寒。',48,'全唐诗/poet.song.64000.json','["春林露如雨，蕭蕭曉花寒。", "引手攀高紅，微香來鼻端。", "何以比芳潔，置之青玉盤。", "持歸供像佛，相對淡無言。"]'),
('13f856e1-f873-4136-811e-c9750f3f1262','華月','張耒','宋','宋诗','song-poetry','','[]','華月流春宵，散我高林影。',48,'全唐诗/poet.song.64000.json','["華月流春宵，散我高林影。", "披衣步其下，愛此掃地靜。", "吾心方浩然，萬境一澄瑩。", "徙倚玉繩低，寂寥沈遠聽。"]'),
('4c6f517f-76cc-48a5-821b-632bc8761f7f','離楚夜泊高麗館寄楊克一甥四首  其一','張耒','宋','宋诗','song-poetry','','[]','去城未五里，夜纜繫衰柳。',48,'全唐诗/poet.song.64000.json','["去城未五里，夜纜繫衰柳。", "水亭暗風雨，人散聞吠狗。", "平生足羈旅，沉此還往久。", "有感不自知，悽然獨回首。"]'),
('22514168-be68-4d5c-9edf-0b8be532f965','離楚夜泊高麗館寄楊克一甥四首  其二','張耒','宋','宋诗','song-poetry','','[]','水天夕雲重，不雨衣自濕。',48,'全唐诗/poet.song.64000.json','["水天夕雲重，不雨衣自濕。", "夜寒更士語，雞唱舟子急。", "青黄數宿莽，蒼茫暗原隰。", "高城亦何有，倚檣成獨立。"]'),
('86edcaea-a4a9-46b5-8964-7967dd41960e','離楚夜泊高麗館寄楊克一甥四首  其三','張耒','宋','宋诗','song-poetry','','[]','客去水關閉，疏燈亦復收。',48,'全唐诗/poet.song.64000.json','["客去水關閉，疏燈亦復收。", "川鳴半夜雨，卧冷五更秋。", "扁舟已寒暑，冉冉真乘桴。", "一燈照客睡，短夢良悠悠。"]'),
('848529dc-3cca-4aff-a4bf-bc131237c648','離楚夜泊高麗館寄楊克一甥四首  其四','張耒','宋','宋诗','song-poetry','','[]','士師我自出，爽邁凌清秋。',84,'全唐诗/poet.song.64000.json','["士師我自出，爽邁凌清秋。", "年少不飲酒，昏燈夜問囚。", "爾家外大父，聽獄代其憂。", "備饑朝煮飯，驅蚊夜張幬。", "獄成上府時，稽顙呼張侯。", "恕心臨縲紲，相盜以戈矛。", "無令市死厲，請帝號重幽。"]'),
('9fad96fb-ef45-480c-af5a-60bcae207af1','三月小園花已謝獨芍藥盛開','張耒','宋','宋诗','song-poetry','','[]','靄靄春日晚，寂寂新陰繁。',72,'全唐诗/poet.song.64000.json','["靄靄春日晚，寂寂新陰繁。", "千紅與萬紫，盛極一時闌。", "西堂晚芍藥，百萼乘露鮮。", "紅妝諸美人，錦繡富春妍。", "東風時過之，舞態低昂翻。", "折贈懷溱洧，感之爲三歎。"]'),
('393ff5d2-4024-4aae-91c4-0381fdeafa13','題焦山','張耒','宋','宋诗','song-poetry','','[]','焦山如伏龜，萬古浸碧浪。',72,'全唐诗/poet.song.64000.json','["焦山如伏龜，萬古浸碧浪。", "舉頭北顧海，尾負金剎壯。", "我聞城東樓，秀色日相向。", "松杉數毛髮，人物見下上。", "欲携浮丘公，據殻恣潜漾。", "仙風如見引，金闕或可訪。"]'),
('77ff9485-5a0b-4d69-aac0-3d11199ad921','春日雜興四首  其一','張耒','宋','宋诗','song-poetry','','[]','桃李用事辰，鮮明奪雲綺。',48,'全唐诗/poet.song.64000.json','["桃李用事辰，鮮明奪雲綺。", "繁華一朝去，默默慚杞梓。", "時徂鷹化鳩，地遷橘爲枳。", "獨有羨門生，後天猶不死。"]'),
('6ee17188-b4ed-4d4a-8517-1334c9914ceb','春日雜興四首  其二','張耒','宋','宋诗','song-poetry','','[]','昔我遊京室，交通五陵間。',120,'全唐诗/poet.song.64000.json','["昔我遊京室，交通五陵間。", "主客各英妙，袍馬相追攀。", "千金具飲啜，百金顧吹彈。", "纓弁羅廣席，當頭舞交竿。", "鮮妝耀淥酒，錦纈生風瀾。", "燈燭暗夜艾，士女紛相班。", "歡娛易徂歇，轉盼如飛翰。", "亹亹負孤願，離離銜永歎。", "山鳥窺茗飲，簷花笑蔬餐。", "棄捐勿重陳，事定須蓋棺。"]'),
('70350008-4c2c-4f17-a477-976801ecb4e4','春日雜興四首  其三','張耒','宋','宋诗','song-poetry','','[]','客從遠方來，遺我昭華管。',96,'全唐诗/poet.song.64000.json','["客從遠方來，遺我昭華管。", "吹之幻人心，異境生虛窾。", "磝磝青嶂橫，决决春流滿。", "馬蹄交狹斜，車轂錯平坦。", "士女競芳辰，禽魚蔭修笴。", "依微認涕笑，凌沉見纖短。", "停吹欻泯滅，耽耽復空館。", "靈物信所直，顧恨知音罕。"]'),
('306e3f10-3ab2-4363-a698-dc51fce86182','春日雜興四首  其四','張耒','宋','宋诗','song-poetry','','[]','潭潭故邑井，猗猗上宮蘭。',96,'全唐诗/poet.song.64000.json','["潭潭故邑井，猗猗上宮蘭。", "不食自清渫，莫服更幽閑。", "志士恥窮極，卷迹甘饑寒。", "佳辰邈良覿，觸物懸悲端。", "入途眇回遠，經歲曠音翰。", "豈不慕裘馬，詭得非所安。", "蟬冕多怵迫，繩樞鮮憂患。", "枉尋竟何補，方枘誠獨難。"]'),
('8a1d3d6f-607d-40fd-93c8-463698f76d31','出長夏門','張耒','宋','宋诗','song-poetry','','[]','出郭心已清，青山忽相對。',96,'全唐诗/poet.song.64000.json','["出郭心已清，青山忽相對。", "游人傍流水，俯仰秀色內。", "誰張蒼玉屏，中斷神斧快。", "清伊瀉其間，銀漢曳天派。", "參差樓觀出，杳靄林麓邃。", "巖聲答遠響，水影弄空翠。", "同遊得君子，興與烟霞會。", "選勝雖自茲，高懷已塵外。"]'),
('f1d96ca0-cf8a-44bb-a758-62f2fdaa8bbe','飯昭果寺','張耒','宋','宋诗','song-poetry','','[]','飄然乘興遊，殽酒笑俗具。',96,'全唐诗/poet.song.64000.json','["飄然乘興遊，殽酒笑俗具。", "僧居致野飯，草草亦有趣。", "山僧慣迎客，煮茗新泉注。", "岩花得春遲，晚秀見紅素。", "蕭蕭野市井，人物自來去。", "溪光送孤舟，石色照素樹。", "題名掃高壁，歲月記所遇。", "書罷迹已陳，出門猶反顧。"]'),
('7cd79d47-98f7-4383-98e3-0553ea697b21','渡伊水','張耒','宋','宋诗','song-poetry','','[]','雙崖若爭妍，秀色日相射。',96,'全唐诗/poet.song.64000.json','["雙崖若爭妍，秀色日相射。", "遊人誇水東，揮榜渡清瀉。", "潺潺溪邊風，五月自瀟洒。", "中流望南北，河漢自天下。", "嗟予水鄉客，塵土困蹈藉。", "江湖久懷歸，無地稅征駕。", "臨流動長想，照影久悲咤。", "滄洲倘有歸，功業付高謝。"]'),
('c9aac777-ddb6-4b9c-adc8-baec978007de','白公祠','張耒','宋','宋诗','song-poetry','','[]','斯人不可見，千古懷清風。',96,'全唐诗/poet.song.64000.json','["斯人不可見，千古懷清風。", "猶想鸞鳳姿，翛然山水中。", "空祠遺像儼，過者爲肅恭。", "同時富貴人，泯滅知何窮。", "公昔得所遇，慨然屢輸忠。", "一傷巧舌刀，泯默類瘖聾。", "出處竟無禍，卷舒詎知蹤。", "被獲空歎麟，不制方爲龍。"]'),
('a31c13aa-3929-4d6a-86ee-7d4314aacc9a','上皇龕','張耒','宋','宋诗','song-poetry','','[]','升危躡石梯，已覺毛骨異。',96,'全唐诗/poet.song.64000.json','["升危躡石梯，已覺毛骨異。", "玄龕剖山腹，六月霜雪至。", "佛臺磨青瑶，紺滑不留水。", "巍巍數天人，蒼玉刻冠佩。", "老僧拂高崖，上有昔人字。", "國都已蕭瑟，山澤隠遺事。", "西軒俯空闊，晝夜納蒼翠。", "卜築莫後時，林中有餘地。"]'),
('c395ec9d-a519-4c64-b889-a1035a9aa3a7','石樓','張耒','宋','宋诗','song-poetry','','[]','清溪若奔虬，八鎖束其頸。',96,'全唐诗/poet.song.64000.json','["清溪若奔虬，八鎖束其頸。", "奔騰去莫脫，擺掣姿驍猛。", "嘈嘈戰風霆，萬鼓助其勁。", "聲驅石崖動，氣抱晴日冷。", "我來怯初登，注視久乃定。", "悠悠山川闊，寸目羅萬景。", "平生林野趣，疏放謝鞭警。", "會期山月出，一嘯清夜永。"]'),
('b6d467a6-6a4f-469c-86b2-7e901fa65d1d','上方','張耒','宋','宋诗','song-poetry','','[]','足躡青玉磴，躋攀不知勞。',96,'全唐诗/poet.song.64000.json','["足躡青玉磴，躋攀不知勞。", "回頭瞰木杪，始覺所歷高。", "孤鳥去滅沒，奔溪深怒號。", "白日當畫梁，青雲送微飈。", "坐久神慮平，微凉清骨毛。", "但警塵垢容，俯仰近赤霄。", "古壁有遺字，昔人嗟寂寥。", "南風不知暑，古木常蕭蕭。"]'),
('c7dfa9ca-b8c5-4b09-a9f5-99ea052fb904','三龕','張耒','宋','宋诗','song-poetry','','[]','萬穴列巖壁，三龕獨雄夸。',96,'全唐诗/poet.song.64000.json','["萬穴列巖壁，三龕獨雄夸。", "封山鑿其骨，開像儼且呀。", "悲哉輕人功，不計歲月賒。", "像成竟何補，國破荒蓬麻。", "悠悠清伊水，去去縈山斜。", "晚渚栖暝鷗，夕波戰餘霞。", "陵谷良未遷，古今如轉車。", "應有千年鶴，歸顧如咨嗟。"]'),
('dfab803e-c044-4398-bb2f-fe998a51454d','晚飯寶應','張耒','宋','宋诗','song-poetry','','[]','晚風吹古栢，落照明空山。',96,'全唐诗/poet.song.64000.json','["晚風吹古栢，落照明空山。", "深行得寶剎，崖嶺相回環。", "人遠草木邃，境幽魚鳥閒。", "道人掃華堂，延我具晚餐。", "齋庖野菊美，石井新泉寒。", "既飽陟上方，浮香出林端。", "平生麋鹿志，强學伏車轅。", "塵懷造勝絕，欲去猶三歎。"]'),
('f6267354-5162-4093-ac23-3e463ace8ea2','廣化遇雨','張耒','宋','宋诗','song-poetry','','[]','浮雲蔽高峰，臺殿延晚色。',96,'全唐诗/poet.song.64000.json','["浮雲蔽高峰，臺殿延晚色。", "風聲轉谷豪，雨脚射山白。", "東樓瞰虛明，龍甲排松栢。", "蕭森異人境，坐視動神魄。", "撞鐘寺門掩，晚霽尚殘滴。", "相携下山去，塵靜馬無跡。", "歸來解鞍歇，新月如破璧。", "但恐桃花源，回舟已青壁。"]'),
('91f883e3-d5b0-4662-97a5-8d236e737cbd','寄子瞻舍人二首  其一','張耒','宋','宋诗','song-poetry','','[]','皎皎連城璧，實惟天地珍。',108,'全唐诗/poet.song.64000.json','["皎皎連城璧，實惟天地珍。", "足傷曾不售，寶氣終氤氳。", "山川媚餘秀，星斗攬奇氛。", "終然不可掩，三浴祓埃塵。", "天王齋戒受，嚴庭具九賓。", "貯之黄金臺，籍以九龍茵。", "事稱忘禮厚，人誰駭其新。", "車輪走四方，爭睹快一陳。", "無瑕故易傷，斂輝志乃神。"]'),
('d7fc00d2-14ee-4015-b1cd-822381065a32','寄子瞻舍人二首  其二','張耒','宋','宋诗','song-poetry','','[]','紛紛名利場，向背不知醜。',96,'全唐诗/poet.song.64000.json','["紛紛名利場，向背不知醜。", "翟公書其門，客態自如舊。", "勢去競詆沮，有餘丐升斗。", "高賢少畦畛，小子多狀候。", "退之呼字生，房相肆琴叟。", "事奇出意表，欲辯不及口。", "神明勞忠孝，福祿日方厚。", "防微無早計，求福常恐後。"]'),
('d91d08b0-3fa4-428c-af97-c1b042d56922','贈楊念三道孚','張耒','宋','宋诗','song-poetry','','[]','黄鶴樓前月，清輝千里寒。',96,'全唐诗/poet.song.64000.json','["黄鶴樓前月，清輝千里寒。", "娟娟過江北，送子別長安。", "長安百萬家，車馬無時閒。", "中天聳觀闕，四海會衣冠。", "憐爾薜蘿子，豪華駭新觀。", "蕭蕭囊中句，饑坐奏清彈。", "漫郎久不愜，逸思生風翰。", "寄聲武昌魚，欲從傖父餐。"]'),
('04b5fa3e-7626-4868-baef-f1cc0a4ae98e','曉赴秘書省有感','張耒','宋','宋诗','song-poetry','','[]','桃李欲開時，長安春正好。',144,'全唐诗/poet.song.64000.json','["桃李欲開時，長安春正好。", "晴空倚閶闔，朝日散馳道。", "雲收龍蛇榜，爛爛金碧曉。", "清都不容塵，虎士守洒掃。", "家無當關警，襟袂免顛倒。", "何慚驅款段，吾事不須早。", "儒生近卜祝，本自異時好。", "聖朝尚文雅，詔使窺鴻寶。", "平生一盃酒，江海送吾老。", "靜喧非人事，不得守懷抱。", "跳梁干造物，乃取鏌鋣誚。", "委懷隨所遭，千葉纔一笑。"]'),
('3994efd6-511a-4322-98d6-1669b4bb55d1','贈无咎以既見君子云胡不喜爲韵八首  其一','張耒','宋','宋诗','song-poetry','','[]','平生懷想人，握手良未易。',48,'全唐诗/poet.song.64000.json','["平生懷想人，握手良未易。", "接君同舍歡，此事非此世。", "十年淮海夢，一笑相逢地。", "投分白首期，願言何有既。"]'),
('fff4d021-4179-47c6-b127-f9a14e5d76f7','贈无咎以既見君子云胡不喜爲韵八首  其二','張耒','宋','宋诗','song-poetry','','[]','賢愚譬觀形，美醜不自見。',48,'全唐诗/poet.song.64000.json','["賢愚譬觀形，美醜不自見。", "醫肱待三折，劍鐵要百鍊。", "磨君古青銅，汰簡寄明辨。", "一智出千愚，食芹敢忘獻。"]'),
('6113bca9-dfee-4f36-b4c7-392d17854f8c','贈无咎以既見君子云胡不喜爲韵八首  其三','張耒','宋','宋诗','song-poetry','','[]','文風還正始，磊落有諸君。',48,'全唐诗/poet.song.64000.json','["文風還正始，磊落有諸君。", "長者進後生，亦使我有聞。", "譬如狸與虎，偶使並稱文。", "終然不可及，困我力空勤。"]'),
('530272a5-7e29-41a9-ad0a-422838bf60f3','贈无咎以既見君子云胡不喜爲韵八首  其四','張耒','宋','宋诗','song-poetry','','[]','文衰東京後，特起得韓子。',48,'全唐诗/poet.song.64000.json','["文衰東京後，特起得韓子。", "支撐誹笑中，久乃化而靡。", "籍湜既洒掃，後生始歸市。", "垂君拯溺手，請效我一指。"]'),
('21f7026d-7e17-4e72-80f3-d1b8b744bcdb','贈无咎以既見君子云胡不喜爲韵八首  其五','張耒','宋','宋诗','song-poetry','','[]','詩壇李杜後，黄子擅奇勳。',48,'全唐诗/poet.song.64000.json','["詩壇李杜後，黄子擅奇勳。", "平生執羈靮，開府與參軍。", "舉詩秉筆徒，吟哦謾云云。", "安知握奇律，一字有風雲。"]'),
('65379136-2d44-4c1e-a32a-1c13a0c29a8d','贈无咎以既見君子云胡不喜爲韵八首  其六','張耒','宋','宋诗','song-poetry','','[]','觸有羸其角，進有跋其胡。',48,'全唐诗/poet.song.64000.json','["觸有羸其角，進有跋其胡。", "膏車秣吾馬，白日在修途。", "雖乏亡何杯，頗多未見書。", "力學致事功，良田本深鋤。"]'),
('de300f91-87c0-4a49-b11d-f37ee7668f73','贈无咎以既見君子云胡不喜爲韵八首  其七','張耒','宋','宋诗','song-poetry','','[]','黄子少年時，風流勝春柳。',48,'全唐诗/poet.song.64000.json','["黄子少年時，風流勝春柳。", "中年一鉢飯，萬事寒木朽。", "室有僧對談，房無妾持帚。", "此道人人事，誰令予獨不。"]'),
('11c72c28-90df-4f33-ad59-11b82407171e','贈无咎以既見君子云胡不喜爲韵八首  其八','張耒','宋','宋诗','song-poetry','','[]','南山縛虎師，肯顧世書字。',48,'全唐诗/poet.song.64000.json','["南山縛虎師，肯顧世書字。", "揚眉哦楚喉，鼎畔倒侯喜。", "詩聲一蒼蠅，下到霹靂耳。", "庸庸老尋常，物外有奇偉。"]'),
('d6040ce9-dfe9-47d6-9eb9-a8bf2dec8669','昨夜月中一睡殊有秋色覺書所見戲呈道孚','張耒','宋','宋诗','song-poetry','','[]','幽人息遙夜，四聽市聲寂。',96,'全唐诗/poet.song.64000.json','["幽人息遙夜，四聽市聲寂。", "月華清可掬，天色紺欲滴。", "候蟲先知秋，微響出陰壁。", "精熒高露濕，斷續殘河白。", "興懷我自出，抱器方待擇。", "感時當有作，陋巷奏金石。", "予方問農圃，朝市嗟掃迹。", "先寒戒裘褐，歲暮養老客。"]'),
('d853e552-d411-4200-91f6-75678f1ba387','東園','張耒','宋','宋诗','song-poetry','','[]','荒園何所有，落葉與衰叢。',48,'全唐诗/poet.song.64000.json','["荒園何所有，落葉與衰叢。", "含芳未肯吐，惟有木芙蓉。", "黄菊如佳人，綠萼包金茸。", "牀隨重陽酒，娛此憔悴翁。"]'),
('757aabdd-6641-4f7a-85a8-6a3182406239','次韵淵明飲酒詩  其一','張耒','宋','宋诗','song-poetry','','[]','我欲常飲酒，俗事苦奪之。',48,'全唐诗/poet.song.64000.json','["我欲常飲酒，俗事苦奪之。", "飲酒不得醉，何如未飲時。", "顛倒衆譏笑，佳處正在茲。", "念此雖杜門，濁醪日常持。"]'),
('7564ed8c-e469-46ed-8363-91ceddb96c25','次韵淵明飲酒詩  其二','張耒','宋','宋诗','song-poetry','','[]','出門憚應接，俗士不多情。',60,'全唐诗/poet.song.64000.json','["出門憚應接，俗士不多情。", "對酒輒拜辭，好禮以求名。", "嗟嗟名幾何，曷足善爾生。", "共處一泡中，倏忽風濤驚。", "好飲信無補，不飲亦何成。"]'),
('81127f9e-e444-46b2-9e3d-2ed02992cf62','次韵淵明飲酒詩  其三','張耒','宋','宋诗','song-poetry','','[]','我久喜文詞，思與鴻鵠飛。',72,'全唐诗/poet.song.64000.json','["我久喜文詞，思與鴻鵠飛。", "老來覺非是，念昔正可悲。", "買金鑄杜康，百拜誓歸依。", "晉陶與康伯，九原吾與歸。", "涉世苦不諳，多病身早衰。", "惟有尊中酒，不與我心違。"]'),
('d0378c73-fedd-4b85-a55e-bb56ee263485','次韵淵明飲酒詩  其四','張耒','宋','宋诗','song-poetry','','[]','處樂非縱情，處靜非避喧。',60,'全唐诗/poet.song.64000.json','["處樂非縱情，處靜非避喧。", "豪夸與枯槁，彼各據一偏。", "悠然獨樂處，在我不在山。", "羲皇迹已遠，三酌呼可還。", "一罇每獨睡，不待賓客言。"]'),
('2cc58eb4-2525-4415-aa26-7e740154fd49','次韵淵明飲酒詩  其五','張耒','宋','宋诗','song-poetry','','[]','所嗜人不得，一物百非是。',48,'全唐诗/poet.song.64000.json','["所嗜人不得，一物百非是。", "猶有尊中酒，道勝無敢毀。", "彼哉譏謗者，誑口而信耳。", "當憂十八隔，罰此繆語綺。"]'),
('55a95cc1-48a0-4697-ab41-389cf8c374a3','次韵淵明飲酒詩  其六','張耒','宋','宋诗','song-poetry','','[]','自庇無一椽，道人分半宅。',60,'全唐诗/poet.song.64000.json','["自庇無一椽，道人分半宅。", "屋西羅古殯，寒草無人跡。", "纍纍長與少，豈復待年百。", "鴉飛朝樹疏，蟲弔宵月白。", "平生或不飲，至此方知惜。"]'),
('d3357de0-c82e-41c6-a740-d19350a8021a','次韵淵明飲酒詩  其七','張耒','宋','宋诗','song-poetry','','[]','曹參漢賢相，掾吏亦豪英。',60,'全唐诗/poet.song.64000.json','["曹參漢賢相，掾吏亦豪英。", "四海付醇酒，乃真知物情。", "亡秦餘毒烈，一洗百壺傾。", "和氣薰醉人，金革乃不鳴。", "卑卑談治道，陋矣洛陽生。"]'),
('759aad7f-09a2-4722-a132-aa36b8b96a10','次韵淵明飲酒詩  其八','張耒','宋','宋诗','song-poetry','','[]','種樹東簷下，雨來發幽姿。',60,'全唐诗/poet.song.64000.json','["種樹東簷下，雨來發幽姿。", "微陽動九地，光彩變新枝。", "榮衰一以異，枯槁易神奇。", "消息天使然，人工徒爾爲。", "杜門沽酒飲，高懸吾馬羈。"]'),
('5b96e3fd-e265-4989-9523-bf9cc18a935d','次韵淵明飲酒詩  其九','張耒','宋','宋诗','song-poetry','','[]','里有好事者，我往罇輒開。',96,'全唐诗/poet.song.64000.json','["里有好事者，我往罇輒開。", "我亦爲之盡，每往亦開懷。", "尚慮數見厭，動作旬月乖。", "今晨起苦晚，獨坐見烏棲。", "冬溫雪作雨，里巷苦多泥。", "且復閉門坐，開卷理多諧。", "誰知無言中，獨往不自迷。", "得意復終日，弭車不復回。"]'),
('1dd3c1de-b5e7-4a89-bbfc-2e5f38cce626','次韵淵明飲酒詩  其一○','張耒','宋','宋诗','song-poetry','','[]','弱歲慕世名，中年頗探道。',72,'全唐诗/poet.song.64000.json','["弱歲慕世名，中年頗探道。", "世間無非苦，病死與生老。", "相尋無窮已，遞代作榮槁。", "奇哉竺乾書，百遍讀愈好。", "汙泥雖云濁，本不害吾寶。", "酒雖破浄律，吾事在律表。"]'),
('b32d1b3f-6ecc-4385-937c-f501ba3a0d59','次韵淵明飲酒詩  其一一','張耒','宋','宋诗','song-poetry','','[]','昔嘗罹厄疾，一卧輒踰時。',72,'全唐诗/poet.song.64000.json','["昔嘗罹厄疾，一卧輒踰時。", "念無所歸咎，乃誓與酒辭。", "那知偶不死，持杯復飲茲。", "既飲輒爲盡，快哉復何疑。", "神暢病自失，此說信不欺。", "藥石傷天和，此方吾笑之。"]'),
('52269b04-3aa5-44c6-aaab-135be45e6043','次韵淵明飲酒詩  其一二','張耒','宋','宋诗','song-poetry','','[]','世間有醉鄉，百世本一境。',60,'全唐诗/poet.song.64000.json','["世間有醉鄉，百世本一境。", "欲游不待駕，但畏足疾醒。", "其鄉無限界，亦不阻巖嶺。", "陰陽無疾癘，風俗盡箕潁。", "君往余請從，無待宵燭炳。"]'),
('43e847f3-5627-40e0-8663-15d3963bc9c9','次韵淵明飲酒詩  其一三','張耒','宋','宋诗','song-poetry','','[]','酒盡輒起沽，躭然待酒至。',60,'全唐诗/poet.song.64000.json','["酒盡輒起沽，躭然待酒至。", "呼兒挈樽杓，未酌兀已醉。", "譬如念醯醢，流液不待味。", "醉客失揖讓，醉語少倫次。", "坐客皆摇頭，知稀故我貴。"]'),
('a187b37d-9e0e-415f-9143-e5ecf22cfb9d','次韵淵明飲酒詩  其一四','張耒','宋','宋诗','song-poetry','','[]','兒童居宛丘，里巷昔所經。',72,'全唐诗/poet.song.64000.json','["兒童居宛丘，里巷昔所經。", "重來三十年，落魄竟何成。", "扣門問長老，主人多已更。", "蕭蕭城南道，松柏共墳庭。", "念此久興歎，游不待鷄鳴。", "悠然且飲酒，聊以慰平生。"]'),
('73984952-e0b0-4be1-83b4-c86715e66569','次韵淵明飲酒詩  其一五','張耒','宋','宋诗','song-poetry','','[]','歲晏霰雪集，客庭號北風。',48,'全唐诗/poet.song.64000.json','["歲晏霰雪集，客庭號北風。", "老人不復出，兀睡小齋中。", "忽然身且老，惜此歲時窮。", "一弛不再張，吾身如掛弓。"]'),
('2ee6c0e7-51cb-4282-a789-480c50d6d296','次韵淵明飲酒詩  其一六','張耒','宋','宋诗','song-poetry','','[]','淵明酒不足，種秫猶可得。',60,'全唐诗/poet.song.64000.json','["淵明酒不足，種秫猶可得。", "無秫酒須求，時人嘲我惑。", "寧當且醉酣，慎勿疑通塞。", "但憎獨醒人，豈有禁酒國。", "酩酊忘對言，滿引常默默。"]'),
('6839f7ce-6aa2-4729-a805-74c93908a7fd','次韵淵明飲酒詩  其一七','張耒','宋','宋诗','song-poetry','','[]','樂天好飲者，少亦登貴仕。',84,'全唐诗/poet.song.64000.json','["樂天好飲者，少亦登貴仕。", "八年潯陽謫，學道乃忘己。", "與時雖寡怨，行己終有恥。", "抗言立朝廷，放志傲閭里。", "優游禍福間，出處皆可紀。", "乘流與偕逝，遇坎輒復止。", "酣歌盡百年，天理端可恃。"]'),
('69c4bc94-288c-4316-aeba-4cc55565e6c4','次韵淵明飲酒詩  其一八','張耒','宋','宋诗','song-poetry','','[]','吾知李太白，瀟灑本天真。',60,'全唐诗/poet.song.64000.json','["吾知李太白，瀟灑本天真。", "一飲三百杯，不問漓與醇。", "子雲亦好飲，白髮事亡新。", "奇窮易投閣，區區賦劇秦。", "兩賢竟誰樂，千載同埃塵。"]'),
('91d17cf2-3463-497e-b178-8376f23f3896','次韵淵明飲酒詩  其一九','張耒','宋','宋诗','song-poetry','','[]','平生自百懶，而獨於酒勤。',60,'全唐诗/poet.song.64000.json','["平生自百懶，而獨於酒勤。", "生事萬緣疏，而獨於酒親。", "皇皇東家丘，隠者笑知津。", "我欲去即去，柴車不勞巾。", "但飲百年中，不愧飲酒人。"]'),
('fa8c10a6-a900-4ca0-b44c-5bfce5551cd2','與潘仲達二首  其一','張耒','宋','宋诗','song-poetry','','[]','東風沛甘雨，百物一時好。',48,'全唐诗/poet.song.64000.json','["東風沛甘雨，百物一時好。", "江南桃李盡，紅紫到百草。", "道傍負擔子，寒食歸祭禱。", "念我淮上丘，三年不躬掃。"]'),
('b22c0de9-2bdb-4b78-89a9-a8c3a316965d','與潘仲達二首  其二','張耒','宋','宋诗','song-poetry','','[]','淮陽牡丹花，盛不數京洛。',48,'全唐诗/poet.song.64000.json','["淮陽牡丹花，盛不數京洛。", "姚黄一枝開，衆艷氣如削。", "亭亭風塵表，獨立朝萬萼。", "誰知臨老眼，更復美葵藿。"]'),
('ec633d3c-fd0a-4ef0-a2ae-79f64e70a0b7','莎雞','張耒','宋','宋诗','song-poetry','','[]','金風透殘伏，玉樹先秋凉。',72,'全唐诗/poet.song.64000.json','["金風透殘伏，玉樹先秋凉。", "喓喓草間蟲，感時振衣裳。", "楚客思萬里，夜吟怨藜床。", "勞勞終夕語，共此簷月光。", "孤輪曳獨繭，折管韵哀傷。", "辛苦豳父兄，無衣畏風霜。"]'),
('dabee147-73ec-4c96-9592-067aaa7b3b68','宦遊','張耒','宋','宋诗','song-poetry','','[]','宦遊吾漫爾，未慕致身早。',48,'全唐诗/poet.song.64000.json','["宦遊吾漫爾，未慕致身早。", "秋來憶山苦，遙夜夢顛倒。", "鳴蟲待誰聽，落葉煩我掃。", "誰得省勞人，吾生常草草。"]'),
('233949df-6c6f-4c4d-ba78-29fa1b853214','次韵秦覯','張耒','宋','宋诗','song-poetry','','[]','琬琰非世珍，昔以羊皮換。',120,'全唐诗/poet.song.64000.json','["琬琰非世珍，昔以羊皮換。", "嗟君復何求，衆棄乃所玩。", "十年少游兄，閉口受客難。", "二毛纔一第，俗子猶憤惋。", "人間異巧拙，善琢貴顔汗。", "嬋娟守重閨，倚市爭倩盼。", "君胡寶滯貨，屢辱訪衰懦。", "譬猶卧仆塗，更侑觥與散。", "球然瑚璉質，磨琢爭璀璨。", "遲君三年鳴，更用驚我慢。"]'),
('64d20a99-1260-47fd-b7fa-36fb25e39cbb','阿几','張耒','宋','宋诗','song-poetry','','[]','小兒名阿几，眉目頗疏明。',96,'全唐诗/poet.song.64000.json','["小兒名阿几，眉目頗疏明。", "日來書案傍，學我讀書聲。", "男兒事業多，何必學讀書。", "自古奇男子，往往羞爲儒。", "阿几笑謂爺，薄雲無密雨。", "看爺饑寒姿，兒豈合貴富。", "翁家破篋中，惟有書與史。", "教兒不讀書，更欲作何事。"]'),
('c2074203-0b6e-457d-8d1f-675daeef0e63','宿虹縣驛','張耒','宋','宋诗','song-poetry','','[]','長隄隘舟車，上下無暫歇。',96,'全唐诗/poet.song.64000.json','["長隄隘舟車，上下無暫歇。", "煎熬古驛門，聒聒爭瑣屑。", "東南淮浙富，輸餽日填咽。", "楚風習喧卑，吳舌動嘲哳。", "平生耽靜意，投鬧劇含噦。", "况茲道路勤，强食慰饑渴。", "年來嵩洛興，久與泉石結。", "終當卜吾廬，雲山對華髮。"]'),
('5a8af157-48ec-466e-a855-c83610a966a7','有感三首  其一','張耒','宋','宋诗','song-poetry','','[]','一春苦多風，桃李見無幾。',120,'全唐诗/poet.song.64000.json','["一春苦多風，桃李見無幾。", "良遊時已失，忽忽三月尾。", "中間亦何有，徒自亂心耳。", "所嗟違所娛，坐費良日晷。", "堂北千葉桃，微本混榛枳。", "居然未之省，一日燦相視。", "零丁不忍摘，攀玩聊自慰。", "乃知物雖微，未易即疏棄。", "從今至零落，猶足伴尊胾。", "仍煩芊綿草，藉我花前醉。"]'),
('1183cf02-590b-4d56-8bb9-a5ddb064e2cc','有感三首  其二','張耒','宋','宋诗','song-poetry','','[]','昨日鴉作巢，今者鴉哺兒。',96,'全唐诗/poet.song.64000.json','["昨日鴉作巢，今者鴉哺兒。", "念知三月闌，春物行已稀。", "晚風颯不收，殘紅怨餘姿。", "回風起輕寒，擁爐火重吹。", "燈明夜齋靜，目澀臨書遲。", "病齒不飲酒，持盃勸妻兒。", "豈無兒女心，惆悵桃李蹊。", "彼昏安目前，丈夫方有思。"]'),
('a437513a-ed74-4f02-b391-2266ff124e49','有感三首  其三','張耒','宋','宋诗','song-poetry','','[]','古今不殊途，掩卷獨長想。',96,'全唐诗/poet.song.64000.json','["古今不殊途，掩卷獨長想。", "炎爐與死灰，相去如反掌。", "彼昏誠不知，一醉富莫量。", "那知道旁殍，曾是厭盃盎。", "一金短販兒，豈暇議得喪。", "但憐反覆間，觀者爲惆悵。", "聖賢蹈大方，不苟目前妄。", "寄身愛憎間，得失真一餉。"]'),
('3000af1a-4490-4222-bc7f-c36611732eba','食菜','張耒','宋','宋诗','song-poetry','','[]','大雨困淋漓，小雨傷霢霂。',108,'全唐诗/poet.song.64000.json','["大雨困淋漓，小雨傷霢霂。", "哀哉南畝人，日夜塗手足。", "入倉無一粒，敢望祈報福。", "餘功歸老圃，畦菜青滿目。", "長官却野饋，性命赦雞鶩。", "何須問清白，薦德芻一束。", "歸來輟食歎，每悔釜炊玉。", "青衫尚如此，何况膏粱腹。", "願君少自寬，謀遠須食肉。"]'),
('8e609eb7-6a4f-447b-8181-002defad7cfe','王子開朝散早年以疾病謝事還江陰求詩爲別三首  其一','張耒','宋','宋诗','song-poetry','','[]','濟物昔所務，捨耕還自非。',48,'全唐诗/poet.song.64000.json','["濟物昔所務，捨耕還自非。", "駸駸老將至，忽忽意多違。", "門有王夫子，柴車謝事歸。", "令人三歎息，羞澀向塵衣。"]'),
('b0840f86-8002-4b75-bef6-d82cd0927124','王子開朝散早年以疾病謝事還江陰求詩爲別三首  其二','張耒','宋','宋诗','song-poetry','','[]','田園何日到，水國洗秋寒。',48,'全唐诗/poet.song.64000.json','["田園何日到，水國洗秋寒。", "興來出飲酒，興罷歸杜門。", "漫郎遊已倦，老眼亂丹鉛。", "扁舟肯載我，共看雪濤翻。"]'),
('a0c05b38-773c-47dd-abe8-987225655e61','王子開朝散早年以疾病謝事還江陰求詩爲別三首  其三','張耒','宋','宋诗','song-poetry','','[]','避祿免危疾，棄鉛得黄金。',48,'全唐诗/poet.song.64000.json','["避祿免危疾，棄鉛得黄金。", "鬚眉藹如漆，便覺老難侵。", "江湖足幽遯，市卒或可尋。", "莫思芙蓉子，丹田亂君心。"]'),
('b6f9bbc1-dbd9-4211-af0a-b86db694332d','暮春奉女兄弟集宴堂','張耒','宋','宋诗','song-poetry','','[]','晨暉麗花柳，流水灧池塘。',72,'全唐诗/poet.song.64000.json','["晨暉麗花柳，流水灧池塘。", "暮春漸暄燠，華構肅朝凉。", "使君簿領暇，亦復陳壺觴。", "班坐豈異人，骨肉皆歡康。", "遙山出遠翠，遠水明斜陽。", "歡言不期醉，淡泊味何長。"]'),
('d7011df5-4556-4d8a-9261-53b367f89e7e','窺園','張耒','宋','宋诗','song-poetry','','[]','吾老懶讀書，得閒嘗窺園。',96,'全唐诗/poet.song.64000.json','["吾老懶讀書，得閒嘗窺園。", "愛此千樹雪，高低不勝繁。", "衝風掠之去，頗已隨沙塵。", "感之可奈何，我豈土木人。", "畏病不飲酒，已慚嵇阮真。", "淡泊非衆嗜，自娛難及賓。", "獨遊還獨吟，魚鳥與我親。", "悠哉山林趣，媿此簪纓身。"]'),
('ebe18e43-74cf-4d1a-b83b-df384cafa83e','馬巨濟董役魏王墳作詩寄之','張耒','宋','宋诗','song-poetry','','[]','城北牛脾山，千丘壓其麓。',96,'全唐诗/poet.song.64000.json','["城北牛脾山，千丘壓其麓。", "事皆有司辦，聖世數厚族。", "園林迫復土，百役興甚速。", "煩我別駕公，侵星次空谷。", "郵亭舊客去，閒日睡頗足。", "聞鶯有佳興，徙倚近喬木。", "櫻笋味鼎來，管弦調漸熟。", "期歸酌燒酒，及此未炎燠。"]'),
('9dae726a-0d1c-44fc-939c-9a48b99023f7','出伏後風雨頓凉有感三首  其一','張耒','宋','宋诗','song-poetry','','[]','秋風振秋曉，萬境一凄清。',48,'全唐诗/poet.song.64000.json','["秋風振秋曉，萬境一凄清。", "幽草蟲響息，高葉露華凝。", "戢翼烏尚宿，引吭雞屢鳴。", "淹留度華歲，悵然難爲情。"]'),
('98e98f0e-8377-4870-b21b-b0c7d887814b','出伏後風雨頓凉有感三首  其二','張耒','宋','宋诗','song-poetry','','[]','三伏如湯釜，熏煮理亦足。',48,'全唐诗/poet.song.64000.json','["三伏如湯釜，熏煮理亦足。", "西風半夜雨，窗戶一清肅。", "那能惜摇落，共喜過炎燠。", "老人亦晨起，稍進杯中醁。"]'),
('7d1ca1ca-f686-4930-8c2b-ca39b7991ab7','出伏後風雨頓凉有感三首  其三','張耒','宋','宋诗','song-poetry','','[]','殘暑扇中盡，新凉枕上歸。',48,'全唐诗/poet.song.64000.json','["殘暑扇中盡，新凉枕上歸。", "微雲起平遠，空碧上朝曦。", "稍感夏衣薄，漸傷高葉稀。", "來鴻飛集喜，卒歲稻粱肥。"]'),
('4bfaa671-c18e-412c-aabd-52271cec9ff5','太寧庭柏','張耒','宋','宋诗','song-poetry','','[]','微風起清籟，烈日交翠陰。',48,'全唐诗/poet.song.64000.json','["微風起清籟，烈日交翠陰。", "蔭茲金仙居，樓殿鬰沈沈。", "永日燕雀下，有時鐘梵音。", "誰能悟斯道，來此契無心。"]'),
('34933e02-0db6-4420-b353-bc0c67ad9d7a','暇日步西園感物輒爲詩得七篇 酴醾','張耒','宋','宋诗','song-poetry','','[]','欲知此園古，請視酴醾蒼。',48,'全唐诗/poet.song.64000.json','["欲知此園古，請視酴醾蒼。", "孫枝已輪囷，走蔓龍蛇長。", "春風一吹噓，灼灼發奇光。", "仙姝不可挹，順風飲其香。"]'),
('293a1b63-5c7a-4516-b34d-76cf32651fb7','暇日步西園感物輒爲詩得七篇 秋圃','張耒','宋','宋诗','song-poetry','','[]','秋圃寂無有，蕭條殘菊枝。',48,'全唐诗/poet.song.64000.json','["秋圃寂無有，蕭條殘菊枝。", "老蛩依日叫，暗蝶傍人飛。", "鎖澀門開少，莎長人到稀。", "舊遊渾記得，到處即如歸。"]'),
('e8b38725-90d9-4802-ab77-7db6bd65cb3e','暇日步西園感物輒爲詩得七篇 菊叢','張耒','宋','宋诗','song-poetry','','[]','下根盤秋泥，上葉披宿雨。',48,'全唐诗/poet.song.64000.json','["下根盤秋泥，上葉披宿雨。", "惟餘黄金蕊，秀色日夜吐。", "寧須薦九日，但惜歲云暮。", "吾將屑落英，持泛蘭皋露。"]'),
('1a35b268-cbeb-4039-a18c-5f59f8b668fc','暇日步西園感物輒爲詩得七篇 芙蓉','張耒','宋','宋诗','song-poetry','','[]','清霜厲嚴殺，松栢氣不振。',48,'全唐诗/poet.song.64000.json','["清霜厲嚴殺，松栢氣不振。", "芙蓉乃微木，曉艷獨嬌春。", "穠粹覺蘭疲，芬敷知菊貧。", "欲攀無所贈，聊復插吾巾。"]'),
('35a09355-e7af-47a2-a57e-5618a690e090','暇日步西園感物輒爲詩得七篇 橘','張耒','宋','宋诗','song-poetry','','[]','奇林藴貞粹，健葉圓青鮮。',48,'全唐诗/poet.song.64000.json','["奇林藴貞粹，健葉圓青鮮。", "中有碧瑶實，正味百果先。", "貢包登堯俎，頌德列騷篇。", "李衡空庸材，徒列木奴千。"]'),
('4366e8ef-7c83-42e4-9c9c-94ae4d080338','暇日步西園感物輒爲詩得七篇 斑竹','張耒','宋','宋诗','song-poetry','','[]','重瞳陟方時，二妃蓋老人。',48,'全唐诗/poet.song.64000.json','["重瞳陟方時，二妃蓋老人。", "安肯泣路傍，洒淚留叢筠。", "頗疑葛陂化，點點留斑鱗。", "慎勿脫水去，入世多埃塵。"]'),
('27aa8cd6-017c-481f-b82d-6548afd0f1a6','暇日步西園感物輒爲詩得七篇 種蔬','張耒','宋','宋诗','song-poetry','','[]','貧舍無旨蓄，種圃治寒蔬。',48,'全唐诗/poet.song.64000.json','["貧舍無旨蓄，種圃治寒蔬。", "縱橫數席間，灌溉亦勤劬。", "積雨有新甲，時摘付中厨。", "何勞樊遲學，當問漢陰夫。"]'),
('1f1bddad-fbac-48cb-8523-75e1d18854df','所居堂後北籬下獲二蛇一小色赤長二尺許一大色黑長七尺圍四五寸尾可貫百錢盡放之','張耒','宋','宋诗','song-poetry','','[]','二物穴我居，歲月亦已老。',48,'全唐诗/poet.song.64000.json','["二物穴我居，歲月亦已老。", "一朝雙擒獲，蜿蜿出幽草。", "安行免噬齧，敢望吐珠報。", "巳月不殺蛇，昔賢有遺告。"]'),
('e46c33c1-671e-429e-96f7-faeed52a9037','小雨效韋體','張耒','宋','宋诗','song-poetry','','[]','午景蔽浮雲，芳林散清雨。',48,'全唐诗/poet.song.64000.json','["午景蔽浮雲，芳林散清雨。", "虛窗度遙吹，稍覺青葉舉。", "殘蔬知夏餘，隕葉兆秋序。", "幽獨無往來，烹茶誰晤語。"]'),
('a9e1c597-24b6-4ce6-bf07-674c6681d364','納凉','張耒','宋','宋诗','song-poetry','','[]','靡靡春事退，寂寂夏日長。',96,'全唐诗/poet.song.64000.json','["靡靡春事退，寂寂夏日長。", "日西騎馬歸，卧此北戶凉。", "官事幸休逸，甘爲白頭郎。", "朝出暮還家，悠悠愧路旁。", "所欣藥物靈，頗覺疾病康。", "幸免三已慍，敢希五饋漿。", "難堪七有餘，不過三已嘗。", "呼兒且糲食，貧固士之常。"]'),
('eee1a181-11be-4e6a-9b11-f64361b28b18','三伏暑甚七月八日立秋是日風作凉爽炎酷頓消老病欣然命酒成二詩  其一','張耒','宋','宋诗','song-poetry','','[]','西風吹淡白，窗戶含凄清。',48,'全唐诗/poet.song.64000.json','["西風吹淡白，窗戶含凄清。", "炎凉一朝變，徂暑逝不停。", "山堂曉瀟洒，病叟巾褐輕。", "平時干雲樹，芳葉亦復零。"]'),
('58230afd-bb95-49f9-bd88-f5d12683d5aa','三伏暑甚七月八日立秋是日風作凉爽炎酷頓消老病欣然命酒成二詩  其二','張耒','宋','宋诗','song-poetry','','[]','苦熱逢三秋，西風颯然起。',48,'全唐诗/poet.song.64000.json','["苦熱逢三秋，西風颯然起。", "金氣入草木，傷夷從此始。", "盛極衰從之，循環固其理。", "老翁復何事，新凉欣酒美。"]'),
('d8506060-3c8a-48e6-ab3b-ceccee23e782','白樂天有渭上雨中獨樂十餘首倣淵明予寓宛丘居多暇日時屢秋雨倣白之作得三章  其一','張耒','宋','宋诗','song-poetry','','[]','寒極則有暑，晦久則有明。',144,'全唐诗/poet.song.64000.json','["寒極則有暑，晦久則有明。", "開闢迄今茲，此理信可憑。", "炎炎者易滅，巍巍者必傾。", "聖智無奈何，况此愚昏氓。", "設羅以獵獸，切骨陷其膺。", "重勢以鎮物，懸絕壓其肱。", "縱使賁與育，力有不獲呈。", "物情千萬變，可盡得經營。", "不如寂寞士，葛带而蘭纓。", "無求復無憂，容貌甚和平。", "况茲積雨餘，秋氣日姿清。", "悠然有佳興，美酒時一傾。"]'),
('71b7b8ad-7aba-4714-8cc5-bf8c4635043f','白樂天有渭上雨中獨樂十餘首倣淵明予寓宛丘居多暇日時屢秋雨倣白之作得三章  其二','張耒','宋','宋诗','song-poetry','','[]','罷官卧窮巷，值此雲物稠。',96,'全唐诗/poet.song.64000.json','["罷官卧窮巷，值此雲物稠。", "連延經旬雨，城市欲行舟。", "柱礎變坳塘，瓦溝成暴流。", "蕭然殘暑退，寒事戒衣裘。", "老人朝睡足，起坐梳白頭。", "呼童飭晨餐，薪濕爨婦愁。", "洗我朱提杯，不復具肴羞。", "一觴已徑醉，萬事良悠悠。"]'),
('7c2046dc-9b65-45e6-8adb-7482a8bec70a','白樂天有渭上雨中獨樂十餘首倣淵明予寓宛丘居多暇日時屢秋雨倣白之作得三章  其三','張耒','宋','宋诗','song-poetry','','[]','故人遺我酒，氣味芳以清。',84,'全唐诗/poet.song.64000.json','["故人遺我酒，氣味芳以清。", "置之屋壁間，興至時一傾。", "銀杯度一合，三釂已徹觥。", "既免戒沉湎，且無憂病酲。", "嵇阮愧令德，劉石無遐齡。", "荒狂有何樂，徒以酒自名。", "吾幸免困此，庶幾盡平生。"]'),
('ddd72b4d-84ca-4e65-a8d5-bbed7559f451','古意三首  其一','張耒','宋','宋诗','song-poetry','','[]','園中楊柳樹，飛舞似含羞。',24,'全唐诗/poet.song.64000.json','["園中楊柳樹，飛舞似含羞。", "如何風靜處，盡放眼中愁。"]'),
('3603723e-50f2-49c3-bf58-141a88390d5d','古意三首  其二','張耒','宋','宋诗','song-poetry','','[]','金鋪銀屈膝，動處有人挨。',24,'全唐诗/poet.song.64000.json','["金鋪銀屈膝，動處有人挨。", "棋盤作十字，中心爲子來。"]'),
('7f406a86-7cd8-4f8a-9e53-a89691b341ae','古意三首  其三','張耒','宋','宋诗','song-poetry','','[]','橘犀如半月，何日是圓時。',24,'全唐诗/poet.song.64000.json','["橘犀如半月，何日是圓時。", "如何一種味，却有兩人知。"]'),
('1dff503a-b8af-48b3-a40a-0fe859765e58','權勢','張耒','宋','宋诗','song-poetry','','[]','權勢世所重，桓溫役孟嘉。',72,'全唐诗/poet.song.64000.json','["權勢世所重，桓溫役孟嘉。", "桓公自人雄，爲下未足嗟。", "頗怪蔡中郎，爲董受疵瑕。", "因之以取死，曾不念漢家。", "士固感知己，尚安知其他。", "搜牢則可誅，好邕自其佳。"]'),
('64159553-c1f9-45c9-9d71-1953b7f445a7','臨文','張耒','宋','宋诗','song-poetry','','[]','一病廢百嗜，好文心未忘。',168,'全唐诗/poet.song.64000.json','["一病廢百嗜，好文心未忘。", "南窗納虛明，羅列陳縑緗。", "茫昧考巢燧，典章斷虞唐。", "清妍進屈景，雋永旌蘇張。", "少狂不自料，遇事形文章。", "誤逢作者歎，因復力披攘。", "蹉跎生白髮，始紬石室藏。", "粗見漢家事，濡毫時否臧。", "文詞比工祝，不殊公卿行。", "何用疲心精，舍本棄耕桑。", "讀賦意凌雲，律令尊張湯。", "榮華繫遇合，才技無短長。", "頗師老氏術，抱璞和其光。", "無營以卒歲，刻意翰墨場。"]'),
('0b04b28e-922d-4232-9689-df75ba3346f9','自淮陰被命守宣城復過楚雨中遇道孚因同誦楚詞爲書此以足楚詞','張耒','宋','宋诗','song-poetry','','[]','秋庭新過雨，佳菊獨秀先。',84,'全唐诗/poet.song.64000.json','["秋庭新過雨，佳菊獨秀先。", "含芳良未展，風氣已清妍。", "金鳳汝婢妾，紅紫徒相鮮。", "老人對節物，昏昏祇欲眠。", "與子讀楚詞，亹亹忽盡編。", "嫋嫋兮秋風，憀慄在遠行。", "蟋蟀鳴西堂，淹留了無成。"]'),
('6b3a23e3-a03d-4d3b-b371-3107499c5cd3','寓陳雜詩十首  其一','張耒','宋','宋诗','song-poetry','','[]','傳舍不可久，束裝投新居。',120,'全唐诗/poet.song.64000.json','["傳舍不可久，束裝投新居。", "新居亦苟完，佳木頗扶疏。", "洒掃尋丈地，琴書遣朝晡。", "風雲中夜變，大雨如决渠。", "落點若强箭，穿我老屋塗。", "中夜起明燭，移床護吾雛。", "傳聞北城隅，老弱堤上廬。", "官吏操畚鍤，紛紛役千夫。", "螘漏或一决，城闉變江湖。", "吾衰也久矣，豈復憚爲魚。"]'),
('a23dfa76-65d3-4565-9a5d-1eadd52908ad','寓陳雜詩十首  其二','張耒','宋','宋诗','song-poetry','','[]','昔記古甲子，商滅而周興。',120,'全唐诗/poet.song.64000.json','["昔記古甲子，商滅而周興。", "如何雨此日，乃爲霪雨徵。", "陰陽久乖張，此事頗有憑。", "豈天悔牧野，洗此漂杵腥。", "舊雨水未乾，洞房苔欲青。", "新雨雖霢霢，欺我牆善崩。", "虛堂就夕眠，永夜楸桐聲。", "蕭然秋氣至，豈覺巾屨輕。", "憐我老病者，三伏困薰蒸。", "得凉且飽飯，何暇念秋成。"]'),
('aae13b91-0b33-4e81-b13c-f3631f47c693','寓陳雜詩十首  其三','張耒','宋','宋诗','song-poetry','','[]','朝雨如棼絲，咫尺不相辨。',108,'全唐诗/poet.song.64000.json','["朝雨如棼絲，咫尺不相辨。", "俄然晨光漏，紺碧出天面。", "天工易明晦，頃刻俄屢變。", "今朝事大定，雲物卷組練。", "客有北來說，蝝生被數縣。", "穀穗無一粒，遺稈如立箭。", "卑田成大澤，投種哀莫見。", "官人懵不知，猶喜輸租辦。", "興懷及鰥寡，猶愧吾飽飯。"]'),
('e6aa7a7d-eb25-4d97-82c8-647b58e9693b','寓陳雜詩十首  其四','張耒','宋','宋诗','song-poetry','','[]','唐有元相國，實殺顔平原。',96,'全唐诗/poet.song.64000.json','["唐有元相國，實殺顔平原。", "平原腹有丹，尸解神已仙。", "顔公死已矣，人見如生前。", "致令遺其像，委曲與人言。", "相國死倉卒，穢襪塞其咽。", "家門隨手破，但怪椒斛千。", "顔公黄塵外，風節猶凜然。", "元子墮九幽，遺臭萬世傳。"]'),
('b301e67f-19e9-42c3-a237-c7f744f96158','寓陳雜詩十首  其五','張耒','宋','宋诗','song-poetry','','[]','清夜何晏晏，客眠亦復佳。',72,'全唐诗/poet.song.64000.json','["清夜何晏晏，客眠亦復佳。", "鄰鐘喚我覺，咽咽聞城笳。", "披衣行中庭，星漢已橫斜。", "缺月挂西南，皎皎流清華。", "莎雞振其羽，蟋蟀旁悲嗟。", "悠哉歲已秋，日月如奔車。"]'),
('e7502064-8716-4324-96ba-2ef2b920cf64','寓陳雜詩十首  其六','張耒','宋','宋诗','song-poetry','','[]','開門無客來，永日不冠履。',96,'全唐诗/poet.song.64000.json','["開門無客來，永日不冠履。", "客至我老懶，投刺輒復去。", "端成兩相忘，因得百無慮。", "故人在旁郡，書信不能屢。", "興哀東城公，將掩郟山墓。", "不能往一慟，名義真有負。", "可能金玉骨，亦遂黄壤腐。", "但恐已神仙，裂石終飛去。"]'),
('3ec2a2f1-bd17-4fd5-9886-41d97a2ea073','寓陳雜詩十首  其七','張耒','宋','宋诗','song-poetry','','[]','疲馬齕故草，閉門苔蘚深。',72,'全唐诗/poet.song.64000.json','["疲馬齕故草，閉門苔蘚深。", "閒坊居人少，秋日疏槐陰。", "境寂心亦閒，蕭然散巾襟。", "靜中有深趣，因見至人心。", "谷神古不死，茲理良可尋。", "無令兒輩覺，一撫無弦琴。"]'),
('fac3e3a7-b82e-4cf0-b54e-3cfdbadc0476','寓陳雜詩十首  其八','張耒','宋','宋诗','song-poetry','','[]','念昔爲吏日，朝夕羨人閒。',96,'全唐诗/poet.song.64000.json','["念昔爲吏日，朝夕羨人閒。", "解印出公府，翛然若歸山。", "衡茅三畝居，無客門常關。", "早眠而起晏，永日或不冠。", "故人遠寄酒，爲致一醉歡。", "我亦領其意，呼兒具杯盤。", "長閒貧亦好，安用朱其轓。", "我生本蓬蓽，久已傲饑寒。"]'),
('13334282-cf7c-4c06-94f6-a663dbded683','寓陳雜詩十首  其九','張耒','宋','宋诗','song-poetry','','[]','我不知暑退，但覺衣汗乾。',96,'全唐诗/poet.song.64000.json','["我不知暑退，但覺衣汗乾。", "頗怪庭中天，湛然青已寬。", "有物叫草根，啾啾自相喧。", "問知已新秋，大火流金天。", "九土變寒暑，正爾事亦繁。", "靜觀付一笑，吾事寧相關。", "但無筋力健，悠然佳意還。", "喧喧憎鄰里，砧杵亂人眠。"]'),
('a9b2ac64-9fb5-440c-a26a-62a5543463d6','寓陳雜詩十首  其一○','張耒','宋','宋诗','song-poetry','','[]','秦子死南海，旋骨還故墟。',96,'全唐诗/poet.song.64000.json','["秦子死南海，旋骨還故墟。", "辛勤一生事，空得數編書。", "琅琅巧言語，玉佩聯瓊琚。", "知者能幾人，憎者頗有餘。", "書生事業薄，生世苦勤劬。", "持以待後世，何足潤槁枯。", "興懷及昔者，使我涕漣如。", "道路阻且長，悲哉違撫孤。"]'),
('a71644d0-542d-4c47-8473-e5f535666471','寄李端叔二首  其一','張耒','宋','宋诗','song-poetry','','[]','束髮聞至道，榮辱久齊觀。',144,'全唐诗/poet.song.64000.json','["束髮聞至道，榮辱久齊觀。", "中年嬰世故，已復傲憂患。", "閒居雖荒寂，几杖頗清晏。", "悠悠閒晷景，草草貧寢飯。", "狂言無爲發，濁酒醉自勸。", "與君通家舊，邇者頗屢見。", "相望豈示遠，數舍隔異縣。", "吾人師佛祖，妙旨得忍粲。", "斂藏避世俗，未免逢侮訕。", "坐令鬢垂雪，猶把從事版。", "尺書每見警，妙語珠在貫。", "復君進明德，同遂丘壑願。"]'),
('07d89137-752a-4e4b-a9e0-dbefdb193231','寄李端叔二首  其二','張耒','宋','宋诗','song-poetry','','[]','陳墟自古皇，疆野實楚縣。',132,'全唐诗/poet.song.64000.json','["陳墟自古皇，疆野實楚縣。", "沃野接神畿，荒溝漕淮甸。", "民風靜而陋，原隰平以遠。", "我來逢艱歲，禾黍秋色淺。", "荒居困蛩蚓，風雨老藜莧。", "閉門謝車馬，隠几親筆硯。", "馬跡巷泥深，庖烟簷日宴。", "深居窺老易，妙理殊自玩。", "困亨方寸足，夸安勞遠願。", "乖離感歲月，老色各滿面。", "友道古所敦，尺書莫辭倦。"]'),
('ceafa643-e923-4d1b-b357-743258f76d21','秋日曬古城','張耒','宋','宋诗','song-poetry','','[]','秋日曬古城，西風振塵埃。',72,'全唐诗/poet.song.64000.json','["秋日曬古城，西風振塵埃。", "出門何所之，壞道連蒿萊。", "飛鳴雞犬稀，破屋枯壕隈。", "老圃理蔬畦，晚甲瘦未開。", "輸人暮出城，栖鴉一一回。", "悵然心不怡，歸坐勸一杯。"]'),
('bebaed9a-5fb1-4648-9bdf-3f864c994cc0','古意效東野二首  其一','張耒','宋','宋诗','song-poetry','','[]','與君雖異坊，秋凉各平分。',48,'全唐诗/poet.song.64000.json','["與君雖異坊，秋凉各平分。", "已遣月入牖，更教風掃門。", "照君幌中寢，拂君堂上塵。", "綢繆似衣带，終日遶君身。"]'),
('a85c162d-c5f5-40da-9b27-31cb381ebe2e','古意效東野二首  其二','張耒','宋','宋诗','song-poetry','','[]','扇不風自凉，身不蘭自香。',48,'全唐诗/poet.song.64000.json','["扇不風自凉，身不蘭自香。", "深居不出門，幽獨更清揚。", "爲鵲栖君樹，爲燕巢君堂。", "不食亦可飽，况乃餐輝光。"]'),
('25e440cc-aaeb-4d8d-8fdf-8a3c439f5023','早稻','張耒','宋','宋诗','song-poetry','','[]','早稻如倒戈，十穗八九折。',96,'全唐诗/poet.song.64000.json','["早稻如倒戈，十穗八九折。", "晚稻不及秀，日炙根土烈。", "踏車激湖水，車衆湖欲竭。", "得泉如沸湯，旱土濕未徹。", "老農祝天工，叩額眼垂血。", "游雲不作雨，風至輒散滅。", "昊天未悔禍，牲玉無徒設。", "誰能縛妖魃，敕起龍潑剌。"]'),
('dcfb06cf-3077-4689-8f8f-4f5370503863','鳴蜩','張耒','宋','宋诗','song-poetry','','[]','鳴蜩嘒高風，逮夜且復靜。',72,'全唐诗/poet.song.64000.json','["鳴蜩嘒高風，逮夜且復靜。", "草蟲何爲者，落日鳴復逞。", "陰陽且戰爭，微物何所競。", "化工執其機，開闔惟所命。", "朔雁有行意，肅肅如待令。", "江河有舊渚，寧畏風霜勁。"]'),
('1ac7c526-5b7d-47ad-a7e4-3c84cff0e4fb','書初凉夜至將曉','張耒','宋','宋诗','song-poetry','','[]','秋房燈火清，人語久已寂。',156,'全唐诗/poet.song.64000.json','["秋房燈火清，人語久已寂。", "城遠不聞更，警柝鳴未息。", "橫參已入地，斗柄當天直。", "乃知三更中，市廛已寂歷。", "我時守書几，磨墨傾硯滴。", "反覆小學書，昏目如芒刺。", "試尋鄰房僧，鼻鼾背負壁。", "體勞徑就枕，冷夢分南北。", "覺來寺鐘鳴，僧禮像前席。", "須臾聞梵唄，木魚如叩石。", "舉頭視東牖，朝日已淡白。", "反身起披衣，神爽健筋力。", "亟來酒甕邊，側聽聲唧唧。"]'),
('f014236e-eadd-4103-9da6-0bd9bf76b08c','秋日喜楊介吉老寄藥','張耒','宋','宋诗','song-poetry','','[]','閒坊遠市聲，終日掩衡門。',96,'全唐诗/poet.song.64000.json','["閒坊遠市聲，終日掩衡門。", "惟有風中葉，蕭騷終日聞。", "午枕不成寐，起坐無與言。", "喜開故人書，珍藥幸見存。", "其方受仙聖，其效未易論。", "豈惟蠲沉痾，庶可輔本根。", "珍重復珍重，厥價萬璵璠。", "永年未可冀，庶保無夭昏。"]'),
('474ae8df-e0fa-4d7c-93c3-c1691fdaf9e2','見黄仲達感秋意','張耒','宋','宋诗','song-poetry','','[]','秋風吹衡茅，寂歷如荒村。',132,'全唐诗/poet.song.64000.json','["秋風吹衡茅，寂歷如荒村。", "獨立無與語，悲蟲鳴草根。", "老木經疾風，枝葉僅得存。", "疏蔭不滿地，白日耿當軒。", "北城有黄仲，眸子清不渾。", "時能出秀句，寶鐵雕璵璠。", "念將舍我去，爲吏國西京。", "荒凉古中牟，晝夜輪蹄奔。", "青衫給吏役，懷惡未易論。", "强顔詭應接，有抱誰能言。", "從容來去間，無厭走黄昏。"]'),
('2e22b04e-92ab-4435-8572-f3a76174fc99','服仙靈脾酒','張耒','宋','宋诗','song-poetry','','[]','冷氣侵吾髀，趨拜劇苦艱。',132,'全唐诗/poet.song.64000.json','["冷氣侵吾髀，趨拜劇苦艱。", "仁哉神農氏，遺藥驅恫瘝。", "持錢取之市，易得如茆芫。", "繁枝與芳葉，盡取無可刪。", "貯之白縑囊，漬以壺酒寬。", "七日以供飲，跛曳皆翩躚。", "呼兒謹蓋藏，用此九轉丹。", "平生誤信書，安坐得老邅。", "方書豈盡信，柳子固無言。", "事固有然者，豈容盡欺謾。", "疾走非吾願，且復補羸殘。"]'),
('aea823d5-f4a8-4217-80dc-a30ba5bc9e1e','孫志康許爲南釀前日已聞糴米欣然作詩以問之','張耒','宋','宋诗','song-poetry','','[]','平生一尊酒，風月不可無。',192,'全唐诗/poet.song.64000.json','["平生一尊酒，風月不可無。", "謫官將十年，一醉未易圖。", "市豈無旗亭，官亦有酒壚。", "薄乃捩齒酸，一滴不可沽。", "英英孫夫子，臭味真吾徒。", "自云得異糵，乃出粳稻腴。", "歲久精粹出，去者乃其粗。", "醖釀纔浹日，芳甘已盈壺。", "傖人喻其力，若火經茅蘆。", "此語真野陋，殆出負販夫。", "前日聞吉語，糴米已在途。", "每恨乏陳糯，價直如買珠。", "憐君久客囊，傾倒無復餘。", "假器走僕僮，供我一笑娛。", "欲爲漉巾潜，請學滌器如。", "作詩以訊之，何日陳尊盂。"]'),
('0e0d3d3f-74e7-45bc-a5a4-793baeb3e533','夜書','張耒','宋','宋诗','song-poetry','','[]','黯黯夜烟青，寥寥秋漢迥。',48,'全唐诗/poet.song.64000.json','["黯黯夜烟青，寥寥秋漢迥。", "海月出天高，霜雲泊天靜。", "鶴鳴知露寒，樹影當軒正。", "幽客獨未眠，經窗夜聲磬。"]'),
('b0b4f011-b6fe-4515-89b6-25c1a25ef799','小雨','張耒','宋','宋诗','song-poetry','','[]','稍稍陰靄集，蕭肅春寒生。',48,'全唐诗/poet.song.64000.json','["稍稍陰靄集，蕭肅春寒生。", "窗燈耿初照，小雨細無聲。", "還來就溫爐，依然有故情。", "燕坐悄無語，軍城遞遠更。"]'),
('ede9e2e2-86eb-4562-9710-b0a2b12944e1','月夜懷陳永源','張耒','宋','宋诗','song-poetry','','[]','衆喧息遙夜，爽氣漬煩襟。',48,'全唐诗/poet.song.64000.json','["衆喧息遙夜，爽氣漬煩襟。", "殷勤低簷月，入幌來相尋。", "平生學虛靜，每爲多病侵。", "卧想陳夫子，幅巾修竹林。"]'),
('9a901562-19f5-4a80-b0d5-f3a21e3b46e9','冬日放言二十一首  其一','張耒','宋','宋诗','song-poetry','','[]','清冬萬境肅，牆戶益蕭然。',48,'全唐诗/poet.song.64000.json','["清冬萬境肅，牆戶益蕭然。", "薄寒惟可飲，短景不容眠。", "貧厨烟火暖，塵釜亦烹鮮。", "且復養口體，何勞更問天。"]'),
('955ac53b-546e-4835-a67c-5b75fe4a454d','冬日放言二十一首  其二','張耒','宋','宋诗','song-poetry','','[]','湯餠慰朝餒，三杯澆旦寒。',48,'全唐诗/poet.song.64000.json','["湯餠慰朝餒，三杯澆旦寒。", "醉飽外何欲，昏然宵就眠。", "幽通夢有告，默存神自全。", "蕭蕭松竹舍，歲暮聊盤桓。"]'),
('d7ca0b72-54e6-4fb3-afb4-c9846ae795a9','冬日放言二十一首  其三','張耒','宋','宋诗','song-poetry','','[]','風雨連江氣，十月如深冬。',48,'全唐诗/poet.song.64000.json','["風雨連江氣，十月如深冬。", "坐曹日暮歸，密室溫爐紅。", "慘慘庭下日，騷騷窗外風。", "三杯容我醉，萬事聽天工。"]'),
('3bfefa68-dadd-4676-b3ac-41cc13844cbf','冬日放言二十一首  其四','張耒','宋','宋诗','song-poetry','','[]','小兒喜學書，滿紙如塗鴉。',48,'全唐诗/poet.song.64000.json','["小兒喜學書，滿紙如塗鴉。", "老婦寒不績，當戶理琵琶。", "樽中有神物，快瀉如流霞。", "三杯任兀兀，凍臉生春華。"]'),
('36a33b05-94d8-4210-ba98-842b315152ac','冬日放言二十一首  其五','張耒','宋','宋诗','song-poetry','','[]','卯飲終日醉，萬事付悠悠。',48,'全唐诗/poet.song.64000.json','["卯飲終日醉，萬事付悠悠。", "醺然據榻瞑，簷雨方颼颼。", "吾事幸無急，不醉欲何求。", "顧謂婦與子，酒盡爲我謀。"]'),
('234d4d15-dd11-44a1-a813-f8442f736437','冬日放言二十一首  其六','張耒','宋','宋诗','song-poetry','','[]','寒羊肉如膏，江魚如切玉。',48,'全唐诗/poet.song.64000.json','["寒羊肉如膏，江魚如切玉。", "肥兔與奔鶉，日夕懸庖屋。", "嬉嬉顧妻孥，滋味喉可欲。", "謫官但强名，比者何不足。"]'),
('36884844-8157-48ac-aabb-335824ece280','冬日放言二十一首  其七','張耒','宋','宋诗','song-poetry','','[]','酒聖卯時歡，此語聞樂天。',48,'全唐诗/poet.song.64000.json','["酒聖卯時歡，此語聞樂天。", "安用苦了了，白日供憂煎。", "浮世本幻妄，空花電露然。", "人間無實事，惟醉庶幾焉。"]'),
('ba71cb99-d81d-45a4-8aed-ac26976ff1fb','冬日放言二十一首  其八','張耒','宋','宋诗','song-poetry','','[]','愈老愈嗜酒，益醉益自然。',48,'全唐诗/poet.song.64000.json','["愈老愈嗜酒，益醉益自然。", "兩人同墜車，醉者乃得全。", "我不但醉酒，天和醉心源。", "當其醉甚時，更類癡與頑。"]'),
('031f80f1-867f-4402-9d3b-50da4dbf9211','冬日放言二十一首  其九','張耒','宋','宋诗','song-poetry','','[]','至道與物反，夫豈會俗心。',48,'全唐诗/poet.song.64000.json','["至道與物反，夫豈會俗心。", "聖處有閫域，扃鑰一何深。", "時時資美酒，可得及其門。", "送君者既返，君駕胡可尋。"]'),
('867650a0-bb5a-4925-a075-5187cfb8e24c','冬日放言二十一首  其一○','張耒','宋','宋诗','song-poetry','','[]','清晨坐官舍，官舍復何有。',48,'全唐诗/poet.song.64000.json','["清晨坐官舍，官舍復何有。", "離披經雨菊，蕭疏委風柳。", "飽食或至睡，涉筆無可否。", "油然有好懷，日暮歸飲酒。"]'),
('0679d31a-ccfd-463b-a7c6-990478911518','冬日放言二十一首  其一一','張耒','宋','宋诗','song-poetry','','[]','日暮歸飲酒，兒女戲我前。',48,'全唐诗/poet.song.64000.json','["日暮歸飲酒，兒女戲我前。", "須臾徑三酌，據榻已欣然。", "老妻坐我傍，餚胾已炮煎。", "大勝劉伶婦，區區爲酒錢。"]'),
('54ad1578-e65b-480f-bd45-f5db42f1fd20','冬日放言二十一首  其一二','張耒','宋','宋诗','song-poetry','','[]','我初謫官時，帝問司酒神。',48,'全唐诗/poet.song.64000.json','["我初謫官時，帝問司酒神。", "曰此好酒徒，聊給酒養真。", "去國一千里，齊安酒最醇。", "失火而遇雨，仰戴天公仁。"]'),
('3bf5c350-c22c-4d43-8ce8-64d700e1e569','冬日放言二十一首  其一三','張耒','宋','宋诗','song-poetry','','[]','吾腹如鴟夷，但滿貯醇酒。',48,'全唐诗/poet.song.64000.json','["吾腹如鴟夷，但滿貯醇酒。", "外圓故不滯，中靜一無有。", "紛紛千百輩，納若一塵垢。", "下而至真源，保之故難朽。"]'),
('ae06147d-a4cb-466a-8137-acb2b8173fdd','冬日放言二十一首  其一四','張耒','宋','宋诗','song-poetry','','[]','淮陽名都會，爽塏太昊墟。',48,'全唐诗/poet.song.64000.json','["淮陽名都會，爽塏太昊墟。", "最愛西城道，汪汪數頃湖。", "古木巢翠鳥，清濠見游魚。", "幽居多不愜，懷我平生娛。"]'),
('21e503b6-b110-4c69-883e-d108864b665b','冬日放言二十一首  其一五','張耒','宋','宋诗','song-poetry','','[]','靈通古叢林，他日休吾車。',48,'全唐诗/poet.song.64000.json','["靈通古叢林，他日休吾車。", "出門循古城，荒圃畦寒蔬。", "手種堂下花，頗已數尺餘。", "何人攬其華，故人應念予。"]'),
('0df3c10b-1c82-4711-bb8b-63aff664f30f','冬日放言二十一首  其一六','張耒','宋','宋诗','song-poetry','','[]','塞向久室處，帟幕亦復周。',48,'全唐诗/poet.song.64000.json','["塞向久室處，帟幕亦復周。", "溫爐熾薪炭，永夜炎光流。", "五更屋霜重，重衾如無裘。", "興懷無衣子，卒歲聊優游。"]'),
('1b3edaa5-b78f-41e8-b860-78d9da4aaa1a','冬日放言二十一首  其一七','張耒','宋','宋诗','song-poetry','','[]','陶潜經世才，齟齬不得肆。',48,'全唐诗/poet.song.64000.json','["陶潜經世才，齟齬不得肆。", "彼寧徒嗜飲，有藴託諸醉。", "時時吐高詞，頗復見一二。", "義熙書甲子，此意有涇渭。"]'),
('c11d0c08-d390-4549-90aa-c407e7feb18b','冬日放言二十一首  其一八','張耒','宋','宋诗','song-poetry','','[]','葛公蓋世才，功業亦云偶。',48,'全唐诗/poet.song.64000.json','["葛公蓋世才，功業亦云偶。", "世無左將軍，老作躬耕叟。", "皇天挺奇産，必使有所受。", "珠玉在山淵，終爲王府有。"]'),
('4e805c5f-66cd-4e5c-9139-2091ac1d4164','冬日放言二十一首  其一九','張耒','宋','宋诗','song-poetry','','[]','秦人焚詩書，意欲遂絕滅。',48,'全唐诗/poet.song.64000.json','["秦人焚詩書，意欲遂絕滅。", "六經至今存，何曾損毫髮。", "興衰有天理，人力自淺拙。", "不憂驪山墓，回首遭發掘。"]'),
('a73de438-97b2-4990-812a-04b484162544','冬日放言二十一首  其二○','張耒','宋','宋诗','song-poetry','','[]','元子本豪爽，頗復有俗氣。',48,'全唐诗/poet.song.64000.json','["元子本豪爽，頗復有俗氣。", "孟嘉亦可人，乃與較權勢。", "崛强盡百年，究竟成何事。", "江左無英雄，汝得免徒隸。"]'),
('4d428983-ffec-47fb-86ed-07ade4d14a9a','冬日放言二十一首  其二一','張耒','宋','宋诗','song-poetry','','[]','淵明非無心，似以酒忘憂。',48,'全唐诗/poet.song.64000.json','["淵明非無心，似以酒忘憂。", "如以藥愈疾，未佳寧免憂。", "我直好飲耳，與世本悠悠。", "人間有何事，奚足煩杯甌。"]'),
('4d4e8be9-bc37-4c45-84da-d65a0c9116cd','四月望日自孝悌坊遷冠蓋孫氏第','張耒','宋','宋诗','song-poetry','','[]','青蕪滿古城，白日照大澤。',120,'全唐诗/poet.song.64000.json','["青蕪滿古城，白日照大澤。", "街荒雞犬鬧，市遠喧閧寂。", "中有騰騰者，淮陽四年客。", "坐偷太倉粟，穩睡而飽食。", "平生願陳力，衰老困逼迫。", "何曾一可意，但有百無益。", "偷安淺夫志，苟且志士惜。", "窮通有天理，誓不安苟得。", "朱陽方肇序，春去無轍迹。", "悵此復幾時，撫事三歎息。"]'),
('49b69181-2db1-4ba1-ac12-61c73d6324db','謫官','張耒','宋','宋诗','song-poetry','','[]','謫官成吏隠，古寺度高秋。',48,'全唐诗/poet.song.64000.json','["謫官成吏隠，古寺度高秋。", "寒燈明夜室，清坐聞更籌。", "裘葛屢往還，感彼歲月遒。", "吾意方有會，誰能賦離憂。"]'),
('cb1663db-13af-477e-a8dd-8c9d1b5585ee','十月二十二日晚作三首  其一','張耒','宋','宋诗','song-poetry','','[]','黯黯東牖闇，寂寂吾廬閒。',48,'全唐诗/poet.song.64000.json','["黯黯東牖闇，寂寂吾廬閒。", "粗糲飽婦子，苜蓿無餘盤。", "雁急天欲雨，雞栖日已寒。", "老人袖手坐，一杯聊自寬。"]'),
('c176b151-ef04-4810-b8fe-3e04be269759','十月二十二日晚作三首  其二','張耒','宋','宋诗','song-poetry','','[]','天寒聊飲酒，再酌已停觴。',48,'全唐诗/poet.song.64000.json','["天寒聊飲酒，再酌已停觴。", "豈不欲酣暢，要使夜腹康。", "意得樂有餘，偶然不必長。", "寄身造化中，勿使天和傷。"]'),
('a8f9703a-e5fd-437e-8244-e08351f98804','十月二十二日晚作三首  其三','張耒','宋','宋诗','song-poetry','','[]','蓬蓽無奧處，北風利戈鋋。',48,'全唐诗/poet.song.64000.json','["蓬蓽無奧處，北風利戈鋋。", "空爐有微火，且復與周旋。", "酒隠柴桑叟，醉吟渭上賢。", "二士忽已遠，遺風載陳編。"]'),
('8d3db9da-77ae-4afc-a8ad-251138a654a9','題壁','張耒','宋','宋诗','song-poetry','','[]','命駕欲詣客，欲去復遲遲。',48,'全唐诗/poet.song.64000.json','["命駕欲詣客，欲去復遲遲。", "事幸無甚急，何用勞驅馳。", "家貧幸有酒，亦略具鮮肥。", "且復東窗下，高歌醉而嬉。"]'),
('e90f6fdc-f3bd-4134-9f1e-0c148465b924','夜坐','張耒','宋','宋诗','song-poetry','','[]','萬籟聲久寂，三更霜已寒。',48,'全唐诗/poet.song.64000.json','["萬籟聲久寂，三更霜已寒。", "老人袖手坐，一氣中自存。", "自得此中趣，不與兒曹論。", "但有老孟光，相對亦無言。"]'),
('be671986-ee5d-40ed-833d-3b016bee5e7e','任仲微閱世亭','張耒','宋','宋诗','song-poetry','','[]','志士抱奇策，常苦不得伸。',108,'全唐诗/poet.song.64000.json','["志士抱奇策，常苦不得伸。", "及其利害出，倏已亡其人。", "今古同此恨，愚智竟誰分。", "哀哉老任公，英魄久已淪。", "惟餘亭下柏，閱世盤深根。", "紛紛凡草木，幾變秋與春。", "朝菌與蟪蛄，盡死我獨存。", "任公不及見，見其賢子孫。", "請君利斯奇，仍復大其門。"]'),
('0aab607b-4a52-46fa-b724-8e6c9ce5e640','感懷','張耒','宋','宋诗','song-poetry','','[]','枯樹桓司馬，五柳陶徵君。',48,'全唐诗/poet.song.64000.json','["枯樹桓司馬，五柳陶徵君。", "微木何足道，所歎此兩人。", "一埋柴桑骨，一爲九錫臣。", "榮辱俱已矣，芳穢萬世聞。"]'),
('3eaa69c9-7bb5-4750-bcd9-3cbfadc5547c','次韵題李援舫子','張耒','宋','宋诗','song-poetry','','[]','紫髯不復見，故宮無入門。',48,'全唐诗/poet.song.64000.json','["紫髯不復見，故宮無入門。", "元子亦寂寞，一丘弔遺魂。", "興亡兩夢幻，今古一朝昏。", "念當置是事，盡此舟中樽。"]'),
('fceef120-114c-4566-9ac3-f3d839bb8674','秋感二首  其一','張耒','宋','宋诗','song-poetry','','[]','秋日無遠暉，秋草無美姿。',72,'全唐诗/poet.song.64000.json','["秋日無遠暉，秋草無美姿。", "殘蛩弔白日，寒鳥悲空枝。", "時節一如此，余出悵安歸。", "强歌不成音，還坐空涕垂。", "感動百慮遊，觸心遂紛披。", "棄捐勿復道，日暮眠吾帷。"]'),
('589b1701-ade0-4760-899f-209df6a1cb86','秋感二首  其二','張耒','宋','宋诗','song-poetry','','[]','秋山多遠聲，日暮尤百態。',96,'全唐诗/poet.song.64000.json','["秋山多遠聲，日暮尤百態。", "鳴風落高樹，清澗瀉寒瀨。", "鳴蜩默誰憐，瘖死不償罪。", "蛩啼獨不已，有愬未逢解。", "天時激汝曹，寧自知進退。", "吹噓成踴躍，芻狗忌撤祭。", "庭空月宵掛，園冷露晨沛。", "嗟哉心雖忘，俯事還感慨。"]'),
('9d70e844-a5e6-4687-88c1-231f483963e8','夜思','張耒','宋','宋诗','song-poetry','','[]','江邊鸕鷀鳴，栖我屋南樹。',48,'全唐诗/poet.song.64000.json','["江邊鸕鷀鳴，栖我屋南樹。", "夜深風霜寒，呼鳴自相語。", "樹頭鴉翼動，樹杪雁行度。", "朦朧見江山，一一翻飛去。"]'),
('93e1f5ee-34ce-45ae-ad43-8065aebc8745','嘲南商','張耒','宋','宋诗','song-poetry','','[]','兩袖全匹帛，望知江淮客。',48,'全唐诗/poet.song.64000.json','["兩袖全匹帛，望知江淮客。", "深藏計算苦，好鬭意氣窄。", "愁逢湯餠碗，遇鮓論甕咋。", "市南沽茅柴，歸店兩顴赤。"]'),
('e22c5960-890f-46f4-8f3b-f1fbd4e85a09','種芭蕉','張耒','宋','宋诗','song-poetry','','[]','幽居玩芳物，自種兩芭蕉。',48,'全唐诗/poet.song.64000.json','["幽居玩芳物，自種兩芭蕉。", "空山夜雨至，滴滴復蕭蕭。", "凉葉泛朝露，芳心展夕飈。", "東堂日虛靜，秀色慰無聊。"]'),
('2a323440-6014-49e0-bce9-65cc57c64fa9','無題','張耒','宋','宋诗','song-poetry','','[]','蔌蔌鳴葉下，初無風過之。',48,'全唐诗/poet.song.64000.json','["蔌蔌鳴葉下，初無風過之。", "流年一如此，慷慨使心悲。", "平日談堯舜，立朝羞自私。", "溫爐煖老客，聊復此棲遲。"]'),
('cb175968-80a3-4698-8f22-ff66dd3bb7ed','大雨十日不止五月十八日晚始霽','張耒','宋','宋诗','song-poetry','','[]','昊穹忽悔禍，淫雨霽今夕。',48,'全唐诗/poet.song.64000.json','["昊穹忽悔禍，淫雨霽今夕。", "峰嶺舒紫翠，雲天麗金碧。", "深蛙鳴遠汪，凉葉墜餘滴。", "漏屋百不憂，宵眠始安席。"]'),
('cc953ba9-0e82-464e-bebe-d9d8cd72e365','天運','張耒','宋','宋诗','song-poetry','','[]','天運不暫止，何啻過隙駒。',48,'全唐诗/poet.song.64000.json','["天運不暫止，何啻過隙駒。", "向來簷前日，忽已牆東隅。", "樂者苦其疾，憂者怨其舒。", "由來盛與衰，變滅皆須臾。"]'),
('1e4c88cb-483b-4e0b-bdc4-9ecc002188fc','悼逝','張耒','宋','宋诗','song-poetry','','[]','結髮爲夫婦，少年共饑寒。',144,'全唐诗/poet.song.64000.json','["結髮爲夫婦，少年共饑寒。", "我迂趨世拙，十載困微官。", "男兒不終窮，會展淩風翰。", "相期脫崎嶇，一笑紓艱難。", "秋風摧芳蕙，既去不可還。", "滴我眼中血，悲哉摧肺肝。", "兒稚立我前，求母夜不眠。", "我雖欲告之，哽咽不能言。", "積金雖至斗，紆朱走華軒。", "失我同心人，撫事皆悲酸。", "積日而成時，積時更成年。", "山海會崩竭，音容永茫然。"]'),
('525572aa-843b-4a6f-b83f-a8796256d2c7','喜雨四首  其一','張耒','宋','宋诗','song-poetry','','[]','陰陽不暫駐，今夕已秋風。',48,'全唐诗/poet.song.64000.json','["陰陽不暫駐，今夕已秋風。", "晨興綿絲冷，歲月驚衰翁。", "朝烟爨薪濕，小甲蔬畦空。", "且復一杯酒，吾生不終窮。"]'),
('b42bdd1d-1d8e-4ad9-aecf-db33ed80936b','喜雨四首  其二','張耒','宋','宋诗','song-poetry','','[]','手種五色蕉，意待聽秋雨。',48,'全唐诗/poet.song.64000.json','["手種五色蕉，意待聽秋雨。", "南風扇旱日，破葉萎不舉。", "霶𩃱未終夕，綠潤遽如許。", "秋色入書幃，已覺青鸞舞。"]'),
('7ba50f9b-fe36-46ed-bf49-9fae921ecb23','喜雨四首  其三','張耒','宋','宋诗','song-poetry','','[]','牆東有高樹，夏葉圓綠綺。',48,'全唐诗/poet.song.64000.json','["牆東有高樹，夏葉圓綠綺。", "西風纔一夕，蕭颯遽如此。", "寒螿號其顛，蟋蟀曉未已。", "羣動催流光，榮華難久恃。"]'),
('d35983bb-c469-4114-8387-1e5fdf724839','喜雨四首  其四','張耒','宋','宋诗','song-poetry','','[]','隙地秋日曉，寂無鄰里音。',48,'全唐诗/poet.song.64000.json','["隙地秋日曉，寂無鄰里音。", "惟有草根蟲，風前咽復吟。", "悲歌者誰子，徂年驚苦心。", "青燈夜齋靜，微溫生薄衾。"]'),
('caf0ba4f-1fa1-41f4-849c-669825928025','次韵曾存之直舍種竹','張耒','宋','宋诗','song-poetry','','[]','曾郎風塵表，不似宰官身。',60,'全唐诗/poet.song.64000.json','["曾郎風塵表，不似宰官身。", "吏舍數竿竹，鑿池水粼粼。", "此君不可疏，亦復未易親。", "虛心澹相授，頗似南郭鄰。", "我知王子猷，正是君輩人。"]'),
('9cabb94b-0c8f-4182-b4cd-758d71573f1f','贈蔡彥規','張耒','宋','宋诗','song-poetry','','[]','我不見蔡子，杜門十日餘。',288,'全唐诗/poet.song.64000.json','["我不見蔡子，杜門十日餘。", "今日叩我門，滿手携瓊琚。", "鏗鏘寫我前，雜以貝與珠。", "我愕不知報，低頭驚且吁。", "讀畢致於懷，餘光溢衿裾。", "坐令簞瓢室，磊犖堆璠璵。", "我拙寡所合，甘爲不材樗。", "嗟君何所聞，屢枉長者車。", "我來淮南遊，靄靄子之譽。", "驊騮走千里，凡馬安能逾。", "奈予不自量，痛鞭而疾驅。", "常憂過所往，疲憊傷吾軀。", "願君少待我，且欲休吾駒。", "跳奔舍其羣，子樂誰與俱。", "俯身援其類，是亦仁之徒。", "不然但用我，畏甚將逃逋。", "何如少待之，效技供子娛。", "我無功名願，與世日益疏。", "反慕古沮溺，窮年事耕鋤。", "皇皇吾夫子，憂世亦勤劬。", "雖然竟何就，孰若安以居。", "人生各有懷，未用相賢愚。", "得樂願即止，安能較錙銖。", "又疑異所任，勞逸事亦殊。"]'),
('7cd50a4e-1625-48b6-92d8-2868c01ff499','寄劉伯聲','張耒','宋','宋诗','song-poetry','','[]','別君幾何時，人事浩千萬。',264,'全唐诗/poet.song.64000.json','["別君幾何時，人事浩千萬。", "身如張射侯，憂愁劇强箭。", "崎嶇走窮縣，艱苦君未見。", "未知菽水豐，已感霜露變。", "羈孤寄窮海，親友誰弔唁。", "析圖補冬裘，乞米煮朝飯。", "無聊猶自思，援溺固誰願。", "人生不終否，此語非我分。", "英雄伏泥塗，暫晦久必現。", "如予百不能，理自合貧賤。", "豈當議隠顯，而有不遇歎。", "但思竄山林，遠脫人世患。", "有田足耕耘，有水足罩汕。", "蕭然便終老，到死百不問。", "平生泥佛祖，久已師壁觀。", "况將無生禪，下視有爲幻。", "吾子出羣材，千牛有餘刃。", "行當脫塵埃，鳴佩侍清燕。", "高卑各有得，願勿譏尺鷃。", "不有行道人，誰當佐堯舜。", "時哉勿自滯，功業在力勸。", "握手不可期，此計吾行辨。"]'),
('21fb6944-1c05-4218-8e35-a335c8ba75ff','寄陳九','張耒','宋','宋诗','song-poetry','','[]','別來常思君，無異饑待哺。',216,'全唐诗/poet.song.64000.json','["別來常思君，無異饑待哺。", "如何偶相逢，握手復告去。", "念初別子時，芳草才及屨。", "天時不可留，再見歲云暮。", "出門怪子瘦，告我困道路。", "飄飄千餘里，陸走復水泝。", "古來黄金盡，壯士色亦沮。", "斯人獨何少，乃有衣食慮。", "才高窮不怨，志大貧若富。", "吾將告君理，子其聽我佈。", "人生不終窮，否泰亦有數。", "子其保所有，錐穎囊必露。", "古來立功名，其始不無忤。", "得難失自寡，進銳退亦遽。", "念君歸海瀕，誰與朝夕聚。", "我方困而學，每冀朋友助。", "一從城北歸，夢魂見已屢。", "願因南來者，時以尺書寓。"]'),
('44c3ff23-638f-4091-86b2-46b5e8822546','贈江瞻道','張耒','宋','宋诗','song-poetry','','[]','我行於四方，其所急者友。',288,'全唐诗/poet.song.64000.json','["我行於四方，其所急者友。", "嗚呼得之難，百不一邂逅。", "人心不可齊，若十指於手。", "隨其短與長，亦各有所取。", "剛或硬而折，柔有弱而仆。", "質良文不揚，中美外莫副。", "寬壺泛以枵，狹盎迫而陋。", "此猶其大概，瑣瑣難悉究。", "譬如選長材，棄百不一有。", "其間雖得之，猶或煩矯揉。", "我友居淮濱，飲德悉自幼。", "豈期羈旅間，乃獲聞謦欬。", "嗟君如美玉，外徹中乃厚。", "埋藏困塵埃，要以不可垢。", "他人十不一，子乃得八九。", "餘虧能幾何，不待勉而就。", "乃知昔求艱，特以見未久。", "但憂奔莫及，敢憚喘而走。", "我心子所知，濩豁無所囿。", "是以行於世，往往得嘲詬。", "人才如其面，不自知好醜。", "立之明鑑前，乃見其可否。", "子於我無嫌，告我當苦口。", "惟我於改過，竊不敢自後。"]'),
('9e1fa84a-c1f9-4ecd-9c45-f585a7b76b88','呈徐仲車','張耒','宋','宋诗','song-poetry','','[]','朝日照高簷，夜霜猶在瓦。',108,'全唐诗/poet.song.64000.json','["朝日照高簷，夜霜猶在瓦。", "纖纖牆邊柳，春色已可把。", "殘年能幾何，奔駛劇湍瀉。", "雖無功名求，衰暮亦悲咤。", "出門問徐子，兩計决取舍。", "爲當勉自修，汲汲不可暇。", "爲當飲美酒，送老在杯斝。", "子當指我途，我即策其馬。", "但我懶拙姿，終非服勤者。"]'),
('96cee944-2e61-4f9e-906c-d9b7bf53edc8','正月望夜示童子','張耒','宋','宋诗','song-poetry','','[]','呼童致明燭，展我窗前書。',96,'全唐诗/poet.song.64000.json','["呼童致明燭，展我窗前書。", "顧謂爾童子，此豈不足歟。", "得意自忘僞，觀一知其餘。", "爾觀千萬燈，豈與一燭殊。", "爾豈不欲醉，舉杯傾我壺。", "爾豈不欲飽，搆火烹我魚。", "人生貪外物，要以樂其軀。", "吾求安不足，安用勞馳驅。"]'),
('6aae76a9-89ab-491d-860f-53babf9113db','贈敦復','張耒','宋','宋诗','song-poetry','','[]','敦復想爲詩，目見無全牛。',192,'全唐诗/poet.song.64000.json','["敦復想爲詩，目見無全牛。", "天工忌其才，小邑使拘囚。", "漫塗以塵埃，訟訊羣啾啾。", "尚于紛紜中，逸興時奔流。", "不知誰使之，瞥爾爲南遊。", "驊騮解其縶，鷹隼脫於鞲。", "山川困搜羅，風月遭嘲咻。", "舉手聊探之，縱橫爛琳璆。", "不有同行人，更歌而迭酬。", "天應憫子勞，久苦暫使休。", "奈何少縱之，一放不可收。", "歸來見我喜，逸氣凌高秋。", "我竊不自量，妄將挾其輈。", "心知不可追，子幸爲我留。", "君方嚴旗幢，我亦戒戈矛。", "將圖詰朝見，百敗非予羞。"]'),
('feeca443-bce7-4e9d-a656-2f45106dda81','讀戚公恕進卷','張耒','宋','宋诗','song-poetry','','[]','世方尚纖柔，子獨不可揉。',240,'全唐诗/poet.song.64000.json','["世方尚纖柔，子獨不可揉。", "人皆喜呶呶，子語不出口。", "巉然即之高，俗子競嘲詬。", "我嘗要之難，快使暴其有。", "乃知謗之非，更覺所得厚。", "由來難小知，此固可大受。", "讀書常辛勤，世務飽經構。", "琅琅滿編文，一一可推究。", "俗儒昧事實，文字工綵繡。", "可觀不可用，章甫冠土偶。", "子能獨不然，渾樸謝雕鏤。", "寧爲目前玩，功見施設後。", "知心古所難，形兀實難售。", "嗟君聽者寡，風雨但孤雊。", "又思理難常，功業亦邂逅。", "豈令匠石斤，常縮袖間手。", "無爲扣角歌，且進滿尊酎。", "但非遽可令，有所待而偶。", "干將伏黄土，氣乃在牛斗。", "顧君久自安，蔽抑寧復又。"]'),
('2a0968b3-96b2-480f-8c85-c26d08e0ecd5','與友人論文因以詩投之','張耒','宋','宋诗','song-poetry','','[]','我雖不知文，嘗聞於達者。',168,'全唐诗/poet.song.64000.json','["我雖不知文，嘗聞於達者。", "文以意爲車，意以文爲馬。", "理强意乃勝，氣盛文如駕。", "理惟當即止，妄說即虛假。", "氣如决江河，勢盛乃傾瀉。", "文莫如六經，此道亦不舍。", "但於文最高，窺不見隙罅。", "故令後世儒，其能及者寡。", "文章古亦衆，其道則一也。", "譬如張衆樂，要以歸之雅。", "區區爲對偶，此格最污下。", "求之古無有，欲學固未暇。", "君爲時俊髦，我老安苟且。", "聊獻師所傳，無以吾言野。"]'),
('0cbcd137-043d-48ef-bdee-32ec3804b725','寄參寥','張耒','宋','宋诗','song-poetry','','[]','春風入楚鄉，與子別經歲。',120,'全唐诗/poet.song.64000.json','["春風入楚鄉，與子別經歲。", "有客過我門，携君尺書至。", "昔我出京師，倉皇省家事。", "遂令千里別，不一執君袂。", "又聞子亦行，杖履若飄駛。", "雖成相思詩，欲寫不可寄。", "飄飄山水夢，時與飛錫值。", "乃能以書來，知子猶我記。", "浮雲隨高風，聚散未可計。", "遲君冰雪詩，濯我塵埃思。"]'),
('e559adc2-2140-4b90-82cc-7e0447dd52c4','送胡考甫','張耒','宋','宋诗','song-poetry','','[]','胡公精悍姿，勇氣如秋鷹。',216,'全唐诗/poet.song.64000.json','["胡公精悍姿，勇氣如秋鷹。", "兵書百萬言，揮麈談如傾。", "羞戴文吏冠，慨然喜功名。", "願得丈二殳，爲國作長城。", "朝廷士力盛，戰馬如雲騰。", "貔貅飽肉食，武庫森神兵。", "此豈不足用，麾之若雷霆。", "如何彼黠虜，坐敢邀金繒。", "由來在得將，選擇當至精。", "譬如養騏驥，有御乃能行。", "安得偉丈夫，長驅兩隅清。", "淮南聽公語，乃是衛霍朋。", "終軍白面兒，尚欲請長纓。", "縱橫老將手，出袖盍一呈。", "策馬勿自滯，我將觀厥成。", "一奮庸將驕，汎灌出精英。", "立功報天子，執節擁旗旌。", "男兒當封侯，寧爲老書生。"]'),
('c54a6138-bec6-4f49-9b3f-e6c16649daa2','旦起','張耒','宋','宋诗','song-poetry','','[]','漫漫東牖白，開帷納晨光。',168,'全唐诗/poet.song.64000.json','["漫漫東牖白，開帷納晨光。", "欠伸推夜枕，叩齒披朝裳。", "瓦盎汲石泉，潄濯齒頰凉。", "維茲孟夏初，宿雨清高堂。", "栖鳥起且啅，露鶯鳴更藏。", "悠悠曉花殷，落落古柳蒼。", "西舍初鳴春，東鄰出求糧。", "客馬已別櫪，商車欲踰岡。", "羲和一揚輝，羣動皆擾攘。", "有生無不求，誰得偃於床。", "人生但如此，勤苦亦可傷。", "况我病倦翮，飄飄信風翔。", "永懷中林士，栖志烟霞鄉。", "願言寄旅跡，相托以徜徉。"]'),
('9a107b82-3c3a-4976-803e-55619c302073','庭草','張耒','宋','宋诗','song-poetry','','[]','冉冉朝雨霽，欣欣禽哺雛。',120,'全唐诗/poet.song.64000.json','["冉冉朝雨霽，欣欣禽哺雛。", "鮮鮮中庭草，佳色日已敷。", "童子惡其蕃，謁我盡掃除。", "我爲再三擷，愛之不能鋤。", "人生羣動中，一氣本不殊。", "奈何欲自私，害彼安其軀。", "况我麋鹿性，得此亦可娛。", "延蔓藩籬間，常若田野居。", "亭亭濯露曉，偃偃披風餘。", "所嗜乃若此，我生合樵漁。"]'),
('c40f1ac9-0ecf-4be3-b212-f86a199c72ba','寄答參寥五首  其一','張耒','宋','宋诗','song-poetry','','[]','昔我初見子，子時客京師。',180,'全唐诗/poet.song.64000.json','["昔我初見子，子時客京師。", "聞名久不獲，既得過所知。", "示我一卷書，大小百首詩。", "我嗜不可輟，熊蹯薦朝饑。", "約子彭城遊，念當行有期。", "中間忽倉卒，决去不子辭。", "子後來高郵，我居淮之湄。", "中間無百里，詩句屢欲馳。", "客來得子書，云子久南歸。", "投書不能讀，恨我聞之遲。", "使我早知此，扁舟尚能追。", "遠別不執手，近居不相携。", "每念今悵昔，耿耿衷腸悲。", "子行日已南，我去日已西。", "音書不可頻，何以慰我思。"]'),
('619937a7-40cb-4511-a40f-8b1a8b938893','寄答參寥五首  其二','張耒','宋','宋诗','song-poetry','','[]','蘇公守吳興，山水方有主。',108,'全唐诗/poet.song.64000.json','["蘇公守吳興，山水方有主。", "子兮從之遊，挂錫當可駐。", "塵埃困孤鶴，念子久失所。", "秋風展其翼，道使萬里去。", "青雲引高唳，爽絕誰敢伍。", "予駒欲西秣，東我江海艣。", "平生二三子，往往在南土。", "子才得所樂，我拙日益魯。", "拳拳相思心，契闊不得語。"]'),
('2c7d8657-6d05-4107-8b62-3051d626ec93','寄答參寥五首  其三','張耒','宋','宋诗','song-poetry','','[]','秦子我所愛，詞若秋風清。',96,'全唐诗/poet.song.64000.json','["秦子我所愛，詞若秋風清。", "蕭蕭吹毛髮，肅肅爽我情。", "精工造奧妙，寶鐵鏤瑶瓊。", "我雖見之晚，披豁盡平生。", "又聞與蘇公，復與子同行。", "更酬而迭唱，鐘磬日撞鳴。", "東吳富山水，草木餘春榮。", "悲予獨契闊，不得陪酬賡。"]'),
('b3dc0d92-7b44-4d5e-8304-b0c7f3985bf6','寄答參寥五首  其四','張耒','宋','宋诗','song-poetry','','[]','我生爲文章，與衆常不偶。',120,'全唐诗/poet.song.64000.json','["我生爲文章，與衆常不偶。", "出其所爲詩，不笑即嘲詬。", "少年勇自辯，盛氣爭可否。", "年來知所避，不敢出諸口。", "時時未免作，包以千襲厚。", "低心讓兒曹，默默衆人後。", "見君不能已，頗亦陳所有。", "君豈少取之，時以佳句授。", "幽弦喜有聽，清唱慰孤奏。", "如何瞥然去，使我不得友。"]'),
('10228fd7-c602-4abe-a2f1-35c82757974e','寄答參寥五首  其五','張耒','宋','宋诗','song-poetry','','[]','蕭蕭江湖客，疏瘦若秋竹。',120,'全唐诗/poet.song.64000.json','["蕭蕭江湖客，疏瘦若秋竹。", "苦心爲詩章，日夜撓心腹。", "清弦無浮聲，促柱有哀曲。", "湔湔幽嚴泉，一一清可掬。", "人生於文章，初若力不作。", "及其成欲售，又困瞽者目。", "予從吳興公，乃獨獲所欲。", "得意有知賞，幽懷免窮獨。", "嗟予有所投，痛學自藏覆。", "子當慰我窮，時寄書數幅。"]'),
('67287402-3c48-4b66-90f0-9e10c6cfa1d9','夏日雜感四首  其一','張耒','宋','宋诗','song-poetry','','[]','我前十日至，柳葉不蔽日。',96,'全唐诗/poet.song.64000.json','["我前十日至，柳葉不蔽日。", "我後十日來，芳條如紺室。", "枝間有好鳥，鳴和若琴瑟。", "渠渠哺其雛，啄我園中實。", "梢梢筍成竹，濯濯草過尺。", "心驚歲已半，念此日月疾。", "朝來數葉墮，盛夏有萎色。", "悲哉一陰生，長養從此極。"]'),
('261c4fd6-516f-4970-9084-8348faf8ece3','夏日雜感四首  其二','張耒','宋','宋诗','song-poetry','','[]','士而懷其居，孔子亦云非。',96,'全唐诗/poet.song.64000.json','["士而懷其居，孔子亦云非。", "賢臣事晉侯，夜載使逃齊。", "酖毒比晏安，君子不可怡。", "樂小必害大，安近遠之迷。", "野芻養騏驥，當念和鑾馳。", "一飽願即止，幾何非犬雞。", "高賢意有在，汲汲不敢遲。", "安能守槽櫪，長伴兒曹嬉。"]'),
('7e60dd91-aef0-4fe6-b3a2-7de2e36713ff','夏日雜感四首  其三','張耒','宋','宋诗','song-poetry','','[]','羣動入夜息，我歸亦安眠。',120,'全唐诗/poet.song.64000.json','["羣動入夜息，我歸亦安眠。", "脫我身上衣，援枕體晏然。", "朝日常營營，有生不可閒。", "羲和戢其光，幸此須臾間。", "人生一世中，大小無百年。", "胡爲不自暇，長抱勤苦歎。", "才者勇設施，誕者夸勢權。", "彼有驅其心，欲休諒無緣。", "我本與世疏，少慵老成頑。", "何爲不引去，坎坷行所難。"]'),
('5e0993ce-c023-460e-8ea2-6f26f392486b','夏日雜感四首  其四','張耒','宋','宋诗','song-poetry','','[]','娟娟簷前月，雖缺猶媚好。',120,'全唐诗/poet.song.64000.json','["娟娟簷前月，雖缺猶媚好。", "團團理絲蟲，養身恃其巧。", "無能老蝙蝠，乘夜出堂奧。", "那能捕飛蚊，未解聒耳鬧。", "悲歌草間蚓，辛苦自鳴噪。", "爾生可以默，何所欲而躁。", "鳴蛙訴其渴，謂若天可禱。", "瘖蟬死不鳴，豈以訴無效。", "悠悠羣動情，誰得辨醜好。", "我歌豈徒然，亦用自警告。"]'),
('df4510f3-7588-412d-9685-0d401fe4feb5','和周楚望','張耒','宋','宋诗','song-poetry','','[]','宿雨生曉潤，繁雲滋暑陰。',120,'全唐诗/poet.song.64000.json','["宿雨生曉潤，繁雲滋暑陰。", "我居廢不葺，常苦積雨侵。", "果墜厭風惡，草沉知潦深。", "拳拳抱幽歎，耿耿嬰煩襟。", "吾子久不來，幽居誰見臨。", "飄然得秀句，生我江湖心。", "一官亦漫爾，勤苦安能任。", "何當舍此去，拂我塵埃琴。", "饑寒仰五斗，求尺而忘尋。", "悲我復契闊，誰復知吾音。"]'),
('292ea2ef-6eef-4583-873a-e9f02318b41d','秋日晨與寄楚望','張耒','宋','宋诗','song-poetry','','[]','夜雨霽清曉，浮雲散凉川。',96,'全唐诗/poet.song.64000.json','["夜雨霽清曉，浮雲散凉川。", "幽人理青髮，汲彼石井泉。", "焚香展素帙，持珠諷妙言。", "晨暉淡悠揚，秋霞麗紺天。", "萎花開露餘，孤葉零風前。", "感此芳節晚，長嘯心悠然。", "傾觴散滯念，粲菊留華年。", "牢落歲暮心，非君誰與宣。"]'),
('1a1a0145-dbf0-4fc2-baa2-b14197dd5cac','感秋呈宏父兼呈周楚望三首  其一','張耒','宋','宋诗','song-poetry','','[]','西風吹我舟，繫纜岸邊柳。',144,'全唐诗/poet.song.64000.json','["西風吹我舟，繫纜岸邊柳。", "蕭蕭落船葉，日夕煩我帚。", "心驚芳歲晚，日月去如走。", "搔我鬢邊髮，少壯寧復久。", "平生拙謀身，辛苦爲五斗。", "苟逃饑寒憂，不敢擇所受。", "心因摧折低，面苦塵埃垢。", "拳拳警前勇，俯俯蹈新揉。", "功名委之命，寧足計薄厚。", "獨遺古人書，千古相獻侑。", "我烹亦有魚，我酌亦有酒。", "非求與俗違，聊以安吾守。"]'),
('107fe335-d681-4471-9a86-752e8d20400b','感秋呈宏父兼呈周楚望三首  其二','張耒','宋','宋诗','song-poetry','','[]','西風中夜來，飛雨隨以至。',120,'全唐诗/poet.song.64000.json','["西風中夜來，飛雨隨以至。", "攬衣不能眠，起坐爲涕泗。", "炎蒸雖云酷，香草猶可佩。", "清商來無情，凋我蘭與蕙。", "咿咿草蟲悲，裊裊露蟬嘒。", "高梁燕如客，鎩翮鷹方鷙。", "乾坤本無心，萬物隨一氣。", "如何於其間，感愴坐自累。", "置之勿復道，得酒但知醉。", "陶然杯杓間，萧洒無餘事。"]'),
('48b8c82e-2525-4922-a82c-e3e5be9f0c19','感秋呈宏父兼呈周楚望三首  其三','張耒','宋','宋诗','song-poetry','','[]','浮雲無停陰，急雨來清秋。',144,'全唐诗/poet.song.64000.json','["浮雲無停陰，急雨來清秋。", "颯颯水上風，吹我千里舟。", "二年客淮楚，乞米充饑喉。", "空堂堆詩書，冷落妻子羞。", "操舟將何之，漫浪爲西遊。", "豈不厭奔走，貧賤無良謀。", "人生天地間，如萍水中浮。", "安得必所往，南北但隨流。", "達者知其然，委己任去留。", "止若寄渚雁，行如浮海桴。", "萬物本無事，百年漫多憂。", "冥懷付造物，俯仰予何求。"]'),
('89284044-bb7b-4c95-8210-acbbe7607a58','和登城依子由韵','張耒','宋','宋诗','song-poetry','','[]','步登高城望，望望殊未已。',144,'全唐诗/poet.song.64000.json','["步登高城望，望望殊未已。", "惟時歲將窮，冬孟月魄死。", "紛吾方有懷，一坐爲三起。", "悲歌擊枯枿，聲與淚俱至。", "人生隨大鈞，命不貸君子。", "付之無如何，外垢資內洗。", "前知賤終吉，外頗與愚似。", "開門張瓊瑶，誰者目不寄。", "支離冒多福，嬋娟畏獨美。", "舉頭蒼天高，歎此青雲士。", "酌公芳尊酒，願公百憂止。", "履善神所勞，委置目前事。"]'),
('173d2556-8640-42f0-a19f-0b113e8b9465','西華道中','張耒','宋','宋诗','song-poetry','','[]','我行陳許郊，千里平若掌。',120,'全唐诗/poet.song.64000.json','["我行陳許郊，千里平若掌。", "居民雜荆榛，耕少地多曠。", "野兔乍跳奔，驚鳶或高颺。", "喬林多疾風，寒澗有餘漲。", "棘籬蔽茅屋，雞犬入村巷。", "主人掃土榻，秣馬具朝餉。", "童兒汲土井，敗飯堆瓦盎。", "勿悲爲生陋，自足無他望。", "嗟予走薄宦，奔走年將壯。", "長抱羈旅愁，何時稅歸鞅。"]'),
('4b56f4c4-65fe-49e3-8c27-3daa3ae35536','泊南京登岸有作呈子由子中子敏逸民','張耒','宋','宋诗','song-poetry','','[]','客行歲云暮，孤舟衝北風。',168,'全唐诗/poet.song.64000.json','["客行歲云暮，孤舟衝北風。", "出門何蕭條，驚沙吹走蓬。", "北涉濉河水，南望宋王臺。", "落葉舞我前，鳴鳥一何哀。", "重城何諠諠，車馬溢四郭。", "朱門列大第，高甍麗飛閣。", "湯湯長河水，赴海無還期。", "蒼蒼栢與松，岡原常不移。", "覽物若有歎，誰者知我心。", "口吟新詩章，予撫白玉琴。", "鳴琴感我情，一奏涕淚零。", "子期久已死，何人爲我聽。", "推琴置之去，酌我黄金罍。", "幽憂損華姿，流景良易頹。"]'),
('06818b76-a4a7-4646-807f-93b33875adae','宿合溜驛','張耒','宋','宋诗','song-poetry','','[]','空庭野雀噪，客至休我駒。',120,'全唐诗/poet.song.64000.json','["空庭野雀噪，客至休我駒。", "盡日衝塵沙，解裘振裳裾。", "熒熒青燈光，夜永寒堂虛。", "破窗見星斗，明月照廣除。", "搆火旋烹煎，妻兒具盤盂。", "强飯一爲飽，困眠體微舒。", "嗟我山野姿，懶拙與世疏。", "如何强所難，妄躡仕進途。", "已習未易舍，欲行倦馳驅。", "悲哉不早計，既晚空嗟吁。"]'),
('5949b018-ed5b-43ef-bf58-6fcedbd90d87','至日離許州','張耒','宋','宋诗','song-poetry','','[]','先王重至日，靜息資微陽。',96,'全唐诗/poet.song.64000.json','["先王重至日，靜息資微陽。", "閉關絕商旅，后爲不省方。", "我獨何爲者，古寺嚴晨裝。", "酌酒飲僮僕，披裘冒朝霜。", "眷彼道路人，熙然樂而康。", "尊酒迭爲壽，華衣冒鮮粧。", "懷古固非士，遠客亦可傷。", "悠哉任行止，且復傾吾觴。"]'),
('0714754d-6c96-4f44-9958-c7508fb94cee','沈丘道中','張耒','宋','宋诗','song-poetry','','[]','霜霧沈遠星，芳林語春鳥。',72,'全唐诗/poet.song.64000.json','["霜霧沈遠星，芳林語春鳥。", "客眸带餘睡，馬力健清曉。", "凝烟披草際，初日動林表。", "心隨和風快，興與飛雲杳。", "芬菲悵已晚，夏陰生桑棗。", "慷慨一據鞍，此懷殊未了。"]'),
('c77f638c-ea15-4324-bdef-202882d99264','感事二首  其一','張耒','宋','宋诗','song-poetry','','[]','投老益無趣，誤爲世塵嬰。',72,'全唐诗/poet.song.64000.json','["投老益無趣，誤爲世塵嬰。", "飄然欲脫去，疲弱安能耕。", "始謀苦不臧，妄欲事功名。", "中路兩不可，徬徨始嗟驚。", "回轍愴已晚，悠悠事遄征。", "萬物各有求，我生安得寧。"]'),
('12cbd795-8622-48a8-802d-90f8fd277324','感事二首  其二','張耒','宋','宋诗','song-poetry','','[]','自古衣食勤，物生無時閒。',96,'全唐诗/poet.song.64000.json','["自古衣食勤，物生無時閒。", "春耕望時雨，厚土常苦乾。", "舉頭呼天公，天遠安得聞。", "幸此中夜雨，瀟瀟洒中田。", "天人兩異情，相值良獨難。", "水旱與豐年，由來皆偶然。", "愚夫苦多怨，智士即而安。", "我歌寧獨此，萬事一嗟歎。"]'),
('4f2bd2cc-a971-4da3-8bc4-2b6cd41903eb','漫浪翁','張耒','宋','宋诗','song-poetry','','[]','堂有書萬卷，園有竹千竿。',156,'全唐诗/poet.song.64000.json','["堂有書萬卷，園有竹千竿。", "逍遙於其間，漫浪追昔賢。", "乃祖首陽人，疾世餓空山。", "堂堂秘書公，赤手犯鯨鱣。", "後來得吾子，門戶真有傳。", "已信懷道貴，預知行世艱。", "婆娑欲頭白，不肯彈其冠。", "我頃未見之，千里知肺肝。", "不惜委珠玉，投我書數編。", "我窮安放逐，老去頗知田。", "君獨胡取之，學問考淵源。", "江鄉歲已晏，幽獨抱悁悁。", "何當一杯酒，與子相周旋。"]'),
('5d968b3b-a2c6-4c21-aa99-17dadcf7c95a','發岐亭宿故鎮三首  其一','張耒','宋','宋诗','song-poetry','','[]','我別竟陵時，楚稻如碧絲。',48,'全唐诗/poet.song.64000.json','["我別竟陵時，楚稻如碧絲。", "秋風發齊安，稻穗如植旗。", "流年去荏苒，客路何逶迤。", "弛擔終未卜，永負山中期。"]'),
('1af20da2-1549-405a-ba1a-72a875736067','發岐亭宿故鎮三首  其二','張耒','宋','宋诗','song-poetry','','[]','乘月入秋山，月午山蹊靜。',48,'全唐诗/poet.song.64000.json','["乘月入秋山，月午山蹊靜。", "森森松竹林，夾道散疏影。", "陰風留暗壑，白露蒙朝嶺。", "耿耿村雞鳴，坐感單衣冷。"]'),
('156ce751-0e8c-4f94-87e0-b17d8ed65ce1','發岐亭宿故鎮三首  其三','張耒','宋','宋诗','song-poetry','','[]','征人不敢安，蓐食待明發。',48,'全唐诗/poet.song.64000.json','["征人不敢安，蓐食待明發。", "潤衝石上雲，冷踏松間月。", "艱難付一笑，歲月驚屢閱。", "偃亞道傍松，茯苓應可掘。"]'),
('478b2a6f-1c55-4d1d-b9bf-4022aa28ec7a','獨遊東園','張耒','宋','宋诗','song-poetry','','[]','清曉步東園，獨遊悵無侶。',48,'全唐诗/poet.song.64000.json','["清曉步東園，獨遊悵無侶。", "菰蒲綠已深，鵝戲春塘雨。", "取酒就花傾，隔林邀客語。", "歸來春興闌，睡起日停午。"]'),
('b2d352b5-c40a-42fb-95ab-0bb1749f98bc','同毅夫賀無斁教授','張耒','宋','宋诗','song-poetry','','[]','吾聞冤句民，盜若春竹笋。',96,'全唐诗/poet.song.64000.json','["吾聞冤句民，盜若春竹笋。", "異時用武吏，搏擊縱鷹隼。", "洋洋劉太守，豈弟發素藴。", "凶年盜乃減，見謂君子敏。", "先生衍詩書，循吏副憂軫。", "庶幾從風靡，少緩束濕緊。", "君家龐眉伯，學行我標準。", "捧書見華髮，應爲一笑聽。"]'),
('dbe9aed5-8fed-4091-8bb6-60b463dca274','喜晴有感呈晁郎','張耒','宋','宋诗','song-poetry','','[]','山城淫雨霽，窗戶含餘清。',96,'全唐诗/poet.song.64000.json','["山城淫雨霽，窗戶含餘清。", "老人午睡足，杖策遶荒庭。", "長夏吾廬秀，清陰交衆榮。", "茫茫榛莽中，萱草揚其英。", "植杖視天壤，悠然感浮生。", "淹泊且無歎，人事亦難恒。", "一旦舍此去，觸物不無情。", "何爲久戚戚，遇酒但知傾。"]'),
('99da0bc5-5694-4ca7-b150-1d528145ce4b','春雪二首  其一','張耒','宋','宋诗','song-poetry','','[]','春雲驕不行，凍雨作飛雪。',144,'全唐诗/poet.song.64000.json','["春雲驕不行，凍雨作飛雪。", "夜深歸無燭，已覺馬蹄滑。", "那知事未已，通夕注不歇。", "堂寒曉附火，簷滴更清絕。", "前者城東遊，桃李粲已發。", "陰陽不可料，寒氣晚猶洩。", "青青高坡麥，舊事日可閱。", "當春望時雨，盛雪或爲孽。", "生民常苦勤，不敢愛膏血。", "如何待一飽，常苦神物奪。", "茫茫元精理，未易論本末。", "解裘換斗酒，莫畏衣百結。"]'),
('eb341c80-d7db-43ba-b56a-01960d06dacd','春雪二首  其二','張耒','宋','宋诗','song-poetry','','[]','天寒城南寺，門外無馬迹。',120,'全唐诗/poet.song.64000.json','["天寒城南寺，門外無馬迹。", "東風雪疾消，春泥深一尺。", "豈無老款段，畏蹶不敢策。", "還歸見兒女，怕冷不下席。", "揚雄玄未就，雙鬢颯已白。", "雖云客載酒，此意終岑寂。", "功成則有命，生事亦人力。", "胡爲不自勤，守此欲何獲。", "田桑既有裕，醪醴亦餘溢。", "嗟哉好事客，從古百無一。"]'),
('491304b8-0c30-41a0-bf46-585621f09856','有感三首  其一','張耒','宋','宋诗','song-poetry','','[]','郁城本自貳師謀，騎士拔劍猶封侯。',64,'全唐诗/poet.song.64000.json','["郁城本自貳師謀，騎士拔劍猶封侯。", "董生明經守正直，白首區區相侯國。", "參差世事足嗟歎，我笑羣兒較目前。", "可能董子之榮辱，乃在封侯得失間。"]');
